def test_decisive_sparse_evidence_anchor_survives_two_weak_rrf_votes() -> None:
    ranked = [
        {
            "doc_id": "episode:truth",
            "rerank_score": 205.0,
            "query_coverage": {"coverage": 1.0, "matched_term_count": 10},
            "supporting_evidence": [{"matched_query_terms": [f"term-{index}" for index in range(7)]}],
        },
        {
            "doc_id": "episode:neighbor",
            "rerank_score": 185.0,
            "query_coverage": {"coverage": 0.9, "matched_term_count": 9},
            "supporting_evidence": [{"matched_query_terms": ["term-1", "term-2"]}],
        },
    ]

    decision = module.episode_sparse_anchor_decision(ranked)
    anchored_score, bonus = module.episode_hybrid_rrf_score(
        sparse_rank=1,
        dense_rank=None,
        sparse_anchor=decision["active"],
    )
    weak_consensus_score, _ = module.episode_hybrid_rrf_score(
        sparse_rank=2,
        dense_rank=1,
    )

    assert decision["status"] == "decisive_coherent_sparse_evidence"
    assert bonus > 0
    assert anchored_score > weak_consensus_score
    ranked[0]["rerank_score"] = 190.0
    assert module.episode_sparse_anchor_decision(ranked)["active"] is False


def test_verbose_coherent_sparse_winner_does_not_require_short_query_coverage() -> None:
    ranked = [
        {
            "doc_id": "episode:verbose-truth",
            "rerank_score": 324.75,
            "query_coverage": {"coverage": 11 / 16, "matched_term_count": 11},
            "supporting_evidence": [
                {"matched_query_terms": [f"term-{index}" for index in range(8)]}
            ],
        },
        {
            "doc_id": "episode:project-neighbor",
            "rerank_score": 308.75,
            "query_coverage": {"coverage": 9 / 16, "matched_term_count": 9},
            "supporting_evidence": [
                {"matched_query_terms": [f"term-{index}" for index in range(4)]}
            ],
        },
    ]

    decision = module.episode_sparse_anchor_decision(ranked)

    assert decision["active"] is True
    assert decision["decision_basis"] == "verbose_absolute_coherence"

    ranked[0]["query_coverage"] = {"coverage": 20 / 24, "matched_term_count": 20}
    ranked[0]["supporting_evidence"] = [
        {"matched_query_terms": [f"term-{index}" for index in range(8)]}
    ]
    assert module.episode_sparse_anchor_decision(ranked)["active"] is False

    ranked[0]["query_coverage"] = {"coverage": 6 / 8, "matched_term_count": 6}
    ranked[0]["supporting_evidence"] = [
        {"matched_query_terms": [f"term-{index}" for index in range(5)]}
    ]
    ranked[1]["rerank_score"] = 323.75
    assert module.episode_sparse_anchor_decision(ranked)["active"] is False


def test_full_coverage_ordered_temporal_span_anchors_hybrid_fusion() -> None:
    ranked = [
        {
            "doc_id": "episode:ordered-truth",
            "temporal_span": {
                "status": "ordered_span_found",
                "minimum_anchor_coverage": 1.0,
                "left": {"line": 10, "refs": {"raw": "raw:line:10"}},
                "right": {"line": 20, "refs": {"raw": "raw:line:20"}},
            },
        },
        {
            "doc_id": "episode:neighbor",
            "temporal_span": {
                "status": "ordered_span_found",
                "minimum_anchor_coverage": 0.75,
                "left": {"line": 30, "refs": {"raw": "raw:line:30"}},
                "right": {"line": 40, "refs": {"raw": "raw:line:40"}},
            },
        },
    ]

    decision = module.episode_temporal_sparse_anchor_decision(ranked, {"active": True})
    anchored_score, bonus = module.episode_hybrid_rrf_score(
        sparse_rank=1,
        dense_rank=None,
        sparse_anchor=decision["active"],
    )
    weak_consensus_score, _ = module.episode_hybrid_rrf_score(sparse_rank=24, dense_rank=6)

    assert decision["status"] == "ordered_full_coverage_sparse_winner"
    assert decision["left_raw_ref"] == "raw:line:10"
    assert decision["right_raw_ref"] == "raw:line:20"
    assert bonus > 0
    assert anchored_score > weak_consensus_score
    ranked[0]["temporal_span"]["minimum_anchor_coverage"] = 0.75
    assert module.episode_temporal_sparse_anchor_decision(ranked, {"active": True})["active"] is False


