def test_episode_selective_rerank_is_bounded_and_only_promotes_decisive_winner(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    aoa_root = tmp_path / ".aoa"
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=False, create_indexes=False)
    results: list[dict[str, Any]] = []
    for index in range(3):
        doc_id = f"episode_semantic:rerank-session:task-000{index + 1}"
        cursor = conn.execute(
            """
            INSERT INTO episode_semantic_meta (
                doc_id, session_id, session_label, session_title, session_date,
                episode_id, preview, session_index_path, projection_version
            ) VALUES (?, 'rerank-session', 'rerank-session', '', '2026-06-03', ?, ?, ?, ?)
            """,
            (
                doc_id,
                f"task-000{index + 1}",
                "x" * 1200,
                str(tmp_path / "rerank-session" / module.SESSION_INDEX_JSON),
                module.EPISODE_SEMANTIC_PROJECTION_VERSION,
            ),
        )
        episode = {
            "episode_id": f"task-000{index + 1}",
            "representations": {"outcomes": [{"text": "x" * 1800}]},
        }
        conn.execute(
            "INSERT INTO episode_semantic_payloads(doc_rowid, payload_zlib) VALUES (?, ?)",
            (
                cursor.lastrowid,
                sqlite3.Binary(module.zlib.compress(json.dumps(episode).encode("utf-8"))),
            ),
        )
        results.append(
            {
                "doc_id": doc_id,
                "session_id": "rerank-session",
                "task_episode_id": f"task-000{index + 1}",
                "supporting_evidence": [
                    {
                        "role": "verification",
                        "source_lane": "message_assistant",
                        "admission_basis": "verification_observation",
                        "outcome": "observed",
                        "text": "evidence " + ("y" * 1200),
                        "refs": {"raw": f"raw:line:{index + 1}"},
                    }
                ],
            }
        )
    conn.commit()
    conn.close()
    calls = {"count": 0}

    def fake_url(url: str, *, method: str = "GET", payload: dict[str, Any] | None = None, timeout: int = 30) -> dict[str, Any]:
        assert payload is not None
        assert len(payload["documents"]) == 3
        assert all(len(document) <= module.EPISODE_RERANK_DOCUMENT_MAX_CHARS for document in payload["documents"])
        assert all("evidence cards:" in document for document in payload["documents"])
        assert all(
            "[role=verification; source=message_assistant; "
            "basis=verification_observation; outcome=observed; raw=raw:line:"
            in document
            for document in payload["documents"]
        )
        calls["count"] += 1
        scores = [0.20, 0.95, 0.10] if calls["count"] == 1 else [0.91, 0.95, 0.90]
        ranked = sorted(range(3), key=lambda index: -scores[index])
        return {
            "ok": True,
            "status": "ok",
            "payload": {
                "model": "test-reranker",
                "results": [
                    {"index": index, "relevance_score": scores[index]}
                    for index in ranked
                ],
                "meta": {"documents": 3, "returned": 3, "total_ms": 1},
            },
        }

    monkeypatch.setattr(module, "run_json_url", fake_url)
    decisive = module.episode_selective_local_rerank(
        aoa_root=aoa_root,
        query="why did recovery happen",
        results=results,
        candidate_limit=24,
    )
    assert decisive["status"] == "decisive_winner_promoted"
    assert decisive["candidate_count"] == 3
    assert decisive["document_policy"] == module.EPISODE_RERANK_DOCUMENT_POLICY
    assert decisive["evidence_card_limit"] == module.EPISODE_RERANK_EVIDENCE_CARD_LIMIT
    assert decisive["results"][0]["task_episode_id"] == "task-0002"

    ambiguous = module.episode_selective_local_rerank(
        aoa_root=aoa_root,
        query="why did recovery happen",
        results=results,
        candidate_limit=24,
    )
    assert ambiguous["status"] == "ambiguous_preserved_fusion_order"
    assert ambiguous["results"][0]["task_episode_id"] == "task-0001"


