def test_asserted_mutation_query_profile_distinguishes_completed_claim_from_installation_context() -> None:
    completed_query = (
        "Какую терминальную программу установил "
        "aoa-session-memory-global-route в этой сессии?"
    )
    completed = module.episode_asserted_mutation_query_profile(
        module.episode_semantic_query_terms(completed_query),
        query_text=completed_query,
    )
    before_query = "какой terminal stack уже стоял перед установкой Ghostty"
    before = module.episode_asserted_mutation_query_profile(
        module.episode_semantic_query_terms(before_query),
        query_text=before_query,
    )
    how_to_query = "how to install Ghostty in a terminal session"
    how_to = module.episode_asserted_mutation_query_profile(
        module.episode_semantic_query_terms(how_to_query),
        query_text=how_to_query,
    )
    english_query = "which package did the command install?"
    english = module.episode_asserted_mutation_query_profile(
        module.episode_semantic_query_terms(english_query),
        query_text=english_query,
    )

    assert completed["active"] is True
    assert completed["action_kinds"] == ["install"]
    assert completed["required_identifiers"] == ["aoa-session-memory-global-route"]
    assert before["active"] is False
    assert how_to["active"] is False
    assert english["active"] is True
    assert english["action_kinds"] == ["install"]


def test_asserted_mutation_alignment_requires_typed_action_and_correlation_owned_success() -> None:
    def entry(
        *,
        line: int,
        text: str,
        event_type: str,
        correlation_id: str,
        role: str,
        source_lane: str,
        outcome: str,
    ) -> dict[str, Any]:
        return {
            "line": line,
            "text": text,
            "event_type": event_type,
            "correlation_id": correlation_id,
            "source_lane": source_lane,
            "admission_basis": (
                "structured_operational_action"
                if role == "actions"
                else "structured_result_status"
            ),
            "outcome": outcome,
            "refs": {
                "raw": f"raw:line:{line}",
                "segment": "segment:1",
                "session": "session:1",
            },
        }

    positive_query = "which package did the command install?"
    positive_terms = module.episode_semantic_query_terms(positive_query)
    install_action = entry(
        line=20,
        text="dnf install ghostty",
        event_type="TOOL_CALL",
        correlation_id="call-install",
        role="actions",
        source_lane="structured_tool_call",
        outcome="requested",
    )
    install_result = entry(
        line=21,
        text="Process exited with code 0",
        event_type="VERIFICATION",
        correlation_id="call-install",
        role="outcomes",
        source_lane="structured_tool_result",
        outcome="succeeded",
    )
    positive = module.episode_asserted_mutation_alignment(
        {
            "representations": {
                "actions": [install_action],
                "outcomes": [install_result],
            }
        },
        {"supporting_evidence": []},
        positive_terms,
        query_text=positive_query,
    )

    false_premise_query = (
        "Какую терминальную программу установил "
        "aoa-session-memory-global-route в этой сессии?"
    )
    false_premise_terms = module.episode_semantic_query_terms(false_premise_query)
    skill_read = entry(
        line=12,
        text=(
            "sed -n '1,240p' "
            "/srv/AbyssOS/.aoa/skills/aoa-session-memory-global-route/SKILL.md"
        ),
        event_type="FILE_READ",
        correlation_id="call-read-skill",
        role="actions",
        source_lane="structured_tool_call",
        outcome="observed",
    )
    skill_read_result = entry(
        line=13,
        text="Process exited with code 0",
        event_type="VERIFICATION",
        correlation_id="call-read-skill",
        role="outcomes",
        source_lane="structured_tool_result",
        outcome="succeeded",
    )
    false_premise = module.episode_asserted_mutation_alignment(
        {
            "representations": {
                "actions": [skill_read],
                "outcomes": [skill_read_result],
            }
        },
        {"supporting_evidence": []},
        false_premise_terms,
        query_text=false_premise_query,
    )

    assert positive["status"] == "ordered_asserted_mutation_result_chain"
    assert positive["chain"]["action"]["refs"]["raw"] == "raw:line:20"
    assert positive["chain"]["result"]["refs"]["raw"] == "raw:line:21"
    assert positive["chain"]["mutation_kinds"] == ["install"]
    assert false_premise["status"] == "asserted_mutation_evidence_unresolved"
    assert false_premise["typed_action_count"] == 0


def test_asserted_mutation_alignment_rejects_ambiguous_successful_actions() -> None:
    def entry(
        *,
        line: int,
        text: str,
        correlation_id: str,
        role: str,
        outcome: str,
    ) -> dict[str, Any]:
        return {
            "line": line,
            "text": text,
            "event_type": "COMMAND" if role == "actions" else "COMMAND_OUTPUT",
            "correlation_id": correlation_id,
            "source_lane": (
                "structured_tool_call"
                if role == "actions"
                else "structured_tool_result"
            ),
            "admission_basis": (
                "structured_operational_action"
                if role == "actions"
                else "structured_result_status"
            ),
            "outcome": outcome,
            "refs": {
                "raw": f"raw:line:{line}",
                "segment": "segment:1",
                "session": "session:1",
            },
        }

    query = "which package did the command install?"
    result = module.episode_asserted_mutation_alignment(
        {
            "representations": {
                "actions": [
                    entry(
                        line=10,
                        text="dnf install ghostty",
                        correlation_id="call-a",
                        role="actions",
                        outcome="requested",
                    ),
                    entry(
                        line=20,
                        text="dnf install tmux",
                        correlation_id="call-b",
                        role="actions",
                        outcome="requested",
                    ),
                ],
                "outcomes": [
                    entry(
                        line=11,
                        text="Process exited with code 0",
                        correlation_id="call-a",
                        role="outcomes",
                        outcome="succeeded",
                    ),
                    entry(
                        line=21,
                        text="Process exited with code 0",
                        correlation_id="call-b",
                        role="outcomes",
                        outcome="succeeded",
                    ),
                ],
            }
        },
        {"supporting_evidence": []},
        module.episode_semantic_query_terms(query),
        query_text=query,
    )

    assert result["status"] == "ambiguous_asserted_mutation_chains"
    assert result["ambiguous"] is True
    assert result["candidate_chain_count"] == 2
    assert {
        chain["action"]["refs"]["raw"] for chain in result["candidate_chains"]
    } == {"raw:line:10", "raw:line:20"}


def test_asserted_mutation_scope_gate_rejects_cross_episode_choice() -> None:
    def result(
        *,
        doc_id: str,
        episode_id: str,
        correlation_id: str,
        action_line: int,
        result_line: int,
    ) -> dict[str, Any]:
        return {
            "doc_id": doc_id,
            "session_id": "session-1",
            "task_episode_id": episode_id,
            "asserted_mutation": {
                "active": True,
                "profile": {"active": True, "action_kinds": ["install"]},
                "status": "ordered_asserted_mutation_result_chain",
                "chain": {
                    "action": {
                        "line": action_line,
                        "correlation_id": correlation_id,
                        "refs": {"raw": f"raw:line:{action_line}"},
                    },
                    "result": {
                        "line": result_line,
                        "correlation_id": correlation_id,
                        "refs": {"raw": f"raw:line:{result_line}"},
                    },
                    "correlation_id": correlation_id,
                    "operation_identity_coverage": 1.0,
                    "result_success": True,
                },
            },
        }

    gated, scope = module.episode_asserted_mutation_scope_gate(
        [
            result(
                doc_id="episode:1",
                episode_id="task-0001",
                correlation_id="call-a",
                action_line=10,
                result_line=11,
            ),
            result(
                doc_id="episode:2",
                episode_id="task-0002",
                correlation_id="call-b",
                action_line=20,
                result_line=21,
            ),
        ]
    )

    assert scope["status"] == "ambiguous_asserted_mutation_chains"
    assert scope["qualified_chain_count"] == 2
    assert gated[0]["asserted_mutation"]["ambiguity_scope"] == (
        "cross_episode_query_scope"
    )
    admission = module.episode_answer_admission(
        {
            **gated[0],
            "query_coverage": {"coverage": 1.0, "matched_term_count": 4},
            "supporting_evidence": [
                {"matched_query_terms": ["which", "package", "install"]}
            ],
        },
        query_term_count=4,
    )
    assert admission["admitted"] is False
    assert admission["status"] == "asserted_mutation_evidence_ambiguous"
    assert admission["basis"] == "asserted_mutation_ambiguous"


def test_answer_admission_accepts_only_proven_asserted_mutation_open_result() -> None:
    top = {
        "query_coverage": {"coverage": 0.6, "matched_term_count": 6},
        "supporting_evidence": [
            {"matched_query_terms": ["install"]},
        ],
        "asserted_mutation": {
            "active": True,
            "status": "ordered_asserted_mutation_result_chain",
            "chain": {
                "action": {
                    "line": 145,
                    "correlation_id": "call-install",
                    "refs": {"raw": "raw:line:145"},
                },
                "result": {
                    "line": 152,
                    "correlation_id": "call-poll",
                    "refs": {"raw": "raw:line:152"},
                },
                "correlation_id": "call-install",
                "terminal_correlation_id": "call-poll",
                "operation_identity_coverage": 1.0,
                "result_success": True,
                "async_transport_chain": {
                    "status": "ordered_async_terminal_success_chain",
                    "terminal_success": True,
                },
            },
        },
        "causal_attribution": {
            "active": True,
            "status": "causal_attribution_chain_unresolved",
        },
    }

    admitted = module.episode_answer_admission(top, query_term_count=10)
    top["asserted_mutation"]["chain"]["async_transport_chain"]["terminal_success"] = False
    rejected = module.episode_answer_admission(top, query_term_count=10)

    assert admitted["admitted"] is True
    assert admitted["basis"] == "correlation_owned_asserted_mutation_evidence"
    assert admitted["causal_attribution_shadowed_by_asserted_mutation"] is True
    assert admitted["relation_gate"]["gates"] == [
        {
            "kind": "asserted_mutation",
            "status": "ordered_asserted_mutation_result_chain",
            "admitted": True,
        }
    ]
    assert rejected["admitted"] is False
    assert rejected["asserted_mutation_open_result_admitted"] is False


def test_episode_answer_admission_blocks_strong_entity_overlap_for_unproven_mutation() -> None:
    top = {
        "query_coverage": {"coverage": 0.8, "matched_term_count": 8},
        "supporting_evidence": [
            {
                "matched_query_terms": [
                    "aoa",
                    "session",
                    "memory",
                    "global",
                    "route",
                    "терминальную",
                ]
            }
        ],
        "asserted_mutation": {
            "active": True,
            "status": "asserted_mutation_evidence_unresolved",
            "ranking_boost": 0.0,
            "chain": {},
        },
    }

    rejected = module.episode_answer_admission(top, query_term_count=10)

    assert rejected["admitted"] is False
    assert rejected["status"] == "asserted_mutation_evidence_unresolved"
    assert rejected["basis"] == "asserted_mutation_unresolved"
    assert rejected["relation_gate"]["gates"] == [
        {
            "kind": "asserted_mutation",
            "status": "asserted_mutation_evidence_unresolved",
            "admitted": False,
        }
    ]


def test_causal_attribution_query_profile_distinguishes_relation_from_command_navigation() -> None:
    russian_query = "какие сессии были подтверждены завершёнными этим поиском?"
    russian = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(russian_query),
        query_text=russian_query,
    )
    assert russian["active"] is True
    assert russian["operation_kinds"] == ["search"]
    assert russian["target_terms"] == ["сессии", "завершёнными"]
    assert russian["required_state_terms"] == ["завершёнными"]

    english_query = "what did this command show about the completed sessions?"
    english = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(english_query),
        query_text=english_query,
    )
    assert english["active"] is True
    assert english["operation_kinds"] == ["command"]

    rg_query = "что подтвердил этот rg: сессии завершёнными?"
    rg_profile = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(rg_query),
        query_text=rg_query,
    )
    assert rg_profile["active"] is True
    assert rg_profile["operation_kinds"] == ["search"]
    assert "rg" not in rg_profile["target_terms"]

    explicit_command_query = (
        "Что показала команда podman system df --format json "
        "с correlation call_NBHkoe8zho6GlW6Ffezaa2yZ?"
    )
    explicit_command = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(explicit_command_query),
        query_text=explicit_command_query,
    )
    assert explicit_command["active"] is True
    assert explicit_command["explicit_named_operation_shape"] is True
    assert explicit_command["open_result_query"] is True
    assert explicit_command["target_terms"] == []
    assert explicit_command["operation_identity_terms"] == [
        "podman",
        "system",
        "df",
        "format",
        "json",
        "nbhkoe8zho6glw6ffezaa2yz",
    ]

    explicit_target_query = (
        "What did command podman system df show about reclaimable images?"
    )
    explicit_target = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(explicit_target_query),
        query_text=explicit_target_query,
    )
    assert explicit_target["active"] is True
    assert explicit_target["open_result_query"] is False
    assert explicit_target["operation_identity_terms"] == [
        "podman",
        "system",
        "df",
    ]
    assert explicit_target["target_terms"] == ["reclaimable", "images"]

    for navigation_query in ("show this command", "покажи эту команду"):
        navigation = module.episode_causal_attribution_query_profile(
            module.episode_semantic_query_terms(navigation_query),
            query_text=navigation_query,
        )
        assert navigation["active"] is False

    validator_query = (
        "В какой среде и с каким результатом запускали "
        "python scripts/validate_connector.py для StackOverflow connector?"
    )
    validator = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(validator_query),
        query_text=validator_query,
    )
    assert validator["active"] is True
    assert validator["open_result_query"] is True
    assert validator["operation_kinds"] == ["script"]
    assert validator["required_state_terms"] == []
    assert validator["operation_identity_terms"] == [
        "python",
        "validate",
        "connector",
        "py",
        "stackoverflow",
    ]


def test_causal_profile_does_not_read_foundation_as_found_relation() -> None:
    """Regression derived from the W3 temporal-between false causal gate."""
    temporal_query = (
        "что происходило 2026-07-10 между успешным MCP receipt "
        "aoa_session_entity_usage_chain для aoa_memo и успешным MCP "
        "receipt aoa_memo_search distributed memory organ foundation"
    )
    temporal = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(temporal_query),
        query_text=temporal_query,
    )
    causal_query = "What did this search find about distributed memory?"
    causal = module.episode_causal_attribution_query_profile(
        module.episode_semantic_query_terms(causal_query),
        query_text=causal_query,
    )

    assert temporal["relation_language"] is False
    assert temporal["active"] is False
    assert causal["relation_language"] is True
    assert causal["active"] is True


def test_exact_operational_anchor_hydration_distinguishes_result_ambiguity_and_mentions(
    tmp_path: Path,
) -> None:
    """Synthetic regression derived from manually sealed connector validation chains."""
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-07-10T00-00-00-exact-operation.jsonl"
    session_id = "exact-operational-anchor-session"
    command = "python scripts/validate_connector.py"

    def custom_exec_call(
        call_id: str,
        connector: str,
    ) -> dict[str, Any]:
        workdir = workspace / "connectors" / connector
        return {
            "timestamp": "2026-07-10T00:00:02Z",
            "type": "response_item",
            "payload": {
                "type": "custom_tool_call",
                "status": "completed",
                "call_id": call_id,
                "name": "exec",
                "input": (
                    "const r = await tools.exec_command({\n"
                    f'  cmd: "{command}",\n'
                    f'  workdir: "{workdir}",\n'
                    "  yield_time_ms: 30000\n"
                    "});\ntext(r.output);\n"
                ),
            },
        }

    def custom_exec_result(
        call_id: str,
        connector: str,
        required_files: int,
    ) -> dict[str, Any]:
        payload = {
            "checked": {"required_files": required_files},
            "errors": [],
            "repo_root": str(workspace / "connectors" / connector),
            "status": "ok",
            "warnings": [],
        }
        return {
            "timestamp": "2026-07-10T00:00:03Z",
            "type": "response_item",
            "payload": {
                "type": "custom_tool_call_output",
                "call_id": call_id,
                "output": [
                    {
                        "type": "input_text",
                        "text": "Script completed\nWall time 0.1 seconds\nOutput:\n",
                    },
                    {
                        "type": "input_text",
                        "text": json.dumps(payload, ensure_ascii=False),
                    },
                ],
            },
        }

    write_jsonl(
        transcript,
        [
            {
                "timestamp": "2026-07-10T00:00:00Z",
                "type": "session_meta",
                "payload": {"id": session_id, "cwd": str(workspace)},
            },
            {
                "timestamp": "2026-07-10T00:00:01Z",
                "type": "response_item",
                "payload": {
                    "type": "message",
                    "role": "user",
                    "content": [{"type": "input_text", "text": "Validate both connectors"}],
                },
            },
            custom_exec_call("call_stackoverflow", "stackoverflow"),
            custom_exec_result("call_stackoverflow", "stackoverflow", 48),
            custom_exec_call("call_telegram", "telegram"),
            custom_exec_result("call_telegram", "telegram", 47),
            {
                "timestamp": "2026-07-10T00:00:04Z",
                "type": "response_item",
                "payload": {
                    "type": "message",
                    "role": "assistant",
                    "content": [
                        {
                            "type": "output_text",
                            "text": (
                                "Documentation mentions "
                                "python scripts/release_check.py, but it was not run."
                            ),
                        }
                    ],
                },
            },
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": session_id,
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    session_record = module.resolve_session_record(aoa_root, session_id)
    session_label = str(session_record["session_label"])
    session_ref = str(Path(session_record["path"]) / "session.manifest.json")

    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)
    for connector, raw_line in (("stackoverflow", 3), ("telegram", 5)):
        workdir = str(workspace / "connectors" / connector)
        module.insert_search_document(
            conn,
            {
                "id": f"event:{session_id}:{raw_line}",
                "doc_type": "event",
                "session_id": session_id,
                "session_label": session_label,
                "session_title": "Exact operational anchors",
                "session_date": "2026-07-10",
                "event_id": str(raw_line),
                "event_type": "TOOL_CALL",
                "action": command,
                "usage_role": "usage",
                "raw_ref": f"raw:line:{raw_line}",
                "manifest_path": session_ref,
                "cwd": workdir,
                "title": f"{command} {connector}",
                "body": f"{command} workdir={workdir}",
                "payload_json": "{}",
                "exact_literal_text": command,
                "exact_literal_source_lane": "structured_tool_call",
            },
        )
    conn.execute(
        """
        INSERT INTO exact_literal_session_state(
          session_id, session_label, source_fingerprint, status,
          posting_document_count, projection_version, indexed_at
        ) VALUES (?, ?, 'synthetic', 'current', 2, ?, '2026-07-10T00:00:05Z')
        """,
        (
            session_id,
            session_label,
            module.SEARCH_EXACT_LITERAL_POSTINGS_VERSION,
        ),
    )
    conn.commit()
    conn.close()

    base_results = [
        {
            "doc_id": f"episode_semantic:{session_id}:task-0001",
            "session_id": session_id,
            "task_episode_id": "task-0001",
            "event_range": {"from_line": 1, "to_line": 7},
            "supporting_evidence": [],
            "match_channel": "episode_sparse_fts",
            "explain": {},
        }
    ]

    def hydrate(query: str) -> tuple[list[dict[str, Any]], dict[str, Any]]:
        terms = module.episode_semantic_query_terms(query)
        return module.episode_exact_operational_anchor_hydration(
            aoa_root=aoa_root,
            session_record=session_record,
            results=base_results,
            terms=terms,
            query_text=query,
            normalized_query=module.episode_semantic_fts_query(terms),
            explain=True,
        )

    specific, specific_report = hydrate(
        "В какой среде и с каким результатом запускали "
        "python scripts/validate_connector.py для StackOverflow connector?"
    )
    specific_chain = specific[0]["causal_attribution"]["chain"]
    assert specific_report["status"] == "applied_unique_correlation_owned_chain"
    assert specific_report["posting_hit_count"] == 2
    assert specific_report["qualified_hit_count"] == 1
    assert specific_chain["correlation_id"] == "call_stackoverflow"
    assert specific_chain["action"]["refs"]["raw"] == "raw:line:3"
    assert specific_chain["result"]["refs"]["raw"] == "raw:line:4"
    assert specific_chain["action"]["workdir"].endswith("/stackoverflow")
    assert '"status": "ok"' in specific_chain["result"]["text"]

    ambiguous, ambiguous_report = hydrate(
        "С каким результатом запускали python scripts/validate_connector.py?"
    )
    ambiguous_attribution = ambiguous[0]["causal_attribution"]
    assert ambiguous_report["status"] == "applied_ambiguous_correlation_owned_chains"
    assert ambiguous_report["chain_count"] == 2
    assert ambiguous_report["query_local_unique_raw_block_count"] == 1
    assert ambiguous_report["query_local_block_cache_hit_count"] == 1
    window_costs = [
        report["cost_profile"]
        for report in ambiguous_report["window_reports"]
    ]
    assert window_costs[0]["decoded_bytes_scanned"] > 0
    assert window_costs[1]["decoded_bytes_scanned"] == 0
    assert window_costs[1]["decoded_bytes_reused"] == (
        window_costs[0]["decoded_bytes_scanned"]
    )
    assert ambiguous_attribution["status"] == "ambiguous_causal_attribution_chains"
    assert {
        chain["correlation_id"]
        for chain in ambiguous_attribution["candidate_chains"]
    } == {"call_stackoverflow", "call_telegram"}

    for absent_query in (
        "С каким результатом запускали python scripts/nonexistent_validator.py?",
        "С каким результатом запускали python scripts/release_check.py?",
    ):
        absent, absent_report = hydrate(absent_query)
        assert absent_report["status"] == "exact_anchor_postings_not_found"
        assert absent_report["posting_hit_count"] == 0
        assert "causal_attribution" not in absent[0]


