def test_causal_attribution_requires_correlation_owned_target_bearing_result() -> None:
    def entry(
        role: str,
        line: int,
        text: str,
        *,
        correlation_id: str = "",
        admission_basis: str,
        event_type: str,
        source_lane: str,
        outcome: str = "observed",
    ) -> dict[str, Any]:
        return {
            "text": text,
            "source_lane": source_lane,
            "evidence_role": role,
            "admission_basis": admission_basis,
            "correlation_id": correlation_id,
            "event_type": event_type,
            "outcome": outcome,
            "line": line,
            "refs": {
                "raw": f"raw:line:{line}",
                "segment": "segment.md",
                "segment_index": "segment.index.json",
                "session": "session.manifest.json",
            },
        }

    query = "какие сессии были подтверждены завершёнными этим поиском?"
    terms = module.episode_semantic_query_terms(query)
    action = entry(
        "actions",
        10,
        "rg -n '\"status\": \"completed\"' sessions/*.json",
        correlation_id="call_search",
        admission_basis="structured_operational_action",
        event_type="COMMAND",
        source_lane="structured_tool_call",
        outcome="requested",
    )
    direct_result = entry(
        "outcomes",
        11,
        "rg -n status sessions/*.json -> succeeded [call_search] "
        "compact successful output observation: "
        "сессии alpha и beta имеют состояние завершёнными",
        correlation_id="call_search",
        admission_basis="structured_compact_success_observation",
        event_type="COMMAND_OUTPUT",
        source_lane="structured_tool_result",
        outcome="succeeded",
    )
    positive_episode = {
        "representations": {
            "actions": [action],
            "outcomes": [direct_result],
            "verification": [],
            "failures": [],
        }
    }
    positive = module.episode_causal_attribution_alignment(
        positive_episode,
        {"supporting_evidence": []},
        terms,
        query_text=query,
    )
    assert positive["status"] == "ordered_action_result_attribution_chain"
    assert positive["chain"]["action"]["line"] == 10
    assert positive["chain"]["result"]["line"] == 11
    assert positive["chain"]["correlation_id"] == "call_search"
    assert positive["chain"]["target_coverage"] == 1.0

    second_action = entry(
        "actions",
        20,
        "rg -n '\"status\": \"completed\"' archived/*.json",
        correlation_id="call_search_second",
        admission_basis="structured_operational_action",
        event_type="COMMAND",
        source_lane="structured_tool_call",
        outcome="requested",
    )
    second_result = entry(
        "outcomes",
        21,
        "rg -n status archived/*.json -> succeeded [call_search_second] "
        "compact successful output observation: "
        "сессии gamma и delta имеют состояние завершёнными",
        correlation_id="call_search_second",
        admission_basis="structured_compact_success_observation",
        event_type="COMMAND_OUTPUT",
        source_lane="structured_tool_result",
        outcome="succeeded",
    )
    ambiguous = module.episode_causal_attribution_alignment(
        {
            "representations": {
                "actions": [action, second_action],
                "outcomes": [direct_result, second_result],
                "verification": [],
                "failures": [],
            }
        },
        {"supporting_evidence": []},
        terms,
        query_text=query,
    )
    assert ambiguous["status"] == "ambiguous_causal_attribution_chains"
