def test_causal_attribution_scope_gate_rejects_repeated_unanchored_command() -> None:
    def result(task_id: str, action_line: int, correlation_id: str) -> dict[str, Any]:
        return {
            "doc_id": f"episode_semantic:session:{task_id}",
            "session_id": "session",
            "task_episode_id": task_id,
            "causal_attribution": {
                "active": True,
                "profile": {
                    "open_result_query": True,
                    "operation_identity_terms": [
                        "podman",
                        "system",
                        "df",
                        "format",
                        "json",
                    ],
                },
                "status": "ordered_action_result_attribution_chain",
                "chain": {
                    "action": {
                        "line": action_line,
                        "refs": {"raw": f"raw:line:{action_line}"},
                    },
                    "result": {
                        "line": action_line + 1,
                        "refs": {"raw": f"raw:line:{action_line + 1}"},
                    },
                    "correlation_id": correlation_id,
                    "operation_identity_coverage": 1.0,
                },
            },
            "explain": {},
        }

    single_results, single_scope = module.episode_causal_attribution_scope_gate(
        [result("task-0002", 239, "call_first")]
    )
    assert single_scope["status"] == "single_causal_attribution_chain"
    assert single_scope["qualified_chain_count"] == 1
    assert (
        single_results[0]["causal_attribution"]["status"]
        == "ordered_action_result_attribution_chain"
    )

    gated_results, scope = module.episode_causal_attribution_scope_gate(
        [
            result("task-0012", 1056, "call_latest"),
            result("task-0006", 410, "call_middle"),
        ]
    )
    assert scope["status"] == "ambiguous_causal_attribution_chains"
    assert scope["qualified_chain_count"] == 2
    assert gated_results[0]["causal_attribution"]["ambiguous"] is True
    assert gated_results[0]["causal_attribution"]["chain"] == {}
    assert {
        candidate["task_episode_id"]
        for candidate in gated_results[0]["causal_attribution"]["candidate_chains"]
    } == {"task-0012", "task-0006"}


def test_answer_admission_cannot_override_unresolved_causal_attribution_with_reranker() -> None:
    query = "какие сессии были подтверждены завершёнными этим поиском?"
    terms = module.episode_semantic_query_terms(query)
    unresolved = {
        "active": True,
        "status": "causal_attribution_chain_unresolved",
        "chain": {},
    }
    top = {
        "query_coverage": {"coverage": 1.0, "matched_term_count": len(terms)},
        "supporting_evidence": [
            {"matched_query_terms": [term["token"] for term in terms]}
        ],
        "host_rerank": {"score": 0.99},
        "causal_attribution": unresolved,
    }
    rejected = module.episode_answer_admission(top, query_term_count=len(terms))
    assert rejected["admitted"] is False
    assert rejected["status"] == "causal_relation_evidence_unresolved"
    assert rejected["basis"] == "causal_relation_unresolved"
    assert rejected["relation_gate"]["gates"] == [
        {
            "kind": "causal_attribution",
            "status": "causal_attribution_chain_unresolved",
            "admitted": False,
        }
    ]

    admitted_top = dict(top)
    admitted_top["causal_attribution"] = {
        "active": True,
        "status": "ordered_action_result_attribution_chain",
        "chain": {"action": {}, "result": {}},
    }
    admitted = module.episode_answer_admission(admitted_top, query_term_count=len(terms))
    assert admitted["admitted"] is True
    assert admitted["basis"] == "strong_lexical_evidence"

    open_result_top = {
        "query_coverage": {"coverage": 0.7, "matched_term_count": 7},
        "supporting_evidence": [
            {"matched_query_terms": []},
        ],
        "causal_attribution": {
            "active": True,
            "status": "ordered_action_result_attribution_chain",
            "profile": {
                "open_result_query": True,
            },
            "chain": {
                "action": {"line": 239, "refs": {"raw": "raw:line:239"}},
                "result": {"line": 243, "refs": {"raw": "raw:line:243"}},
                "correlation_id": "call_NBHkoe8zho6GlW6Ffezaa2yZ",
                "operation_identity_coverage": 1.0,
            },
        },
    }
    open_result = module.episode_answer_admission(
        open_result_top,
        query_term_count=10,
    )
    assert open_result["admitted"] is True
    assert open_result["basis"] == "correlation_owned_open_result_evidence"

    weak_open_result_top = dict(open_result_top)
    weak_open_result_top["causal_attribution"] = {
        **open_result_top["causal_attribution"],
        "chain": {
            **open_result_top["causal_attribution"]["chain"],
            "operation_identity_coverage": 0.5,
        },
    }
    weak_open_result = module.episode_answer_admission(
        weak_open_result_top,
        query_term_count=10,
    )
    assert weak_open_result["admitted"] is False
    assert weak_open_result["status"] == "candidate_navigation_below_answer_threshold"

    ambiguous_top = dict(top)
    ambiguous_top["causal_attribution"] = {
        "active": True,
        "ambiguous": True,
        "status": "ambiguous_causal_attribution_chains",
        "chain": {},
        "qualified_chain_count": 2,
    }
    ambiguous = module.episode_answer_admission(
        ambiguous_top,
        query_term_count=len(terms),
    )
    assert ambiguous["admitted"] is False
    assert ambiguous["status"] == "causal_relation_evidence_ambiguous"
    assert ambiguous["basis"] == "causal_relation_ambiguous"
    assert ambiguous["relation_gate"]["gates"] == [
        {
            "kind": "causal_attribution",
            "status": "ambiguous_causal_attribution_chains",
            "admitted": False,
            "ambiguous": True,
            "qualified_count": 2,
        }
    ]


def test_episode_answer_admission_rejects_ambiguous_temporal_relation() -> None:
    strong = {
        "query_coverage": {"coverage": 0.82, "matched_term_count": 9},
        "supporting_evidence": [
            {"matched_query_terms": ["generated", "surfaces", "57", "skills", "export"]}
        ],
    }

    rejected = module.episode_answer_admission(
        strong,
        query_term_count=11,
        temporal_relation_gate={
            "status": "ambiguous_ordered_spans_available",
            "ambiguous": True,
            "qualified_count": 14,
        },
    )
    admitted = module.episode_answer_admission(
        strong,
        query_term_count=11,
        temporal_relation_gate={
            "status": "qualified_ordered_spans_available",
            "ambiguous": False,
            "qualified_count": 1,
        },
    )

    assert rejected["admitted"] is False
    assert rejected["status"] == "temporal_relation_evidence_ambiguous"
    assert rejected["basis"] == "temporal_relation_ambiguous"
    assert rejected["relation_gate"]["required"] is True
    assert admitted["admitted"] is True


def test_episode_answer_admission_requires_qualified_operational_group() -> None:
    strong = {
        "query_coverage": {"coverage": 0.55, "matched_term_count": 6},
        "supporting_evidence": [
            {"matched_query_terms": ["eval", "skill", "bundles", "corpus"]}
        ],
    }

    rejected = module.episode_answer_admission(
        strong,
        query_term_count=9,
        operational_group_gate={
            "status": "no_qualified_operational_group",
            "ambiguous": False,
            "qualified_count": 0,
        },
    )
    admitted = module.episode_answer_admission(
        strong,
        query_term_count=9,
        operational_group_gate={
            "status": "qualified_operational_groups_available",
            "ambiguous": False,
            "qualified_count": 1,
        },
    )

    assert rejected["admitted"] is False
    assert rejected["status"] == "operational_group_evidence_unresolved"
    assert rejected["basis"] == "operational_group_unresolved"
    assert admitted["admitted"] is True
    assert admitted["basis"] == "typed_operational_group_evidence"


