def test_issue_resolution_admits_explicit_test_target_retry_chain() -> None:
    """Owner-neutral regression derived from the manual W3 causal retry span."""

    def entry(
        line: int,
        text: str,
        *,
        correlation_id: str = "",
        outcome: str = "observed",
        event_type: str = "CONTEXT_STATE",
        source_lane: str = "message_assistant",
    ) -> dict[str, Any]:
        return {
            "line": line,
            "text": text,
            "correlation_id": correlation_id,
            "outcome": outcome,
            "event_type": event_type,
            "source_lane": source_lane,
            "refs": {"raw": f"raw:line:{line}"},
        }

    query = (
        "где первая apply_patch попытка не нашла context в test_contract.py, "
        "затем исправленная попытка сработала и pytest прошел"
    )
    terms = module.episode_semantic_query_terms(query)
    episode = {
        "representations": {
            "failures": [
                entry(
                    10,
                    "apply_patch verification failed: Failed to find context "
                    "in tests/test_contract.py",
                    correlation_id="call_failed_patch",
                    outcome="failed",
                    event_type="ERROR",
                    source_lane="structured_tool_result",
                )
            ],
            "actions": [
                entry(
                    20,
                    "*** Begin Patch\\n*** Update File: "
                    "/repo/tests/test_contract.py\\n@@\\n+assert contract",
                    correlation_id="call_corrected_patch",
                    outcome="requested",
                    event_type="TOOL_CALL",
                    source_lane="structured_tool_call",
                ),
                entry(
                    30,
                    "rg -n contract /repo/tests/test_contract.py",
                    correlation_id="call_inspection",
                    outcome="requested",
                    event_type="TOOL_CALL",
                    source_lane="structured_tool_call",
                ),
                entry(
                    40,
                    "pytest -q tests/test_contract.py",
                    correlation_id="call_verification",
                    outcome="requested",
                    event_type="COMMAND",
                    source_lane="structured_tool_call",
                ),
            ],
            "outcomes": [
                entry(
                    21,
                    "Success. Updated /repo/tests/test_contract.py",
                    correlation_id="call_corrected_patch",
                    outcome="changed",
                    event_type="TOOL_OUTPUT",
                    source_lane="structured_tool_result",
                ),
                entry(
                    31,
                    "/repo/tests/test_contract.py:12: contract marker",
                    correlation_id="call_inspection",
                    event_type="TOOL_OUTPUT",
                    source_lane="structured_tool_result",
                ),
            ],
            "verification": [
                entry(
                    41,
                    "44 passed in 1.00s",
                    correlation_id="call_verification",
                    outcome="succeeded",
                    event_type="COMMAND_OUTPUT",
                    source_lane="structured_tool_result",
                )
            ],
        }
    }

    alignment = module.episode_issue_resolution_alignment(
        episode,
        terms,
        query_text=query,
    )

    assert alignment["status"] == "ordered_issue_mutation_verification_chain"
    chain = alignment["chain"]
    assert [
        chain[key]["line"]
        for key in (
            "issue",
            "mutation_action",
            "mutation_result",
            "verification_action",
            "verification_result",
        )
    ] == [10, 20, 21, 40, 41]
    assert chain["mutation_paths"] == ["/repo/tests/test_contract.py"]
    assert chain["mutation_action"]["mutation_kind"] == "query_target_test"
    assert chain["distinct_correlation_ids"] is True

    support = module.episode_relation_prioritized_support(
        {"supporting_evidence": []},
        decision_followup={},
        failure_recovery={},
        issue_resolution=alignment,
    )
    admission = module.episode_answer_admission(
        {
            "query_coverage": {"coverage": 0.2, "matched_term_count": 1},
            "supporting_evidence": support,
            "issue_resolution": alignment,
        },
        query_term_count=len(terms),
    )
    assert admission["admitted"] is True
    assert admission["typed_issue_resolution_admitted"] is True
    assert admission["basis"] == "typed_issue_mutation_verification_evidence"
    assert admission["policy"] == (
        "accepted issue-resolution claims are limited to the ordered issue, "
        "mutation, correlation-owned result, and distinct verification raw refs"
    )

    inspection_only = json.loads(json.dumps(episode))
    inspection_only["representations"]["actions"][0]["text"] = (
        "rg -n apply_patch /repo/tests/test_contract.py"
    )
    unresolved = module.episode_issue_resolution_alignment(
        inspection_only,
        terms,
        query_text=query,
    )
    assert unresolved["status"] == "issue_resolution_chain_unresolved"

    mismatched_query = (
        "где apply_patch не нашла context, затем исправили "
        "nonexistent_contract.py и pytest прошел"
    )
    mismatched = module.episode_issue_resolution_alignment(
        episode,
        module.episode_semantic_query_terms(mismatched_query),
        query_text=mismatched_query,
    )
    assert mismatched["status"] == "issue_resolution_chain_unresolved"
    assert mismatched["required_file_anchors"] == [
        "nonexistent_contract.py"
    ]


def test_explicit_time_support_diversifies_compositional_clusters() -> None:
    """A bounded multi-part window must retain a late direct-evidence cluster."""

    def support(
        line: int,
        matched_terms: list[str],
        reading_score: float,
    ) -> dict[str, Any]:
        return {
            "line": line,
            "matched_query_terms": matched_terms,
            "reading_score": reading_score,
            "refs": {"raw": f"raw:line:{line}"},
        }

    candidates = [
        support(
            line,
            [
                "review",
                "skills",
                "diff",
                "skill",
                "usage",
                "correlation",
                "fixture",
                "completion",
            ],
            300.0 - line,
        )
        for line in range(2, 8)
    ]
    candidates.extend(
        [
            support(22, ["diff", "skill", "usage"], 210.0),
            support(23, ["diff", "skill", "usage"], 205.0),
            support(
                40,
                ["skills", "skill", "usage", "correlation", "fixture"],
                190.0,
            ),
            support(
                41,
                ["skills", "skill", "usage", "correlation", "fixture"],
                195.0,
            ),
        ]
    )

    selected = module.episode_explicit_time_select_support(
        candidates,
        limit=module.EPISODE_EXPLICIT_TIME_SUPPORT_PER_RESULT,
        diversify_clusters=True,
    )

    selected_raw_refs = {
        item["refs"]["raw"]
        for item in selected
    }
    assert "raw:line:41" in selected_raw_refs
    assert any(
        22 <= int(item["line"]) <= 23
        for item in selected
    )


def test_explicit_time_treats_inspections_as_activity_not_identifier() -> None:
    """A mixed-language activity noun must not become an exact-recall gate."""
    query = (
        "какие inspections были выполнены для aoa-stats через MCP?"
    )
    selected, basis, ignored = module.episode_explicit_time_anchor_terms(
        module.episode_semantic_query_terms(query),
        query_text=query,
    )
    selected_tokens = {
        str(term.get("token") or "")
        for term in selected
    }

    assert basis == "mixed_query_structured_latin_or_numeric_anchors"
    assert {"aoa", "stats", "mcp"} <= selected_tokens
    assert "inspections" not in selected_tokens
    assert "inspections" in ignored


