def test_compositional_reading_joins_adjacent_episode_role_evidence() -> None:
    """A multi-part answer must not be admitted from only one partial episode."""

    def evidence(
        line: int,
        role: str,
        terms: list[str],
    ) -> dict[str, Any]:
        return {
            "line": line,
            "role": role,
            "matched_query_terms": terms,
            "reading_score": 100.0,
            "refs": {"raw": f"raw:line:{line}"},
        }

    query = (
        "Какой порядок задал пользователь, какие inspections были "
        "выполнены, и было ли решение уже принято?"
    )
    results = [
        {
            "task_episode_id": "task-actions",
            "query_coverage": {
                "coverage": 1.0,
                "matched_term_count": 3,
                "matched_query_terms": ["alpha", "beta", "mcp"],
            },
            "supporting_evidence": [
                evidence(30, "actions", ["alpha", "beta"]),
                evidence(31, "outcomes", ["alpha", "mcp"]),
            ],
            "explicit_time_evidence": {
                "status": "in_window_support_available",
                "anchor_coverage_admitted": True,
                "ambiguous": False,
            },
        },
        {
            "task_episode_id": "task-intent",
            "query_coverage": {
                "coverage": 1.0,
                "matched_term_count": 3,
                "matched_query_terms": ["alpha", "beta", "mcp"],
            },
            "supporting_evidence": [
                evidence(10, "intents", ["alpha", "beta", "mcp"]),
            ],
            "explicit_time_evidence": {
                "status": "in_window_support_available",
                "anchor_coverage_admitted": True,
                "ambiguous": False,
            },
        },
        {
            "task_episode_id": "task-noise",
            "query_coverage": {
                "coverage": 0.66,
                "matched_term_count": 2,
                "matched_query_terms": ["alpha", "beta"],
            },
            "supporting_evidence": [
                evidence(2, "reasoning", ["alpha", "beta"]),
            ],
            "explicit_time_evidence": {
                "status": "in_window_support_available",
                "anchor_coverage_admitted": True,
                "ambiguous": False,
            },
        },
    ]

    reading = module.episode_compositional_evidence_reading(
        results=results,
        query_text=query,
        terms=module.episode_semantic_query_terms(query),
        explicit_time_scope={
            "active": True,
            "status": "applied",
            "admission_ready": True,
            "anchor_terms": ["alpha", "beta", "mcp"],
            "truncated": False,
        },
    )

    assert reading["status"] == "multi_episode_support_available"
    assert reading["admitted"] is True
    assert reading["component_episode_ids"] == [
        "task-actions",
        "task-intent",
    ]
    assert reading["component_count"] == 2
    assert {"intents", "actions", "outcomes"} <= set(
        reading["support_roles"]
    )
    assert "raw:line:10" in reading["support_raw_refs"]
    assert "task-noise" not in reading["component_episode_ids"]


def test_compositional_admission_rejects_one_partial_top_episode() -> None:
    """A manual compositional case showed top-only admission hiding actions."""
    ordinary = {
        "admitted": True,
        "status": "answer_evidence_admitted",
        "basis": "strong_lexical_evidence",
        "relation_gate": {
            "required": False,
            "status": "not_requested",
            "admitted": True,
            "gates": [],
        },
        "explicit_time_evidence_gate": {
            "status": "applied",
            "admitted": True,
        },
    }
    complete_reading = {
        "active": True,
        "status": "multi_episode_support_available",
        "admitted": True,
        "candidate_count": 3,
        "component_count": 2,
        "component_episode_ids": ["task-intent", "task-actions"],
        "support_roles": ["actions", "intents", "outcomes"],
        "support_raw_refs": ["raw:line:10", "raw:line:30"],
        "role_requirements": {
            "intent": True,
            "operational_evidence": True,
            "distinct_strong_roles": True,
        },
    }

    admitted = module.episode_compositional_answer_admission(
        ordinary,
        reading=complete_reading,
    )

    assert admitted["admitted"] is True
    assert admitted["basis"] == "compositional_multi_episode_evidence"
    assert admitted["component_episode_ids"] == [
        "task-intent",
        "task-actions",
    ]
    assert admitted["explicit_time_evidence_gate"]["admitted"] is True

    incomplete_reading = {
        **complete_reading,
        "status": "multi_episode_support_incomplete",
        "admitted": False,
        "component_count": 1,
        "component_episode_ids": ["task-intent"],
        "support_roles": ["intents"],
        "support_raw_refs": ["raw:line:10"],
    }
    rejected = module.episode_compositional_answer_admission(
        ordinary,
        reading=incomplete_reading,
    )

    assert rejected["admitted"] is False
    assert rejected["status"] == "compositional_evidence_incomplete"
    assert rejected["basis"] == "multi_episode_support_incomplete"


def test_compositional_admission_does_not_bypass_typed_relation_gate() -> None:
    """Composite lexical support cannot override an unresolved causal relation."""
    typed = {
        "admitted": False,
        "status": "causal_relation_evidence_unresolved",
        "basis": "causal_relation_unresolved",
        "relation_gate": {
            "required": True,
            "status": "issue_resolution:mutation_without_verification",
            "admitted": False,
            "gates": [
                {
                    "kind": "issue_resolution",
                    "status": "mutation_without_verification",
                    "admitted": False,
                }
            ],
        },
    }
    reading = {
        "active": True,
        "status": "multi_episode_support_available",
        "admitted": True,
        "candidate_count": 2,
        "component_count": 2,
        "component_episode_ids": ["task-failure", "task-repair"],
        "support_roles": ["actions", "failures", "outcomes"],
        "support_raw_refs": ["raw:line:20", "raw:line:40"],
        "role_requirements": {
            "intent": True,
            "operational_evidence": True,
            "distinct_strong_roles": True,
        },
    }

    preserved = module.episode_compositional_answer_admission(
        typed,
        reading=reading,
    )

    assert preserved["admitted"] is False
    assert preserved["status"] == "causal_relation_evidence_unresolved"
    assert preserved["basis"] == "causal_relation_unresolved"
    assert (
        preserved["compositional_evidence"]["status"]
        == "available_but_typed_relation_gate_preserved"
    )


def build_completion_scope_fixture(
    tmp_path: Path,
    *,
    events: list[dict[str, Any]],
) -> dict[str, Any]:
    session_dir = tmp_path / "completion-scope-session"
    raw_path = session_dir / "raw" / "session.raw.jsonl"
    raw_block_path = (
        session_dir
        / "raw"
        / "blocks"
        / "000__initial-to-latest.raw.jsonl"
    )
    raw_rows = [
        {
            "timestamp": event["timestamp"],
            "type": "response_item",
            "payload": {
                "type": "message",
                "role": "assistant",
                "content": [
                    {
                        "type": "output_text",
                        "text": str(
                            event.get("text")
                            or f"fixture event {event['line']}"
                        ),
                    }
                ],
            },
        }
        for event in events
    ]
    write_jsonl(raw_path, raw_rows)
    write_jsonl(raw_block_path, raw_rows)
    raw_sha = hashlib.sha256(raw_path.read_bytes()).hexdigest()
    block_sha = hashlib.sha256(raw_block_path.read_bytes()).hexdigest()
    source_range = {
        "from_line": 1,
        "to_line": len(events),
    }
    source_block = {
        "path": str(raw_block_path),
        "plain_path": str(raw_block_path),
        "source_range": source_range,
        "line_count": len(events),
        "sha256": block_sha,
    }
    index_path = (
        session_dir
        / "segments"
        / "000__initial-to-latest.index.json"
    )
    write_json(
        index_path,
        {
            "schema_version": module.SCHEMA_VERSION,
            "route_signal_classifier_version": (
                module.ROUTE_SIGNAL_CLASSIFIER_VERSION
            ),
            "source_range": source_range,
            "source_block": source_block,
            "events": events,
        },
    )
    write_json(
        session_dir / "session.manifest.json",
        {
            "schema_version": module.SCHEMA_VERSION,
            "session_id": "completion-scope-session",
            "raw": {
                "path": str(raw_path),
                "source_path": str(tmp_path / "archived-source-missing.jsonl"),
                "sha256": raw_sha,
                "line_count": len(events),
            },
            "segments": [
                {
                    "segment_id": "000",
                    "index": str(index_path),
                    "source_range": source_range,
                    "event_count": len(events),
                    "raw_block": source_block,
                }
            ],
        },
    )
    return {
        "record": {
            "session_id": "completion-scope-session",
            "path": str(session_dir),
        },
        "index_path": index_path,
    }


def test_completion_scope_allows_only_bounded_structured_absence(
    tmp_path: Path,
) -> None:
    """A manual bounded window had no closeout or verification signal."""
    fixture = build_completion_scope_fixture(
        tmp_path,
        events=[
            {
                "line": 1,
                "timestamp": "2026-07-11T04:31:00Z",
                "type": "ASSISTANT_MESSAGE",
                "raw_ref": "raw:line:1",
                "outcome": "observed",
                "facets": {
                    "agent_event": {"class": "assistant_plan"},
                },
            },
            {
                "line": 2,
                "timestamp": "2026-07-11T04:31:10Z",
                "type": "TOOL_OUTPUT",
                "raw_ref": "raw:line:2",
                "outcome": "observed",
                "text": (
                    "documentation says completion was verified; this "
                    "successful dump is not a closeout"
                ),
                "facets": {},
            },
            {
                "line": 3,
                "timestamp": "2026-07-11T04:31:20Z",
                "type": "ASSISTANT_MESSAGE",
                "raw_ref": "raw:line:3",
                "outcome": "observed",
                "facets": {
                    "agent_event": {"class": "assistant_progress"},
                },
            },
        ],
    )

    scope = module.episode_completion_evidence_scope(
        resolved_session_record=fixture["record"],
        query_text="было ли completion уже доказано?",
        time_from="2026-07-11T04:31:05Z",
        time_to="2026-07-11T04:31:15Z",
    )

    assert scope["active"] is True
    assert scope["status"] == "not_observed_in_complete_time_window"
    assert scope["absence_claim_allowed"] is True
    assert scope["completion_claim_event_count"] == 0
    assert scope["verification_event_count"] == 0
    assert scope["in_window_event_count"] == 1
    assert scope["archive_integrity"]["status"] == "verified"

    fixture["index_path"].unlink()
    incomplete = module.episode_completion_evidence_scope(
        resolved_session_record=fixture["record"],
        query_text="было ли completion уже доказано?",
        time_from="2026-07-11T04:31:05Z",
        time_to="2026-07-11T04:31:15Z",
    )

    assert incomplete["status"] == "completion_evidence_scope_incomplete"
    assert incomplete["absence_claim_allowed"] is False


