def test_episode_temporal_raw_hydration_requires_query_identifiers_on_each_anchor(
    tmp_path: Path,
) -> None:
    """A structurally similar foreign chain must not satisfy identifier-scoped anchors."""
    raw_path = tmp_path / "session.raw.jsonl"

    def call(call_id: str, command: str) -> dict[str, Any]:
        return {
            "type": "response_item",
            "payload": {
                "type": "function_call",
                "name": "exec_command",
                "call_id": call_id,
                "arguments": json.dumps({"cmd": command}),
            },
        }

    def result(call_id: str, exit_code: int) -> dict[str, Any]:
        return {
            "type": "response_item",
            "payload": {
                "type": "function_call_output",
                "call_id": call_id,
                "output": f"Process exited with code {exit_code}\nFinal output:\n",
            },
        }

    write_jsonl(
        raw_path,
        [
            {"type": "session_meta", "payload": {"id": "temporal-collision-session"}},
            call("call_ForeignCompile999", "python -m py_compile src/foreign.py"),
            result("call_ForeignCompile999", 0),
            call("call_ForeignPytest999", "pytest -q tests/test_foreign.py"),
            result("call_ForeignPytest999", 1),
            call("call_CompileIdentifier123", "python -m py_compile src/runtime.py"),
            result("call_CompileIdentifier123", 0),
            call("call_PytestIdentifier456", "pytest -q tests/test_runtime.py"),
            result("call_PytestIdentifier456", 1),
        ],
    )
    temporal_span = module.episode_temporal_span_query(
        "what happened between call_CompileIdentifier123 py_compile exit 0 and "
        "call_PytestIdentifier456 pytest exit 1"
    )
    candidates = [
        {
            "doc_id": "episode_semantic:temporal-collision-session:task-wrong",
            "session_id": "temporal-collision-session",
            "task_episode_id": "task-wrong",
            "event_range": {"from_line": 2, "to_line": 5},
            "temporal_span": {"active": True, "status": "temporal_span_unresolved_or_unordered"},
        },
        {
            "doc_id": "episode_semantic:temporal-collision-session:task-target",
            "session_id": "temporal-collision-session",
            "task_episode_id": "task-target",
            "event_range": {"from_line": 6, "to_line": 9},
            "temporal_span": {"active": True, "status": "temporal_span_unresolved_or_unordered"},
        },
    ]

    hydrated, hydration = module.episode_temporal_scoped_raw_hydration(
        raw_path=raw_path,
        segments=[],
        results=candidates,
        temporal_span=temporal_span,
        max_raw_bytes=1024 * 1024,
        max_lines=100,
    )

    assert hydration["qualified_candidate_count"] == 1
    assert hydrated[0]["temporal_span"]["status"] != "ordered_span_found"
    assert hydrated[1]["temporal_span"]["status"] == "ordered_span_found"
    assert hydrated[1]["temporal_span"]["admission_basis"].startswith("identifier_backed")


def test_episode_temporal_exact_anchor_seed_adds_episode_missing_from_semantic_pool(
    tmp_path: Path,
) -> None:
    """Synthetic regression derived from a real rank-58 episode outside the BM25 pool."""
    aoa_root = tmp_path / ".aoa"
    aoa_root.mkdir()
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)
    session_id = "temporal-exact-seed-session"
    for doc_id, raw_line, exact_text in (
        (
            "event:temporal-exact-seed-session:left",
            106,
            "call_CompileIdentifier123 py_compile exit 0",
        ),
        (
            "event:temporal-exact-seed-session:right",
            109,
            "call_PytestIdentifier456 pytest exit 1",
        ),
    ):
        module.insert_search_document(
            conn,
            {
                "id": doc_id,
                "doc_type": "event",
                "session_id": session_id,
                "session_label": session_id,
                "session_title": "Temporal exact seed",
                "session_date": "2026-06-11",
                "event_id": str(raw_line),
                "event_type": "COMMAND_OUTPUT",
                "raw_ref": f"raw:line:{raw_line}",
                "manifest_path": "session.manifest.json",
                "title": exact_text,
                "body": exact_text,
                "payload_json": "{}",
                "exact_literal_text": exact_text,
                "exact_literal_source_lane": "response_item",
            },
        )
    conn.execute(
        """
        INSERT INTO exact_literal_session_state(
          session_id, session_label, source_fingerprint, status,
          posting_document_count, projection_version, indexed_at
        ) VALUES (?, ?, 'synthetic', 'current', 2, ?, '2026-06-11T00:00:00Z')
        """,
        (session_id, session_id, module.SEARCH_EXACT_LITERAL_POSTINGS_VERSION),
    )
    episode_cursor = conn.execute(
        """
        INSERT INTO episode_semantic_meta(
          doc_id, session_id, session_label, session_title, session_date,
          episode_id, episode_status, from_line, to_line,
          from_timestamp, to_timestamp, raw_ref, segment_ref, session_ref,
          session_index_path, preview, source_fingerprint, freshness_status,
          projection_version
        ) VALUES (?, ?, ?, 'Temporal exact seed', '2026-06-11',
                  'task-target', 'closed', 100, 120,
                  '', '', 'raw:line:100', '001.md', 'session.manifest.json',
                  'session.index.json', 'bounded text omitted exact call identifiers',
                  'synthetic', 'fresh', ?)
        """,
        (
            f"episode_semantic:{session_id}:task-target",
            session_id,
            session_id,
            module.EPISODE_SEMANTIC_PROJECTION_VERSION,
        ),
    )
    episode_payload = {
        "episode_id": "task-target",
        "status": "closed",
        "event_range": {"from_line": 100, "to_line": 120},
        "time_span": {},
        "representations": {},
        "anchors": {},
        "narrative": "bounded text omitted exact call identifiers",
        "semantic_contract": {},
        "lineage": {},
        "provenance": {},
    }
    conn.execute(
        "INSERT INTO episode_semantic_payloads(doc_rowid, payload_zlib) VALUES (?, ?)",
        (
            episode_cursor.lastrowid,
            sqlite3.Binary(
                module.zlib.compress(
                    json.dumps(episode_payload, separators=(",", ":")).encode("utf-8"),
                    level=6,
                )
            ),
        ),
    )
    conn.commit()
    conn.close()
    query = (
        "what happened between call_CompileIdentifier123 py_compile exit 0 and "
        "call_PytestIdentifier456 pytest exit 1"
    )
    temporal_span = module.episode_temporal_span_query(query)
    semantic_only_candidates = [
        {
            "doc_id": f"episode_semantic:{session_id}:task-wrong",
            "session_id": session_id,
            "task_episode_id": "task-wrong",
            "event_range": {"from_line": 1, "to_line": 20},
        }
    ]

    seeded, report = module.episode_temporal_exact_anchor_seed_candidates(
        aoa_root=aoa_root,
        session_id=session_id,
        results=semantic_only_candidates,
        temporal_span=temporal_span,
        terms=module.episode_semantic_query_terms(query),
        query_text=query,
        normalized_query=module.episode_semantic_fts_query(module.episode_semantic_query_terms(query)),
        explain=True,
    )

    assert report["status"] == "applied"
    assert report["anchor_hit_count"] == 2
    assert report["added_episode_count"] == 1
    assert seeded[0]["task_episode_id"] == "task-target"
    assert seeded[0]["match_channel"] == "episode_exact_temporal_anchor_seed"
    assert {hit["raw_ref"] for hit in seeded[0]["temporal_exact_anchor_seed"]["hits"]} == {
        "raw:line:106",
        "raw:line:109",
    }


def test_episode_temporal_span_requires_interval_intent_not_generic_between_relation() -> None:
    non_temporal_queries = [
        "где contract test поймал рассинхрон stable_fields между exporter и константой",
        "какая разница между pending receipt и reviewed commit",
        "what distinction was made between fixture consistency and runtime effectiveness",
    ]
    temporal_queries = [
        "что произошло между compile exit 0 и pytest exit 1",
        "покажи команды между generated gate и completed export wait",
        "show the commands between the generated gate and the completed export wait",
    ]

    for query in non_temporal_queries:
        temporal_span = module.episode_temporal_span_query(query)
        assert temporal_span["active"] is False, (query, temporal_span)

    for query in temporal_queries:
        temporal_span = module.episode_temporal_span_query(query)
        assert temporal_span["active"] is True, (query, temporal_span)
        assert temporal_span["left_terms"]
        assert temporal_span["right_terms"]


def test_empty_live_tail_merge_preserves_archived_episode_ranking() -> None:
    """Regression from a live deferred session whose fresh tail had no query match."""
    archived = [
        {
            "doc_id": "episode_semantic:session:task-top",
            "session_id": "session",
            "task_episode_id": "task-top",
            "query_coverage": {"coverage": 0.8, "matched_term_count": 8},
            "supporting_evidence": [
                {"matched_query_terms": ["one", "two", "three", "four"]}
            ],
            "rerank_score": 180.0,
        },
        {
            "doc_id": "episode_semantic:session:task-second",
            "session_id": "session",
            "task_episode_id": "task-second",
            "query_coverage": {"coverage": 0.8, "matched_term_count": 8},
            "supporting_evidence": [
                {"matched_query_terms": ["one", "two", "three", "four", "five"]}
            ],
            "rerank_score": 179.0,
        },
    ]

    merged, report = module.merge_archived_and_live_episode_results(
        archived,
        [],
        explain=True,
    )

    assert [item["doc_id"] for item in merged] == [
        "episode_semantic:session:task-top",
        "episode_semantic:session:task-second",
    ]
    assert report["policy"] == "archive_order_preserved_without_live_candidates_v1"
    assert report["live_candidate_count"] == 0


def test_live_tail_merge_preserves_each_source_local_ranking() -> None:
    """A weak live-tail candidate must not reshuffle stale-readable archive candidates."""
    archived = [
        {
            "doc_id": "episode_semantic:session:task-top",
            "session_id": "session",
            "task_episode_id": "task-top",
            "query_coverage": {"coverage": 0.8, "matched_term_count": 8},
            "supporting_evidence": [
                {"matched_query_terms": ["one", "two", "three", "four"]}
            ],
        },
        {
            "doc_id": "episode_semantic:session:task-second",
            "session_id": "session",
            "task_episode_id": "task-second",
            "query_coverage": {"coverage": 0.8, "matched_term_count": 8},
            "supporting_evidence": [
                {"matched_query_terms": ["one", "two", "three", "four", "five"]}
            ],
        },
    ]
    live = [
        {
            "doc_id": "live_tail:session:task-new",
            "session_id": "session",
            "task_episode_id": "task-new",
            "query_coverage": {"coverage": 0.1, "matched_term_count": 1},
            "supporting_evidence": [{"matched_query_terms": ["one"]}],
        }
    ]

    merged, report = module.merge_archived_and_live_episode_results(
        archived,
        live,
        explain=True,
    )

    archived_after_merge = [
        item["doc_id"]
        for item in merged
        if item["retrieval_partition"] == "archive_projection"
    ]
    assert archived_after_merge == [
        "episode_semantic:session:task-top",
        "episode_semantic:session:task-second",
    ]
    assert report["policy"] == "cross_source_score_merge_preserves_source_local_order_v2"


def test_memory_query_intent_separates_exact_typed_episode_temporal_graph_and_diagnostic_lanes() -> None:
    cases = {
        "/srv/AbyssOS/.aoa/scripts/aoa_session_memory.py": "exact_literal",
        "was aoa-session-memory CLI, MCP, or a session-memory skill actually invoked in this span?": "entity_usage",
        "какой terminal stack уже стоял и чего не хватало перед установкой Ghostty": "temporal_state",
        "MV3 background fix -> restart failure -> safer process selection -> successful capture": "causal_chain",
        "как skill aoa-eval связан с MCP и owner route": "relationship_topology",
        "какие повторяющиеся ошибки и решения были во всех старых сессиях": "global_narrative",
        "почему зелёный downstream canary мог не проверить соседние репозитории": "semantic_episode",
        "почему search projection stale и что в maintenance queue": "freshness_diagnostic",
        "что произошло между stale search-provider-status и git add README PIPELINE READINESS": "temporal_state",
        "": "insufficient_evidence",
    }

    for query, expected in cases.items():
        intent = module.memory_query_intent(query)
        assert intent["primary"] == expected, (query, intent)
        assert intent["confidence"] in {"high", "medium", "low"}
        assert intent["signals"] or expected == "insufficient_evidence"


def test_memory_query_intent_keeps_short_ru_paraphrase_and_completion_question_out_of_closeout_literal_lane() -> None:
    semantic_queries = [
        "искали поля состояния и завершённости сессии через rg",
        "какие сессии были подтверждены завершёнными этим поиском?",
    ]

    for query in semantic_queries:
        intent = module.memory_query_intent(query)
        assert intent["primary"] == "semantic_episode", (query, intent)
        assert "exact_literal" not in intent["secondary"]
        assert intent["literal_shape"]["inferred_agent_event"] == ""

    explicit_closeout = module.memory_query_intent("финальный ответ ассистента")
    assert explicit_closeout["primary"] == "exact_literal"
    assert explicit_closeout["literal_shape"]["inferred_agent_event"] == "assistant_final_closeout"


def test_agent_event_route_prefers_session_index_and_keeps_multi_class_shard_sql(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-06-18T00-00-00-agent-event-shards.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-06-18T00:00:00Z", "type": "session_meta", "payload": {"id": "agent-event-shards", "cwd": str(workspace)}},
            {"timestamp": "2026-06-18T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Check shard route"}]}},
            {"timestamp": "2026-06-18T00:00:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Сейчас проверяю shard route."}]}},
            {"timestamp": "2026-06-18T00:00:03Z", "type": "response_item", "payload": {"type": "function_call", "name": "exec_command", "call_id": "call-1", "arguments": "{\"cmd\":\"pytest -q\"}"}},
            {"timestamp": "2026-06-18T00:00:04Z", "type": "response_item", "payload": {"type": "function_call_output", "call_id": "call-1", "output": "1 passed"}},
            {"timestamp": "2026-06-18T00:00:05Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Shard route использует структурные refs и не открывает raw body."}]}},
            {"timestamp": "2026-06-18T00:00:06Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Готово. Итог: проверка прошла."}]}},
        ],
    )

    module.handle_hook_event(
        "Stop",
        {
            "session_id": "agent-event-shards",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    session_dir = next(path for path in (aoa_root / "sessions").iterdir() if path.is_dir())
    assert module.search_index_sessions(aoa_root=aoa_root, target="all", rebuild=True)["ok"] is True
    assert module.materialize_search_shards(aoa_root=aoa_root, target="all")["ok"] is True

    route = module.agent_event_route_search(
        aoa_root=aoa_root,
        session=session_dir.name,
        agent_events=["assistant_answer", "assistant_final_closeout"],
        limit=10,
    )

    assert route["ok"] is True
    assert route["result_count"] == 2
    assert route["uses_shards"] is False
    assert route["uses_fts"] is False
    assert route["elapsed_ms"] >= 0
    assert route["cost_profile"]["uses_session_segment_indexes"] is True
    assert route["cost_profile"]["raw_ref_preview"] is True
    assert route["cost_profile"]["multi_class_structured_sql"] is False
    assert route["cost_profile"]["class_query_count"] == 1
    assert route["cost_profile"]["agent_event_class_count"] == 2
    assert route["search_projection"]["route_kind"] == "agent_event_session_segment_index"
    assert route["provider"]["authoritative_result_provider"] == "session_segment_index"
    assert all(item["refs"]["raw"] for item in route["results"])
    assert all(str(item["preview_source"]).startswith("raw") for item in route["results"])
    assert any("Shard route" in item["bounded_preview"] for item in route["results"])
    assert {item["agent_event"] for item in route["results"]} == {"assistant_answer", "assistant_final_closeout"}

    shard_route = module.agent_event_route_search(
        aoa_root=aoa_root,
        agent_events=["assistant_answer", "assistant_final_closeout"],
        limit=10,
    )

    assert shard_route["ok"] is True
    assert shard_route["result_count"] == 2
    assert shard_route["uses_shards"] is True
    assert shard_route["uses_fts"] is False
    assert shard_route["cost_profile"]["multi_class_structured_sql"] is True
    assert shard_route["cost_profile"]["raw_ref_preview"] is True
    assert shard_route["cost_profile"]["class_query_count"] == 1
    assert shard_route["search_projection"]["route_kind"] == "agent_event_structured_multi_class_shard_sql"
    assert all(str(item["preview_source"]).startswith("raw") for item in shard_route["results"])
    assert any("Shard route" in item["bounded_preview"] for item in shard_route["results"])
    assert {item["agent_event"] for item in shard_route["results"]} == {"assistant_answer", "assistant_final_closeout"}


def test_agent_event_splits_handoff_resume_and_ignores_external_restart(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-06-30T00-00-00-agent-transition.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-06-30T00:00:00Z", "type": "session_meta", "payload": {"id": "agent-transition", "cwd": str(workspace)}},
            {"timestamp": "2026-06-30T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Продолжай проверку session evidence"}]}},
            {"timestamp": "2026-06-30T00:00:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Перезапускаю Chromium, чтобы расширение перечитало service worker."}]}},
            {"timestamp": "2026-06-30T00:00:03Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Вижу перезапуск сессии, восстанавливаю контекст и проверяю refs."}]}},
            {"timestamp": "2026-06-30T00:00:04Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Handoff для следующего агента: продолжить с проверки raw refs."}]}},
        ],
    )

    module.handle_hook_event(
        "Stop",
        {
            "session_id": "agent-transition",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    session_dir = next(path for path in (aoa_root / "sessions").iterdir() if path.is_dir())
    segment_index = json.loads(next((session_dir / "segments").glob("*.index.json")).read_text(encoding="utf-8"))
    events_by_line = {event["line"]: event for event in segment_index["events"]}
    external_restart = events_by_line[3]
    resume = events_by_line[4]
    handoff = events_by_line[5]

    assert external_restart["facets"]["agent_event"]["class"] == "assistant_answer"
    assert "transition_kind" not in external_restart["facets"]["agent_event"]
    assert resume["facets"]["agent_event"]["class"] == "assistant_resume"
    assert resume["facets"]["agent_event"]["transition_kind"] == "resume"
    assert handoff["facets"]["agent_event"]["class"] == "assistant_handoff"
    assert handoff["facets"]["agent_event"]["transition_kind"] == "handoff"

    session_index = json.loads((session_dir / "session.index.json").read_text(encoding="utf-8"))
    episode = session_index["task_episodes"][0]
    transition_agent_events = [ref.get("agent_event") for ref in episode["transition_refs"]]
    assert episode["status"] == "handoff"
    assert transition_agent_events == ["assistant_resume", "assistant_handoff"]

    module.search_index_sessions(aoa_root=aoa_root, target="all", rebuild=True)
    handoff_route = module.agent_event_route_search(
        aoa_root=aoa_root,
        session=session_dir.name,
        agent_events=["handoff"],
        limit=5,
    )
    resume_route = module.agent_event_route_search(
        aoa_root=aoa_root,
        session=session_dir.name,
        agent_events=["resume"],
        limit=5,
    )
    legacy_route = module.agent_event_route_search(
        aoa_root=aoa_root,
        session=session_dir.name,
        agent_events=["assistant_handoff_or_resume"],
        limit=5,
    )

    assert handoff_route["agent_events"] == ["assistant_handoff"]
    assert handoff_route["result_count"] == 1
    assert handoff_route["results"][0]["agent_event"] == "assistant_handoff"
    assert resume_route["agent_events"] == ["assistant_resume"]
    assert resume_route["result_count"] == 1
    assert resume_route["results"][0]["agent_event"] == "assistant_resume"
    assert legacy_route["agent_events"] == [
        "assistant_handoff",
        "assistant_resume",
        "assistant_handoff_or_resume",
    ]
    assert legacy_route["requested_agent_events"] == ["assistant_handoff_or_resume"]
    assert legacy_route["result_count"] == 2
    assert {item["agent_event"] for item in legacy_route["results"]} == {"assistant_handoff", "assistant_resume"}


