def test_session_evidence_window_preserves_custom_tool_transport_completion(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-custom-tool-window.jsonl"
    command = (
        "const r = await tools.exec_command({"
        '"cmd":"sed -n \'1,80p\' /srv/AbyssOS/.aoa/skills/example/SKILL.md",'
        '"workdir":"/home/dionysus"'
        "}); text(r.output);"
    )
    write_jsonl(
        transcript,
        [
            {
                "timestamp": "2026-05-12T00:00:00Z",
                "type": "session_meta",
                "payload": {"id": "custom-tool-evidence-window", "cwd": str(workspace)},
            },
            {
                "timestamp": "2026-05-12T00:00:01Z",
                "type": "response_item",
                "payload": {
                    "type": "message",
                    "role": "user",
                    "content": [{"type": "input_text", "text": "Inspect the example skill source."}],
                },
            },
            {
                "timestamp": "2026-05-12T00:00:02Z",
                "type": "response_item",
                "payload": {
                    "type": "custom_tool_call",
                    "name": "exec",
                    "call_id": "call-custom-window",
                    "input": command,
                },
            },
            {
                "timestamp": "2026-05-12T00:00:03Z",
                "type": "response_item",
                "payload": {
                    "type": "custom_tool_call_output",
                    "call_id": "call-custom-window",
                    "output": [
                        {
                            "type": "input_text",
                            "text": "Script completed\nWall time 0.2 seconds\nOutput:\n",
                        },
                        {
                            "type": "input_text",
                            "text": "A displayed document may contain: Process exited with code 1",
                        },
                    ],
                },
            },
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "custom-tool-evidence-window",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    packet = module.session_evidence_window(
        aoa_root=aoa_root,
        session="custom-tool-evidence-window",
        raw_ref="raw:line:3",
        before=0,
        after=0,
        include_correlated=True,
    )

    assert packet["anchor"]["tool_name"] == "exec"
    assert packet["anchor"]["command"] == command
    assert packet["relations"][0]["evidence_basis"] == "exact_structured_correlation_id"
    result = packet["related_events"][0]
    assert result["transport_status"] == "completed"
    assert result["result_status"] == "observed"
    assert result["result_status_basis"] == "explicit_transport_completion_without_result_outcome"
    assert result["exit_code"] is None

    indexed = module.search_index_sessions(aoa_root=aoa_root, target="all", rebuild=True)
    assert indexed["ok"] is True
    entity_state = module.episode_entity_state_search(
        aoa_root=aoa_root,
        anchor="skill:example",
        kind="skill",
        session="custom-tool-evidence-window",
        limit=10,
    )
    assert entity_state["entity_state"] == "inspected_without_observed_invocation"
    assert entity_state["relation_counts"] == {"inspected": 1}
    assert entity_state["results"][0]["raw_ref"] == "raw:line:3"

    workdir_state = module.episode_entity_state_search(
        aoa_root=aoa_root,
        anchor="path:home_dionysus",
        kind="path",
        session="custom-tool-evidence-window",
        limit=10,
    )
    assert workdir_state["entity_state"] == "action_reference_without_observed_invocation"
    assert workdir_state["relation_counts"] == {"referenced_by_action": 1}

    namespace_state = module.episode_entity_state_search(
        aoa_root=aoa_root,
        anchor="tool:namespace_tool",
        kind="tool",
        session="custom-tool-evidence-window",
        limit=10,
    )
    assert namespace_state["entity_state"] == "invocation_observed"
    assert namespace_state["relation_counts"] == {"invoked": 1}

    indexed_classifier_version = module.ROUTE_SIGNAL_CLASSIFIER_VERSION
    monkeypatch.setattr(
        module,
        "ROUTE_SIGNAL_CLASSIFIER_VERSION",
        indexed_classifier_version + 1,
    )
    stale_entity_state = module.episode_entity_state_search(
        aoa_root=aoa_root,
        anchor="skill:example",
        kind="skill",
        session="custom-tool-evidence-window",
        limit=10,
    )
    assert stale_entity_state["projection"]["status"] == "stale"
    assert stale_entity_state["projection"]["route_available"] is False
    assert stale_entity_state["projection"]["route_signal_classifier_version"] == indexed_classifier_version
    assert stale_entity_state["projection"]["expected_route_signal_classifier_version"] == indexed_classifier_version + 1
    assert "episode_semantic_route_signal_classifier_version_changed" in stale_entity_state["projection"]["reasons"]
    assert stale_entity_state["result_count"] == 0
    assert stale_entity_state["abstention"]["status"] == "insufficient_projection_coverage"

    stale_episode_search = module.episode_semantic_search(
        aoa_root=aoa_root,
        query="inspect example skill source",
        session="custom-tool-evidence-window",
        limit=5,
        mode="sparse",
    )
    assert stale_episode_search["result_count"] == 0
    assert stale_episode_search["projection"]["status"] == "stale"
    assert stale_episode_search["abstention"]["status"] == "insufficient_projection_coverage"

    record = module.resolve_session_record(aoa_root, "custom-tool-evidence-window")
    dirty_projection = module.episode_semantic_projection_state(aoa_root, records=[record])
    assert dirty_projection["status"] == "stale"
    assert dirty_projection["dirty_session_count"] == 1
    assert "episode_semantic_route_signal_classifier_version_changed" in dirty_projection["dirty_sessions"][0]["reasons"]

    queue_seed = module.episode_semantic_queue_seed(
        aoa_root,
        projection_state=dirty_projection,
        now="2026-05-12T00:00:10Z",
        query_demand_counts={"custom-tool-evidence-window": 3},
    )
    assert queue_seed["enqueued_count"] == 1
    queue_conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=False, create_indexes=False)
    assert queue_conn.execute(
        "SELECT demand_count FROM episode_semantic_queue WHERE session_id = ?",
        ("custom-tool-evidence-window",),
    ).fetchone()[0] == 3
    queue_conn.execute(
        "UPDATE episode_semantic_queue SET status = 'blocked_retry_exhausted', attempt_count = ?, "
        "route_signal_classifier_version = ? WHERE session_id = ?",
        (
            module.EPISODE_SEMANTIC_QUEUE_MAX_ATTEMPTS,
            indexed_classifier_version,
            "custom-tool-evidence-window",
        ),
    )
    queue_conn.commit()
    queue_conn.close()
    reset_seed = module.episode_semantic_queue_seed(
        aoa_root,
        projection_state=dirty_projection,
        now="2026-05-12T00:00:11Z",
    )
    assert reset_seed["reset_count"] == 1
    queue_conn = sqlite3.connect(module.search_db_path(aoa_root))
    queue_conn.row_factory = sqlite3.Row
    queued = queue_conn.execute(
        "SELECT status, attempt_count, route_signal_classifier_version, demand_count "
        "FROM episode_semantic_queue WHERE session_id = ?",
        ("custom-tool-evidence-window",),
    ).fetchone()
    queue_conn.close()
    assert queued["status"] == "queued"
    assert queued["attempt_count"] == 0
    assert queued["route_signal_classifier_version"] == indexed_classifier_version + 1
    assert queued["demand_count"] == 0

    refreshed = module.episode_semantic_index_sessions(
        aoa_root=aoa_root,
        target="custom-tool-evidence-window",
        dirty_only=True,
        limit=1,
        max_cost_class="heavy",
    )
    assert refreshed["ok"] is True
    assert refreshed["processed_count"] == 1
    current_entity_state = module.episode_entity_state_search(
        aoa_root=aoa_root,
        anchor="skill:example",
        kind="skill",
        session="custom-tool-evidence-window",
        limit=10,
    )
    assert current_entity_state["projection"]["status"] == "current"
    assert current_entity_state["projection"]["route_available"] is True
    assert current_entity_state["projection"]["route_signal_classifier_version"] == indexed_classifier_version + 1
    assert current_entity_state["entity_state"] == "inspected_without_observed_invocation"
    assert current_entity_state["abstention"]["status"] == "typed_entity_evidence_available"


def test_usage_raw_preview_prefers_raw_block_refs(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-usage-raw-block.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "usage-raw-block", "cwd": str(workspace)}},
            {"timestamp": "2026-05-12T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Use raw block preview for usage evidence."}]}},
            {"timestamp": "2026-05-12T00:00:02Z", "type": "turn_context", "payload": {"summary": "compact boundary"}},
            {"timestamp": "2026-05-12T00:00:03Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Raw block preview is bounded."}]}},
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "usage-raw-block",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    session_dir = aoa_root / "sessions" / "2026-05-12__001__use-raw-block-preview-for-usage-evidence"
    manifest_path = session_dir / "session.manifest.json"
    manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
    first_block = manifest["raw_blocks"]["blocks"][0]
    raw_path = Path(manifest["raw"]["path"])
    raw_lines = raw_path.read_text(encoding="utf-8").splitlines()
    raw_lines[1] = json.dumps({"type": "mutated_full_raw_line"}, ensure_ascii=False)
    raw_path.write_text("\n".join(raw_lines) + "\n", encoding="utf-8")

    preview = module.raw_preview_for_usage_event(
        {
            "refs": {
                "session": str(manifest_path),
                "raw": "raw:line:2",
                "raw_block": first_block["rel"],
            }
        },
        max_chars=1000,
    )

    assert preview["status"] == "available"
    assert preview["source"] == "raw_block"
    assert "Use raw block preview for usage evidence" in preview["text"]
    assert "mutated_full_raw_line" not in preview["text"]


def test_raw_block_storage_compact_reads_compressed_blocks_after_plain_removal(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-raw-block-compact.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "raw-block-compact", "cwd": str(workspace)}},
            {"timestamp": "2026-05-12T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Compact raw block storage"}]}},
            {"timestamp": "2026-05-12T00:00:02Z", "type": "turn_context", "payload": {"summary": "compact boundary"}},
            {"timestamp": "2026-05-12T00:00:03Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Compressed raw block reader should keep refs stable."}]}},
        ],
    )

    module.handle_hook_event(
        "Stop",
        {
            "session_id": "raw-block-compact",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    session_dir = aoa_root / "sessions" / "2026-05-12__001__compact-raw-block-storage"
    manifest = json.loads((session_dir / "session.manifest.json").read_text(encoding="utf-8"))
    first_block = manifest["raw_blocks"]["blocks"][0]
    first_plain_path = Path(first_block["path"])
    first_rel = first_block["rel"]

    plan = module.raw_block_storage_compact(
        aoa_root=aoa_root,
        target=session_dir.name,
        estimate_compression=True,
        sample_limit=8,
    )
    assert plan["ok"] is True
    assert plan["mutates"] is False
    assert plan["planned_count"] == 2
    assert plan["compressed_count"] == 0
    assert plan["plain_bytes"] > 0
    assert plan["compressed_bytes"] > 0

    applied = module.raw_block_storage_compact(
        aoa_root=aoa_root,
        target=session_dir.name,
        apply=True,
        confirm_remove_plain=True,
        sample_limit=8,
    )
    assert applied["ok"] is True
    assert applied["mutates"] is True
    assert applied["compressed_count"] == 2
    assert applied["removed_plain_count"] == 2
    assert applied["post_apply_raw_block_ref_audit"]["ok"] is True

    manifest = json.loads((session_dir / "session.manifest.json").read_text(encoding="utf-8"))
    compressed_block = manifest["raw_blocks"]["blocks"][0]
    assert compressed_block["storage_mode"] == module.RAW_BLOCK_STORAGE_MODE_GZIP
    assert compressed_block["rel"] == first_rel
    assert compressed_block["plain_removed"] is True
    assert not first_plain_path.exists()
    assert Path(compressed_block["compressed_path"]).exists()
    assert manifest["segments"][0]["raw_block"]["storage_mode"] == module.RAW_BLOCK_STORAGE_MODE_GZIP

    preview = module.raw_block_line_preview(
        session_dir,
        manifest,
        "raw:line:2",
        raw_block_ref=first_rel,
    )
    assert preview["status"] == "available"
    assert preview["compressed"] is True
    assert preview["storage_mode"] == module.RAW_BLOCK_STORAGE_MODE_GZIP
    assert preview["block_line"] == 2

    boundary_window = module.session_evidence_window(
        aoa_root=aoa_root,
        session="raw-block-compact",
        raw_ref="raw:line:3",
        before=0,
        after=1,
        include_correlated=True,
    )
    assert boundary_window["ok"] is True
    assert [event["line"] for event in boundary_window["events"]] == [3, 4]
    assert boundary_window["source_integrity"]["verified_count"] == 2
    assert all(
        str(block["payload_ref"]).endswith(".raw.jsonl.gz")
        for block in boundary_window["raw_blocks"]
    )
    assert all(
        str(event["refs"]["raw_block_payload"]).endswith(".raw.jsonl.gz")
        for event in boundary_window["events"]
    )

    audit = module.raw_block_ref_audit(aoa_root=aoa_root, target=session_dir.name, sample_limit=8)
    assert audit["ok"] is True
    assert audit["mismatch_count"] == 0
    assert audit["missing_count"] == 0

    storage = module.session_storage_breakdown(aoa_root)
    assert storage["raw_block_storage"]["plain_bytes"] == 0
    assert storage["raw_block_storage"]["compressed_bytes"] > 0
    assert storage["raw_block_duplication_candidate_bytes"] == 0

    no_candidates = module.raw_block_storage_compact(
        aoa_root=aoa_root,
        target="all",
        skip_no_plain=True,
        limit=20,
    )
    assert no_candidates["ok"] is True
    assert no_candidates["status"] == "current_no_plain_candidates"
    assert no_candidates["selected_count"] == 0


def test_raw_block_storage_compact_skips_deferred_live_sessions(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    live_transcript = tmp_path / "rollout-2026-05-12T00-00-00-raw-block-live.jsonl"
    stable_transcript = tmp_path / "rollout-2026-05-13T00-00-00-raw-block-stable.jsonl"
    write_jsonl(
        live_transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "raw-block-live", "cwd": str(workspace)}},
            {"timestamp": "2026-05-12T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Keep live raw blocks guarded."}]}},
            {"timestamp": "2026-05-12T00:00:02Z", "type": "turn_context", "payload": {"summary": "live compact boundary"}},
            {"timestamp": "2026-05-12T00:00:03Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Live deferred sessions should not be physically compacted."}]}},
        ],
    )
    write_jsonl(
        stable_transcript,
        [
            {"timestamp": "2026-05-13T00:00:00Z", "type": "session_meta", "payload": {"id": "raw-block-stable", "cwd": str(workspace)}},
            {"timestamp": "2026-05-13T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Compact stable raw blocks."}]}},
            {"timestamp": "2026-05-13T00:00:02Z", "type": "turn_context", "payload": {"summary": "stable compact boundary"}},
            {"timestamp": "2026-05-13T00:00:03Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Stable sessions can be compacted."}]}},
        ],
    )
    for transcript, session_id in ((live_transcript, "raw-block-live"), (stable_transcript, "raw-block-stable")):
        module.handle_hook_event(
            "Stop",
            {
                "session_id": session_id,
                "transcript_path": str(transcript),
                "cwd": str(workspace),
                "hook_event_name": "Stop",
            },
            workspace_root=workspace,
            aoa_root=aoa_root,
        )

    live_dir = aoa_root / "sessions" / "2026-05-12__001__keep-live-raw-blocks-guarded"
    stable_dir = aoa_root / "sessions" / "2026-05-13__001__compact-stable-raw-blocks"
    live_manifest = json.loads((live_dir / "session.manifest.json").read_text(encoding="utf-8"))
    stable_manifest = json.loads((stable_dir / "session.manifest.json").read_text(encoding="utf-8"))
    live_plain_path = Path(live_manifest["raw_blocks"]["blocks"][0]["path"])
    stable_plain_path = Path(stable_manifest["raw_blocks"]["blocks"][0]["path"])

    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=False)
    module.upsert_search_freshness_state(
        conn,
        projection_state={
            "session_id": "raw-block-live",
            "session_label": live_dir.name,
            "session_dir": str(live_dir),
            "fingerprint": "live",
            "latest_source_mtime": 1.0,
        },
        status="deferred_live",
        reason="recent_live_projection_updates_deferred",
        checked_at="2026-05-13T00:00:04Z",
        deferred_live_reason="recent_live_codex_transcript_update",
        live_transcript_path=str(live_transcript),
        live_transcript_mtime=1.0,
    )
    conn.commit()
    conn.close()

    live_only = module.raw_block_storage_compact(
        aoa_root=aoa_root,
        target=live_dir.name,
        apply=True,
        confirm_remove_plain=True,
        sample_limit=8,
    )
    assert live_only["ok"] is True
    assert live_only["mutates"] is False
    assert live_only["status"] == "skipped_live_deferred"
    assert live_only["skipped_live_deferred_count"] == 1
    assert live_plain_path.exists()

    mixed = module.raw_block_storage_compact(
        aoa_root=aoa_root,
        target="all",
        skip_no_plain=True,
        limit=20,
        apply=True,
        confirm_remove_plain=True,
        sample_limit=8,
    )
    assert mixed["ok"] is True
    assert mixed["mutates"] is True
    assert mixed["skipped_live_deferred_count"] == 1
    assert any(item["status"] == "skipped_live_deferred" for item in mixed["results"])
    assert live_plain_path.exists()
    assert not stable_plain_path.exists()


def test_raw_block_storage_compact_apply_uses_maintenance_lock(tmp_path: Path, monkeypatch: Any) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    calls: dict[str, Any] = {}

    def fake_lock(root: Path, callback: Any, **kwargs: Any) -> dict[str, Any]:
        calls["root"] = root
        calls.update(kwargs)
        payload = callback()
        payload["maintenance_coordinator"] = {"status": "completed"}
        return payload

    monkeypatch.setattr(module, "run_with_maintenance_lock", fake_lock)
    args = module.argparse.Namespace(
        workspace_root=str(workspace),
        aoa_root=str(aoa_root),
        session="all",
        limit=1,
        skip_no_plain=True,
        apply=True,
        confirm_remove_plain=True,
        estimate_compression=False,
        compression_level=6,
        sample_limit=4,
        write_report=False,
    )

    assert module.command_raw_block_storage_compact(args) == 0
    assert calls["root"] == aoa_root
    assert calls["owner_job"] == "raw-block-storage-compact"
    assert calls["mode"] == "manual-bulk"
    assert calls["target"] == "all"
    assert {"raw_blocks", "session_manifests", "session_registry"} <= set(calls["touched_surfaces"])


def test_reindex_sessions_command_uses_maintenance_lock_for_mutation(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """Regression derived from a real reindex/search catch-up overlap."""

    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    calls: dict[str, Any] = {}

    def fake_reindex(**kwargs: Any) -> dict[str, Any]:
        calls["reindex"] = kwargs
        return {
            "ok": True,
            "artifact_type": "session_reindex",
            "selected_count": 1,
            "processed_count": 1,
            "results": [],
        }

    def fake_lock(root: Path, callback: Any, **kwargs: Any) -> dict[str, Any]:
        calls["root"] = root
        calls.update(kwargs)
        payload = callback()
        payload["maintenance_coordinator"] = {"status": "completed"}
        return payload

    monkeypatch.setattr(module, "reindex_sessions", fake_reindex)
    monkeypatch.setattr(module, "run_with_maintenance_lock", fake_lock)
    args = module.argparse.Namespace(
        workspace_root=str(workspace),
        aoa_root=str(aoa_root),
        session="session-id",
        since=None,
        since_days=None,
        until=None,
        limit=None,
        max_raw_mb=200,
        stale_route_indexes=False,
        budget_seconds=600,
        progress_every=1,
        dry_run=False,
        write_report=False,
        full=False,
    )

    assert module.command_reindex_sessions(args) == 0
    assert calls["root"] == aoa_root
    assert calls["owner_job"] == "reindex-sessions"
    assert calls["mode"] == "manual-bulk"
    assert calls["target"] == "session-id"
    assert calls["reason"] == "operator_reindex_sessions"
    assert {
        "route_indexes",
        "session_manifests",
        "sessions",
        "token_accounting",
    } <= set(calls["touched_surfaces"])
    assert calls["budget_seconds"] == 600
    assert calls["reindex"]["max_raw_bytes"] == 200 * 1024 * 1024


def test_reindex_sessions_command_does_not_report_lock_deferral_as_success(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"

    def fail_reindex(**_kwargs: Any) -> dict[str, Any]:
        raise AssertionError("deferred reindex must not enter the writer")

    def defer_for_lock(_root: Path, _callback: Any, **_kwargs: Any) -> dict[str, Any]:
        return {
            "ok": True,
            "status": "skipped_lock_held",
            "mutates": False,
            "maintenance_coordinator": {"status": "skipped_lock_held"},
        }

    monkeypatch.setattr(module, "reindex_sessions", fail_reindex)
    monkeypatch.setattr(module, "run_with_maintenance_lock", defer_for_lock)
    args = module.argparse.Namespace(
        workspace_root=str(workspace),
        aoa_root=str(aoa_root),
        session="session-id",
        since=None,
        since_days=None,
        until=None,
        limit=None,
        max_raw_mb=200,
        stale_route_indexes=False,
        budget_seconds=600,
        progress_every=1,
        dry_run=False,
        write_report=False,
        full=False,
    )

    assert module.command_reindex_sessions(args) == 1


def test_segment_index_records_conversation_acts(tmp_path: Path, monkeypatch: Any) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-conversation-acts.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "conversation-acts", "cwd": str(workspace)}},
            {"timestamp": "2026-05-12T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Важная идея: нужно индексировать мысли"}]}},
            {"timestamp": "2026-05-12T00:00:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "План: сначала проверю индекс"}]}},
            {"timestamp": "2026-05-12T00:00:03Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Ты не понял, это ошибка"}]}},
            {"timestamp": "2026-05-12T00:00:04Z", "type": "response_item", "payload": {"type": "function_call", "name": "exec_command", "call_id": "call-test", "arguments": json.dumps({"cmd": "pytest -q"})}},
            {"timestamp": "2026-05-12T00:00:05Z", "type": "response_item", "payload": {"type": "function_call_output", "call_id": "call-test", "output": "Process exited with code 0\nOutput:\n2 passed\n"}},
            {"timestamp": "2026-05-12T00:00:06Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Готово: итог проверки зеленый"}]}},
        ],
    )

    module.handle_hook_event(
        "Stop",
        {
            "session_id": "conversation-acts",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    session_dir = aoa_root / "sessions" / "2026-05-12__001__важная-идея-нужно-индексировать-мысли"
    segment_index = json.loads((session_dir / "segments" / "000__initial-to-latest.index.json").read_text(encoding="utf-8"))
    records = {event["event_id"]: event for event in segment_index["events"]}

    assert segment_index["conversation_act_schema_version"] == module.CONVERSATION_ACT_SCHEMA_VERSION
    assert records["000002"]["facets"]["conversation_act"]["kind"] == "operator_concept"
    assert records["000003"]["facets"]["conversation_act"]["kind"] == "assistant_plan"
    assert records["000004"]["facets"]["conversation_act"]["kind"] == "operator_correction"
    assert records["000005"]["facets"]["conversation_act"]["kind"] == "command_verification_request"
    assert records["000006"]["facets"]["conversation_act"]["kind"] == "verification_result"
    assert records["000007"]["facets"]["conversation_act"]["kind"] == "assistant_final_closeout"
    assert segment_index["by_conversation_act"]["operator_concept"] == ["000002"]
    assert segment_index["by_conversation_act"]["operator_correction"] == ["000004"]
    assert segment_index["by_conversation_act"]["verification_result"] == ["000006"]

    audit = module.conversation_act_audit(aoa_root=aoa_root, target="conversation-acts", write_report=True)
    assert audit["ok"] is True
    assert audit["missing_eligible_conversation_act"] == 0
    assert audit["counts"]["operator_concept"] == 1
    assert audit["counts"]["operator_correction"] == 1
    assert audit["counts"]["verification_result"] == 1
    assert Path(audit["report_json"]).exists()
    assert Path(audit["report_markdown"]).exists()
    monkeypatch.setattr(module, "compact_stamp", lambda: "20260614T000000Z")
    first_report = module.conversation_act_audit(aoa_root=aoa_root, target="conversation-acts", write_report=True)
    second_report = module.conversation_act_audit(aoa_root=aoa_root, target="conversation-acts", write_report=True)
    assert first_report["report_json"] != second_report["report_json"]
    assert first_report["report_json"].endswith("__conversation-act-audit.json")
    assert second_report["report_json"].endswith("__conversation-act-audit__01.json")
    assert Path(first_report["report_json"]).exists()
    assert Path(second_report["report_json"]).exists()


