def test_entity_registry_lookup_falls_back_to_observed_route_terms(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    (aoa_root / module.ENTITY_REGISTRY_PATH.parent).mkdir(parents=True)
    module.write_json(
        aoa_root / module.ENTITY_REGISTRY_PATH,
        {
            "schema_version": module.ENTITY_REGISTRY_SCHEMA_VERSION,
            "artifact_type": "entity_registry_snapshot",
            "generated_at": "2026-06-26T00:00:00Z",
            "ok": True,
            "entries": [],
        },
    )
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)

    def insert_observed_route(layer: str, key: str, *, event_id: str) -> None:
        route_signal = f"{layer}:{key}"
        conn.execute(
            "INSERT OR IGNORE INTO route_terms(layer, key, route_signal) VALUES (?, ?, ?)",
            (layer, key, route_signal),
        )
        route_id = conn.execute("SELECT id FROM route_terms WHERE route_signal = ?", (route_signal,)).fetchone()[0]
        cursor = conn.execute(
            """
            INSERT INTO documents(
              id, doc_type, session_id, session_label, session_date, event_id,
              event_type, session_act, usage_role, route_signals, raw_ref, manifest_path, payload_json
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                f"event:observed-route:{event_id}",
                "event",
                "observed-route",
                "observed-route",
                "2026-06-26",
                event_id,
                "COMMAND",
                "tool_call",
                "usage",
                f"|{route_signal}|",
                f"raw:line:{int(event_id)}",
                "session.manifest.json",
                "{}",
            ),
        )
        conn.execute("INSERT INTO document_routes(doc_rowid, route_id) VALUES (?, ?)", (cursor.lastrowid, route_id))

    insert_observed_route("script", "skill_intelligence", event_id="000001")
    insert_observed_route("goal", "goal_inspected", event_id="000002")
    insert_observed_route("git", "commit", event_id="000003")
    insert_observed_route("agent", "sub_agent", event_id="000004")
    insert_observed_route("decision_thread", "open_thread", event_id="000005")
    insert_observed_route("failure_mode", "test_failure", event_id="000006")
    insert_observed_route("hook_health", "userpromptsubmit", event_id="000007")
    insert_observed_route("agent_event", "assistant_answer", event_id="000008")
    insert_observed_route("owner_route", "abyss_stack", event_id="000009")
    insert_observed_route("route_next_action", "repair", event_id="000010")
    conn.commit()
    conn.close()

    lookup = module.entity_registry_lookup(aoa_root=aoa_root, anchor="skill_intelligence", kind="script")

    assert lookup["agent_route_packet"]["registered"] is True
    assert lookup["entries"][0]["kind"] == "script"
    assert lookup["entries"][0]["canonical_key"] == "skill_intelligence"
    assert lookup["entries"][0]["status"] == "observed"
    assert lookup["entries"][0]["source_surface"] == "archived_route_terms"
    assert lookup["entries"][0]["freshness"]["signal_count"] == 1
    assert lookup["entries"][0]["freshness"]["session_count"] == 1

    observed_expectations = [
        ("goal_inspected", "goal", "goal_inspected", "goal:goal_inspected"),
        ("commit", "git", "commit", "git:commit"),
        ("sub_agent", "agent", "sub_agent", "agent:sub_agent"),
        ("open_thread", "decision", "open_thread", "decision_thread:open_thread"),
        ("test_failure", "error", "test_failure", "failure_mode:test_failure"),
        ("userpromptsubmit", "receipt", "userpromptsubmit", "hook_health:userpromptsubmit"),
        ("assistant_answer", "agent_event", "assistant_answer", "agent_event:assistant_answer"),
        ("abyss_stack", "owner_route", "abyss_stack", "owner_route:abyss_stack"),
        ("repair", "route_next_action", "repair", "route_next_action:repair"),
    ]
    for anchor, kind, key, route_signal in observed_expectations:
        typed_lookup = module.entity_registry_lookup(aoa_root=aoa_root, anchor=anchor, kind=kind)
        assert typed_lookup["agent_route_packet"]["registered"] is True
        assert typed_lookup["entries"][0]["kind"] == kind
        assert typed_lookup["entries"][0]["canonical_key"] == key
        assert typed_lookup["entries"][0]["route_signal"] == route_signal
        assert typed_lookup["entries"][0]["status"] == "observed"
        assert typed_lookup["entries"][0]["source_surface"] == "archived_route_terms"

    receipt_candidates = module.trace_route_candidates("userpromptsubmit", kind="receipt")
    error_candidates = module.trace_route_candidates("test_failure", kind="error")
    owner_route_candidates = module.trace_route_candidates("abyss_stack", kind="owner_route")
    next_action_candidates = module.trace_route_candidates("repair", kind="route_next_action")
    assert any(candidate["route_signal"] == "hook_health:userpromptsubmit" for candidate in receipt_candidates)
    assert any(candidate["route_signal"] == "failure_mode:test_failure" for candidate in error_candidates)
    assert any(candidate["route_signal"] == "owner_route:abyss_stack" for candidate in owner_route_candidates)
    assert any(candidate["route_signal"] == "route_next_action:repair" for candidate in next_action_candidates)


def test_entity_registry_uses_rollup_observed_source_and_retains_previous_observed(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    (aoa_root / module.ENTITY_REGISTRY_PATH.parent).mkdir(parents=True)
    previous_entry = module.entity_registry_make_entry(
        kind="validator",
        key="legacy_full_route_validator",
        aliases=["validator:legacy_full_route_validator"],
        source_refs=[
            {
                "source_type": "search_route_terms",
                "path": str(module.search_db_path(aoa_root)),
                "status": "observed",
                "latest_session_date": "2026-06-25",
            }
        ],
        source_surface="archived_route_terms",
        owner="aoa-session-memory",
        status="observed",
        signal_count=7,
        session_count=2,
    )
    module.write_json(
        aoa_root / module.ENTITY_REGISTRY_PATH,
        {
            "schema_version": module.ENTITY_REGISTRY_SCHEMA_VERSION,
            "artifact_type": "entity_registry_snapshot",
            "generated_at": "2026-06-26T00:00:00Z",
            "generated_at_epoch": 1782432000.0,
            "ok": True,
            "entity_count": 1,
            "counts_by_kind": {"validator": 1},
            "counts_by_status": {"observed": 1},
            "entries": [previous_entry],
        },
    )
    shard_db = aoa_root / "search" / "shards" / "2026-06.sqlite3"
    shard_db.parent.mkdir(parents=True)
    shard_db.write_text("dummy shard", encoding="utf-8")
    rollup_db = module.search_operational_route_rollup_db_path(aoa_root)
    conn = module.init_search_operational_route_rollup_db(rollup_db)
    conn.executemany(
        "INSERT OR REPLACE INTO meta(key, value) VALUES (?, ?)",
        [
            ("artifact_type", "session_memory_search_operational_route_rollup"),
            ("rollup_schema_version", str(module.SEARCH_OPERATIONAL_ROUTE_ROLLUP_SCHEMA_VERSION)),
            ("generated_at", "2026-06-26T00:01:00Z"),
        ],
    )
    conn.execute(
        """
        INSERT INTO shards(
            shard, shard_db_path, source_size_bytes, source_mtime_ns, generated_at, status,
            event_total, candidate_tail_count, candidate_tail_with_route_signals_count,
            candidate_route_posting_count, candidate_route_term_count, elapsed_ms
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            "month/2026-06",
            str(shard_db),
            module.path_total_size(shard_db),
            shard_db.stat().st_mtime_ns,
            "2026-06-26T00:01:00Z",
            "current",
            3,
            3,
            3,
            3,
            1,
            1,
        ),
    )
    conn.execute(
        """
        INSERT INTO route_rollups(
            shard, layer, key, route_signal, posting_count, session_count,
            first_session_date, last_session_date, raw_refs_json, segment_refs_json, session_ids_json
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            "month/2026-06",
            "script",
            "fast_rollup_script",
            "script:fast_rollup_script",
            3,
            1,
            "2026-06-26",
            "2026-06-26",
            json.dumps(["raw:line:1"]),
            json.dumps(["000__initial-to-latest.md#event-000001"]),
            json.dumps(["rollup-session"]),
        ),
    )
    conn.commit()
    conn.close()

    payload = module.build_entity_registry(
        aoa_root=aoa_root,
        write=True,
        include_runtime=False,
        observed_source="route-rollup",
    )
    entries = {(entry["kind"], entry["canonical_key"]): entry for entry in payload["entries"]}

    assert payload["observed_route_source"] == "operational_route_rollup"
    assert entries[("script", "fast_rollup_script")]["source_surface"] == "operational_route_rollup"
    retained = entries[("validator", "legacy_full_route_validator")]
    assert retained["source_surface"] == "archived_route_terms"
    assert retained["retained_from_snapshot"]["reason"] == "fast_observed_route_uses_operational_rollup"
    assert "observed_entity_retained_from_previous_snapshot" in retained["freshness"]["diagnostics"]


def test_entity_registry_auto_uses_stale_materialized_rollup_before_route_terms(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
