def test_generic_usage_keeps_shared_consequence_edges_and_consistent_rejection_counts(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    usage_hits = [
        {
            "doc_id": f"event:session:001:00000{index}",
            "event_id": f"00000{index}",
            "event_type": "TOOL_CALL",
            "conversation_act": "tool_call_request",
            "session_act": "tool_call",
            "usage_role": "usage",
            "title": f"MCP call {index}",
            "route_signals": "mcp:aoa_session_memory_mcp",
            "refs": {
                "raw": f"raw:line:{index}",
                "segment": f"001.md#event-00000{index}",
            },
            "freshness": {"status": "fresh"},
        }
        for index in (1, 2)
    ]

    def fake_search_sessions(**kwargs: Any) -> dict[str, Any]:
        hits = usage_hits if kwargs.get("usage_role") == "usage" else []
        return {"ok": True, "result_count": len(hits), "results": hits, "diagnostics": []}

    def fake_consequences(
        hit: dict[str, Any],
        *,
        false_correlation_events: list[dict[str, Any]],
        **_kwargs: Any,
    ) -> list[dict[str, Any]]:
        source_doc_id = str(hit["doc_id"])
        false_correlation_events.append(
            {
                "doc_id": "event:session:001:000099",
                "source_doc_id": source_doc_id,
                "event_id": "000099",
                "event_type": "TOOL_OUTPUT",
                "role": "context",
                "source_correlation_id": source_doc_id,
                "rejected_correlation_id": "foreign-call",
                "correlation_id": "foreign-call",
                "refs": {
                    "raw": "raw:line:99",
                    "segment": "001.md#event-000099",
                },
                "freshness": {"status": "fresh"},
            }
        )
        return [
            {
                "doc_id": "event:session:001:000010",
                "source_doc_id": source_doc_id,
                "event_id": "000010",
                "event_type": "TOOL_OUTPUT",
                "role": "result",
                "relation": "same_correlation_id",
                "outcome": "succeeded",
                "title": "Shared result event",
                "refs": {
                    "raw": "raw:line:10",
                    "segment": "001.md#event-000010",
                },
                "freshness": {"status": "fresh"},
            }
        ]

    monkeypatch.setattr(module, "search_sessions", fake_search_sessions)
    monkeypatch.setattr(module, "consequence_events_for_usage_hit", fake_consequences)
    monkeypatch.setattr(module, "search_usage_role_filter_supported", lambda *_args, **_kwargs: True)
    monkeypatch.setattr(
        module,
        "search_provider_status_fast",
        lambda **_kwargs: {"providers": {"portable_sqlite": {"freshness": {"status": "current"}}}},
    )

    audit = module.entity_usage_audit(
        aoa_root=tmp_path / ".aoa",
        anchor="aoa-session-memory-mcp",
        kind="mcp",
        limit=2,
        per_route_limit=2,
    )

    assert audit["consequence_event_count"] == 2
    assert {event["source_doc_id"] for event in audit["consequence_events"]} == {
        usage_hits[0]["doc_id"],
        usage_hits[1]["doc_id"],
    }
    assert audit["false_correlation_edge_count"] == 2
    assert audit["unique_false_correlation_event_count"] == 1
    assert audit["quality"]["false_correlation_edge_count"] == 2
    assert audit["quality"]["unique_false_correlation_event_count"] == 1
    assert "false_correlation_edges: `2`" in module.entity_usage_audit_markdown(audit)

    chain = module.entity_usage_chain(
        aoa_root=tmp_path / ".aoa",
        anchor="aoa-session-memory-mcp",
        kind="mcp",
        limit=2,
        per_route_limit=2,
    )
    assert [item["has_result_or_consequence"] for item in chain["usage_chain"]["chains"]] == [
        True,
        True,
    ]
    assert chain["counts"]["false_correlation_edge_count"] == 2
    assert chain["counts"]["unique_false_correlation_event_count"] == 1
    assert "false_correlation_edges: `2`" in module.entity_usage_chain_markdown(chain)


def test_unique_entity_usage_events_keeps_strongest_correlated_role() -> None:
    context_view = {
        "doc_id": "event:session:001:000004",
        "event_id": "000004",
        "event_type": "HOOK_EVENT",
        "role": "context",
        "outcome": "succeeded",
        "refs": {"raw": "raw:line:4"},
    }
    result_view = {
        **context_view,
        "role": "result",
        "relation": "same_correlation_id",
        "correlation_id": "call-4",
    }

    unique = module.unique_entity_usage_events([context_view, result_view])

    assert unique == [result_view]
    assert module.entity_usage_event_action_semantics(unique[0]) == ["observed"]


def test_entity_usage_audit_retries_route_window_before_text_fallback(tmp_path: Path, monkeypatch: Any) -> None:
    result_hits = [
        {
            "doc_id": f"event:session:001:{index:06d}",
            "event_type": "COMMAND_OUTPUT",
            "conversation_act": "tool_output_success",
            "session_act": "memory_observation",
            "title": f"MCP result {index}",
            "route_signals": "mcp:aoa_decisions_mcp",
            "refs": {"raw": f"raw:line:{index}", "segment": "001.md", "session": "session.manifest.json"},
        }
        for index in range(1, 31)
    ]
    usage_hit = {
        "doc_id": "event:session:001:000031",
        "event_type": "TOOL_CALL",
        "conversation_act": "tool_call_request",
        "session_act": "tool_call",
        "title": "MCP usage",
        "route_signals": "mcp:aoa_decisions_mcp",
        "refs": {"raw": "raw:line:31", "segment": "001.md", "session": "session.manifest.json"},
    }
    candidate_hits = [*result_hits, usage_hit]
    called_limits: list[int] = []
    called_queries: list[str] = []

    def fake_search_sessions(**kwargs: Any) -> dict[str, Any]:
        called_limits.append(int(kwargs.get("limit") or 0))
        called_queries.append(str(kwargs.get("query") or ""))
        limit = int(kwargs.get("limit") or 0)
        return {"ok": True, "result_count": min(limit, len(candidate_hits)), "results": candidate_hits[:limit], "diagnostics": []}

    def fake_provider_status(**_kwargs: Any) -> dict[str, Any]:
        return {
            "schema_version": 1,
            "artifact_type": "search_provider_status",
            "ok": True,
            "authority_law": "portable sqlite remains authoritative",
            "selected_provider": "portable_sqlite",
            "freshness_mode": "hot",
            "providers": {
                "portable_sqlite": {
                    "provider": "portable_sqlite",
                    "ok": True,
                    "status": "ready",
                    "has_route_index": True,
                    "has_route_terms": True,
                    "freshness": {"status": "current", "checked": True},
                }
            },
        }

    monkeypatch.setattr(module, "search_sessions", fake_search_sessions)
    monkeypatch.setattr(module, "search_provider_status", fake_provider_status)

    audit = module.entity_usage_audit(
        aoa_root=tmp_path / ".aoa",
        anchor="aoa-decisions-mcp",
        kind="mcp",
        limit=3,
        per_route_limit=3,
    )

    assert audit["ok"] is True
    assert audit["usage_event_count"] == 1
    assert audit["usage_events"][0]["doc_id"] == "event:session:001:000031"
    assert audit["quality"]["route_usage_retry_applied"] is True
    assert max(called_limits) > 12
    assert set(called_queries) == {""}
    assert audit["quality"]["text_search_skipped"] is True


def test_entity_usage_audit_routes_explicit_non_aoa_mcp_service_names(tmp_path: Path, monkeypatch: Any) -> None:
    usage_hit = {
        "doc_id": "event:session:001:000001",
        "event_id": "000001",
        "event_type": "TOOL_CALL",
        "conversation_act": "tool_call_request",
        "session_act": "tool_call",
        "usage_role": "usage",
        "title": "Tool call: tos_corpus_lookup",
        "route_signals": "mcp:tos_corpus_mcp",
        "refs": {"raw": "raw:line:1", "segment": "001.md", "session": "session.manifest.json"},
    }
    called_route_signals: list[str] = []
    called_queries: list[str] = []

    def fake_search_sessions(**kwargs: Any) -> dict[str, Any]:
        route_signal = str(kwargs.get("route_signal") or "")
        query = str(kwargs.get("query") or "")
        called_route_signals.append(route_signal)
        called_queries.append(query)
        if route_signal in {"entity:tos", "entity:mcp"}:
            raise AssertionError(f"fragment entity route should be suppressed for precise MCP service anchor: {route_signal}")
        if query:
            raise AssertionError("precise MCP service route should not fall back to broad text search")
        if route_signal == "mcp:tos_corpus_mcp":
            return {"ok": True, "result_count": 1, "results": [usage_hit], "diagnostics": []}
        return {"ok": True, "result_count": 0, "results": [], "diagnostics": []}

    def fake_provider_status(**_kwargs: Any) -> dict[str, Any]:
        return {
            "providers": {
                "portable_sqlite": {
                    "has_route_index": True,
                    "has_route_terms": True,
                    "freshness": {"status": "current", "checked": True},
                }
            }
        }

    monkeypatch.setattr(module, "search_sessions", fake_search_sessions)
    monkeypatch.setattr(module, "search_provider_status", fake_provider_status)
    monkeypatch.setattr(module, "search_usage_role_filter_supported", lambda *_args, **_kwargs: False)

    audit = module.entity_usage_audit(
        aoa_root=tmp_path / ".aoa",
        anchor="tos-corpus-mcp",
        kind="mcp",
        limit=1,
        per_route_limit=1,
    )

    candidate_routes = {
        candidate.get("route_signal")
        for candidate in audit.get("route_candidates", [])
        if isinstance(candidate, dict)
    }
    assert audit["ok"] is True
    assert "mcp:tos_corpus_mcp" in candidate_routes
    assert "entity:tos_corpus_mcp" in candidate_routes
    assert "entity:tos" not in candidate_routes
    assert "entity:mcp" not in candidate_routes
    assert audit["usage_event_count"] == 1
    assert audit["usage_events"][0]["matched_routes"] == ["mcp:tos_corpus_mcp"]
    assert audit["quality"]["direct_usage_present"] is True
    assert audit["quality"]["text_search_skipped"] is True
    assert set(called_queries) == {""}
    assert "mcp:tos_corpus_mcp" in called_route_signals


