    assert [event["refs"]["raw"] for event in audit["context_events"]] == ["raw:line:2"]
    assert audit["context_events"][0]["relation"] == "route_result_correlation_rejected"
    assert audit["quality"]["direct_result_correlation_rejected_count"] == 1
    assert audit["quality"]["direct_result_correlation_owned_count"] == 1


