def test_sub_agent_activity_is_correlated_operational_status_not_hook_event() -> None:
    """Regression derived from a real collaboration send_message activity packet."""

    row = {
        "timestamp": "2026-07-11T05:31:15.920Z",
        "type": "event_msg",
        "payload": {
            "type": "sub_agent_activity",
            "event_id": "call-activity",
            "agent_thread_id": "agent-thread",
            "agent_path": "/root",
            "kind": "interacted",
        },
    }

    event = module.classify_raw_event(json.dumps(row), row, 2)

    assert event.event_type == "CONTEXT_STATE"
    assert event.correlation_id == "call-activity"
    assert event.facets["message_type"] == "sub_agent_activity"
    assert event.facets["conversation_act"]["kind"] == "agent_activity_status"
    assert event.facets["session_act"]["kind"] == "agent_activity_status"
    assert event.facets["agent_activity"]["kind"] == "interacted"
    route_signals = {
        (item["layer"], item["key"])
        for item in event.facets["route_signals"]
    }
    assert ("correlation", "tool_call_output_link") in route_signals
    assert not any(layer in {"hook", "hook_health"} for layer, _key in route_signals)


def test_task_episode_admits_only_correlated_sub_agent_activity_as_bounded_status() -> None:
    """Manual wave invariant: structured status outranks unrelated `git status` text."""

    correlated_row = {
        "timestamp": "2026-07-11T05:31:15.920Z",
        "type": "event_msg",
        "payload": {
            "type": "sub_agent_activity",
            "event_id": "call-activity",
            "agent_thread_id": "agent-thread",
            "agent_path": "/root",
            "kind": "interacted",
        },
    }
    uncorrelated_row = {
        "timestamp": "2026-07-11T05:31:16.000Z",
        "type": "event_msg",
        "payload": {
            "type": "sub_agent_activity",
            "agent_path": "/root",
            "kind": "interacted",
        },
    }
    segments = [
        {
            "segment_id": "001",
            "markdown": "001.md",
            "index": "001.index.json",
            "source_range": {"from_line": 1, "to_line": 3},
        }
    ]
    correlated = module.classify_raw_event(
        json.dumps(correlated_row),
        correlated_row,
        2,
    )
    uncorrelated = module.classify_raw_event(
        json.dumps(uncorrelated_row),
        uncorrelated_row,
        3,
    )

    entry = module.task_episode_representation_entry(
        correlated,
        segments,
        linked_action="send_message",
        linked_action_event_type="TOOL_CALL",
    )
    rejected = module.task_episode_representation_entry(
        uncorrelated,
        segments,
        linked_action="send_message",
        linked_action_event_type="TOOL_CALL",
    )

    assert entry is not None
    assert entry["evidence_role"] == "outcomes"
    assert entry["source_lane"] == "structured_agent_activity_status"
    assert entry["admission_basis"] == "structured_correlated_status"
    assert entry["outcome"] == "observed"
    assert entry["refs"]["raw"] == "raw:line:2"
    assert "send_message" in entry["text"]
    assert "kind=interacted" in entry["text"]
    assert "agent_path=/root" in entry["text"]
    assert "call-activity" in entry["text"]
    assert "succeeded" not in entry["text"]
    assert rejected is None


