def test_episode_sparse_search_exposes_rejected_status_collision(tmp_path: Path) -> None:
    """The public reader must show typed noise it rejected, not hide the audit trail."""

    aoa_root = tmp_path / ".aoa"
    conn = module.init_search_db(
        module.search_db_path(aoa_root),
        rebuild=False,
        create_indexes=False,
    )
    episode = {
        "episode_id": "task-0001",
        "event_range": {"from_line": 1, "to_line": 4},
        "representations": {
            "actions": [
                {
                    "text": "git status --short --branch",
                    "source_lane": "structured_tool_call",
                    "evidence_role": "actions",
                    "admission_basis": "structured_operational_action",
                    "event_type": "TOOL_CALL",
                    "outcome": "requested",
                    "line": 2,
                    "refs": {"raw": "raw:line:2"},
                }
            ],
            "outcomes": [
                {
                    "text": "structured agent activity status: kind=interacted",
                    "source_lane": "structured_agent_activity_status",
                    "evidence_role": "outcomes",
                    "admission_basis": "structured_correlated_status",
                    "event_type": "CONTEXT_STATE",
                    "outcome": "observed",
                    "line": 3,
                    "refs": {"raw": "raw:line:3"},
                }
            ],
        },
        "narrative": "",
    }
    cursor = conn.execute(
        """
        INSERT INTO episode_semantic_meta (
            doc_id, session_id, session_label, session_title, session_date,
            episode_id, episode_status, from_line, to_line,
            raw_ref, segment_ref, session_ref, session_index_path, preview,
            source_fingerprint, freshness_status, projection_version
        ) VALUES ('episode_semantic:status-collision:task-0001',
                  'status-collision', 'status-collision', '', '2026-07-14',
                  'task-0001', 'closed', 1, 4,
                  'raw:line:1', '001.md', 'session.manifest.json',
                  'session.index.json', 'agent interaction status',
                  'synthetic', 'fresh', ?)
        """,
        (module.EPISODE_SEMANTIC_PROJECTION_VERSION,),
    )
    conn.execute(
        """
        INSERT INTO episode_semantic_fts (
            rowid, intents, plans, actions, outcomes, verification,
            failures, reasoning, narrative, anchors
        ) VALUES (?, '', '', ?, ?, '', '', '', '', '')
        """,
        (
            cursor.lastrowid,
            "git status --short --branch",
            "structured agent activity status: kind=interacted",
        ),
    )
    conn.execute(
        "INSERT INTO episode_semantic_payloads(doc_rowid, payload_zlib) VALUES (?, ?)",
        (
            cursor.lastrowid,
            sqlite3.Binary(
                module.zlib.compress(
                    json.dumps(episode, separators=(",", ":")).encode("utf-8")
                )
            ),
        ),
    )
    conn.execute(
        """
        INSERT INTO episode_semantic_session_state (
            session_id, session_label, source_fingerprint, status,
            episode_count, projection_version, indexed_at,
            source_fingerprint_mode, route_signal_classifier_version
        ) VALUES ('status-collision', 'status-collision', 'synthetic',
                  'current', 1, ?, '2026-07-14T00:00:00Z', ?, ?)
        """,
        (
            module.EPISODE_SEMANTIC_PROJECTION_VERSION,
            module.EPISODE_SEMANTIC_SOURCE_FINGERPRINT_MODE,
            module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
        ),
    )
    conn.commit()
    conn.close()

    result = module.episode_semantic_search(
        aoa_root=aoa_root,
        query="agent interaction status",
        mode="sparse",
        limit=1,
    )

    assert result["ok"] is True
    assert result["results"][0]["support_rejections"] == [
        {
            "reason": "generic_status_token_outside_structured_agent_activity",
            "line": 2,
            "matched_query_terms": ["status"],
            "source_lane": "structured_tool_call",
            "admission_basis": "structured_operational_action",
            "refs": {"raw": "raw:line:2"},
        }
    ]


