def test_consequence_events_follow_async_results_with_semantic_event_classification(
    tmp_path: Path,
) -> None:
    """Regression derived from a sealed long-running process-session chain."""

    rows = [
        {
            "type": "response_item",
            "payload": {
                "type": "function_call",
                "name": "exec_command",
                "call_id": "call-origin",
                "arguments": json.dumps({"cmd": "tools/snapshot-audit active"}),
            },
        },
        {
            "type": "response_item",
            "payload": {
                "type": "function_call_output",
                "call_id": "call-origin",
                "output": "Process running with session ID 9001\nOutput:\nstarted",
            },
        },
        {
            "type": "response_item",
            "payload": {
                "type": "function_call",
                "name": "write_stdin",
                "call_id": "call-poll-one",
                "arguments": json.dumps({"session_id": 9001, "chars": ""}),
            },
        },
        {
            "type": "response_item",
            "payload": {
                "type": "function_call_output",
                "call_id": "call-poll-one",
                "output": (
                    "Process running with session ID 9001\nOutput:\n"
                    "bounded security-sensitive path inventory"
                ),
            },
        },
        {
            "type": "response_item",
            "payload": {
                "type": "function_call",
                "name": "write_stdin",
                "call_id": "call-poll-two",
                "arguments": json.dumps({"session_id": 9001, "chars": ""}),
            },
        },
        {
            "type": "response_item",
            "payload": {
                "type": "function_call_output",
                "call_id": "call-poll-two",
                "output": (
                    "Process running with session ID 9001\nOutput:\n"
                    "documentation says ERROR while the process is still running"
                ),
            },
        },
        {
            "type": "response_item",
            "payload": {
                "type": "function_call",
                "name": "write_stdin",
                "call_id": "call-poll-terminal",
                "arguments": json.dumps({"session_id": 9001, "chars": ""}),
            },
        },
        {
            "type": "response_item",
            "payload": {
                "type": "function_call_output",
                "call_id": "call-poll-terminal",
                "output": "Process exited with code 0\nOutput:\ncomplete",
            },
        },
    ]
    event_types = [
        "COMMAND",
        "TOOL_OUTPUT",
        "COMMAND",
        "SECURITY_TOUCHPOINT",
        "COMMAND",
        "ERROR",
        "COMMAND",
        "COMMAND_OUTPUT",
    ]
    correlations = [
        "call-origin",
        "call-origin",
        "call-poll-one",
        "call-poll-one",
        "call-poll-two",
        "call-poll-two",
        "call-poll-terminal",
        "call-poll-terminal",
    ]
    events = [
        {
            "event_id": f"{line:06d}",
            "type": event_type,
            "correlation_id": correlation,
            "raw_ref": f"raw:line:{line}",
            "facets": {
                "payload_type": (
                    "function_call_output"
                    if line in {2, 4, 6, 8}
                    else "function_call"
                ),
                "session_act": {
                    "tool_name": (
                        "exec_command"
                        if line == 1
                        else "write_stdin"
                        if line in {3, 5, 7}
                        else ""
                    )
                },
            },
        }
        for line, (event_type, correlation) in enumerate(
            zip(event_types, correlations),
            1,
        )
    ]
    hit, caches = async_usage_fixture(tmp_path, rows=rows, events=events)
    async_diagnostics: dict[str, int] = {}
    false_correlations: list[dict[str, Any]] = []

    consequences = module.consequence_events_for_usage_hit(
        hit,
        window=8,
        false_correlation_events=false_correlations,
        manifest_cache=caches["manifest"],
        raw_preview_cache=caches["raw_preview"],
        async_diagnostics=async_diagnostics,
    )
    compact = {
        event["refs"]["raw"]: module.entity_usage_chain_event(event)
        for event in consequences
    }

    assert list(compact) == [
        "raw:line:2",
        "raw:line:3",
        "raw:line:4",
        "raw:line:5",
        "raw:line:6",
        "raw:line:7",
        "raw:line:8",
    ]
    assert compact["raw:line:4"]["event_type"] == "SECURITY_TOUCHPOINT"
    assert compact["raw:line:4"]["result_status"] == "running"
    assert compact["raw:line:4"]["outcome"] == "observed"
    assert compact["raw:line:6"]["event_type"] == "TOOL_OUTPUT"
    assert compact["raw:line:6"]["classified_event_type"] == "ERROR"
    assert compact["raw:line:6"]["classification_shadowed_by"] == (
        "source_verified_async_running_envelope"
    )
    assert "failed" not in compact["raw:line:6"]["usage_actions"]
    assert compact["raw:line:8"]["async_transport_state"] == "terminal"
    assert compact["raw:line:8"]["result_status"] == "succeeded"
    assert compact["raw:line:8"]["outcome"] == "succeeded"
    assert false_correlations == []
    assert async_diagnostics["accepted_wait_call_count"] == 3
    assert async_diagnostics["accepted_wait_result_count"] == 3
    assert async_diagnostics["completed_chain_count"] == 1


