def test_entity_usage_audit_probes_and_pages_session_candidate_window(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    segment_index = write_structured_tool_call_index(
        tmp_path,
        tool_name="abyss_machine",
        event_ids=list(range(1, 31)),
    )
    hits = [
        {
            "doc_id": f"event:session:001:{index:06d}",
            "session_id": "session",
            "session_label": "2026-06-27__001__usage-audit-pages",
            "session_date": "2026-06-27",
            "segment_id": "001",
            "event_id": f"{index:06d}",
            "event_type": "TOOL_CALL",
            "family": "tool_interaction",
            "phase": "act",
            "actor": "assistant",
            "action": "call_tool",
            "outcome": "requested",
            "conversation_act": "tool_call_request",
            "session_act": "tool_call",
            "usage_role": "usage",
            "route_signals": ["tool:abyss_machine"],
            "title": f"Tool call {index}",
            "refs": {
                "session": "session.manifest.json",
                "segment": "001.md",
                "segment_index": str(segment_index),
                "raw": f"raw:line:{index}",
            },
            "freshness": {"status": "fresh"},
        }
        for index in range(30, 0, -1)
    ]
    calls: list[dict[str, Any]] = []

    def fake_search_sessions(**kwargs: Any) -> dict[str, Any]:
        calls.append(dict(kwargs))
        before = str(kwargs.get("event_id_before") or "")
        candidates = [hit for hit in hits if not before or str(hit["event_id"]) < before]
        selected = candidates[: int(kwargs["limit"])]
        return {
            "ok": True,
            "result_count": len(selected),
            "results": selected,
            "diagnostics": [],
        }

    monkeypatch.setattr(module, "search_sessions", fake_search_sessions)
    monkeypatch.setattr(module, "search_usage_role_filter_supported", lambda *_args, **_kwargs: True)
    monkeypatch.setattr(module, "search_provider_status_fast", lambda **_kwargs: {})

    first = module.entity_usage_audit(
        aoa_root=tmp_path / ".aoa",
        anchor="abyss-machine",
        kind="tool",
        limit=2,
        per_route_limit=2,
        session="session",
    )

    assert calls[0]["limit"] == 13
    assert calls[0]["event_id_before"] is None
    assert first["truncated"] is True
    assert first["truncation"]["candidate_count_exhaustive"] is False
    assert first["truncation"]["candidate_event_count"] == 13
    assert first["truncation"]["selected_event_count"] == 2
    assert first["truncation"]["omitted_event_count"] == 11
    assert first["truncation"]["next_before_event_id"] == "000029"
    assert [event["event_id"] for event in first["usage_events"]] == ["000030", "000029"]

    calls.clear()
    second = module.entity_usage_audit(
        aoa_root=tmp_path / ".aoa",
        anchor="abyss-machine",
        kind="tool",
        limit=2,
        per_route_limit=2,
        session="session",
        before_event_id=first["truncation"]["next_before_event_id"],
    )

    assert calls[0]["event_id_before"] == "000029"
    assert [event["event_id"] for event in second["usage_events"]] == ["000028", "000027"]


def test_entity_usage_chain_marks_failed_candidate_queries_incomplete(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """A bounded query timeout must never be reported as an exhaustive zero."""

    def timed_out_search(**_kwargs: Any) -> dict[str, Any]:
        return {
            "ok": False,
            "result_count": 0,
            "results": [],
            "diagnostics": [
                "search_structured_query_timeout:8000ms",
                "sqlite_query_timeout:interrupted",
            ],
        }

    monkeypatch.setattr(module, "search_sessions", timed_out_search)
    monkeypatch.setattr(
        module,
        "search_usage_role_filter_supported",
        lambda *_args, **_kwargs: True,
    )
    monkeypatch.setattr(module, "search_provider_status_fast", lambda **_kwargs: {})

    audit = module.entity_usage_audit(
        aoa_root=tmp_path / ".aoa",
        anchor="exec_command",
        kind="tool",
        limit=6,
        per_route_limit=8,
        session="gold-session",
    )

    assert audit["ok"] is False
    assert audit["truncated"] is False
    assert audit["incomplete"] is True
    assert audit["truncation"]["status"] == "incomplete"
    assert audit["truncation"]["candidate_count_exhaustive"] is False
    assert (
        audit["truncation"]["candidate_count_basis"]
        == "incomplete_upstream_query"
    )
    assert audit["quality"]["upstream_query_failure_count"] > 0
    assert audit["quality"]["upstream_query_failure_diagnostics"] == [
        "search_structured_query_timeout:8000ms",
        "sqlite_query_timeout:interrupted",
    ]

    chain = module.entity_usage_chain(
        aoa_root=tmp_path / ".aoa",
        anchor="exec_command",
        kind="tool",
        limit=6,
        per_route_limit=8,
        session="gold-session",
    )

    assert chain["ok"] is False
    assert chain["truncated"] is False
    assert chain["incomplete"] is True
    assert chain["truncation"]["status"] == "incomplete"
    assert chain["truncation"]["candidate_count_exhaustive"] is False
    assert chain["quality"]["incomplete"] is True
    assert "upstream_candidate_window_incomplete" in chain["noise_flags"]


