def test_entity_usage_event_action_semantics_classifies_operational_actions() -> None:
    samples = {
        "called": {"event_type": "TOOL_CALL", "action": "call_tool", "role": "usage"},
        "read": {"event_type": "FILE_READ", "action": "read", "role": "usage"},
        "edited": {"event_type": "DIFF", "action": "mutate_workspace", "role": "usage"},
        "configured": {"event_type": "FILE_WRITE", "title": "Updated config.toml settings", "role": "usage"},
        "validated": {"event_type": "COMMAND", "title": "python3 validate_session_memory_mcp.py", "role": "usage"},
        "failed": {"event_type": "ERROR", "outcome": "failed", "role": "result"},
        "repaired": {"event_type": "COMMAND", "title": "repair stale index refs", "role": "usage"},
    }

    for expected, event in samples.items():
        assert expected in module.entity_usage_event_action_semantics(event)

    read_only_result = {
        "event_type": "TOOL_OUTPUT",
        "role": "result",
        "action": "return_output",
        "outcome": "observed",
        "title": "Tool output: call-read-only-search",
        "snippet": '{"config_path":"/workspace/config/decision-summary.json","count":0}',
        "route_signals": [
            "mutation_surface:config",
            "authority_surface:source",
            "route_next_action:repair",
        ],
    }
    assert module.entity_usage_event_action_semantics(read_only_result) == ["observed"]
    referenced_memory_query = {
        "event_type": "COMMAND",
        "role": "context",
        "action": "run_command",
        "session_act": "memory_read",
        "execution_entity_usage_admission": "inspection_or_reference_not_invocation",
    }
    assert module.entity_usage_event_action_semantics(referenced_memory_query) == [
        "referenced"
    ]


def test_entity_usage_action_diverse_selection_preserves_usage_and_surfaces_read() -> None:
    """Regression derived from the raw-first 20260717 validator density review."""

    def pair(event_id: str, role: str, **fields: Any) -> tuple[dict[str, Any], dict[str, Any], int]:
        event = {"event_id": event_id, "role": role, **fields}
        return ({"doc_id": f"event:{event_id}"}, event, int(event_id))

    ranked_pairs = [
        pair("1", "usage", event_type="COMMAND"),
        pair("2", "usage", event_type="COMMAND"),
        pair("3", "context", event_type="COMMAND_OUTPUT"),
        pair("4", "context", event_type="TOOL_OUTPUT"),
        pair(
            "5",
            "context",
            event_type="COMMAND",
            action="run_command",
            session_act="memory_read",
            execution_entity_usage_admission="inspection_or_reference_not_invocation",
        ),
        pair(
            "6",
            "context",
            event_type="FILE_READ",
            action="read",
            session_act="memory_read",
            execution_entity_usage_admission="inspection_or_reference_not_invocation",
        ),
    ]

    selected, quality = module.entity_usage_action_diverse_selection(
        ranked_pairs,
        normalized_kind="validator",
        limit=4,
    )

    assert [event["event_id"] for _hit, event, _index in selected] == [
        "1",
        "2",
        "3",
        "6",
    ]
    assert quality == {
        "policy": "preserve_core_roles_then_sample_execution_inspection",
        "eligible": True,
        "applied": True,
        "read_sample_present": True,
        "selected_event_id": "6",
        "replaced_event_id": "4",
    }
    assert sum(event["role"] == "usage" for _hit, event, _index in selected) == 2

    all_usage, all_usage_quality = module.entity_usage_action_diverse_selection(
        ranked_pairs[:2],
        normalized_kind="validator",
        limit=2,
    )
    assert all_usage == ranked_pairs[:2]
    assert all_usage_quality["applied"] is False
    assert all_usage_quality["read_sample_present"] is False


def test_live_scenario_usage_chain_audit_tracks_action_semantics(tmp_path: Path, monkeypatch: Any) -> None:
    def fake_entity_usage_chain(**kwargs: Any) -> dict[str, Any]:
        anchor = str(kwargs["anchor"])
        if anchor == "missing-action":
            actions = {"called": 1, "used": 1}
            ok = True
        else:
            actions = {"called": 1, "read": 1, "used": 1, "validated": 1, "observed": 1}
            ok = True
        return {
            "ok": ok,
            "kind": kwargs["kind"],
            "requested_kind": kwargs["kind"],
            "counts": {
                "event_count": 3,
                "usage_event_count": 1,
                "result_event_count": 1,
                "outcome_event_count": 0,
                "consequence_event_count": 1,
            },
            "usage_action_counts": actions,
            "primary_usage_action_counts": {"called": 1, "observed": 1},
            "quality": {
                "skipped_graph_rag_packet": True,
                "skipped_graph_neighborhood": True,
                "skipped_raw_preview_neighborhood": True,
            },
            "evidence_refs": [{"kind": "raw_line", "value": f"raw:{anchor}:1"}],
            "first_ref": {"raw": f"raw:{anchor}:1"},
            "diagnostics": [],
        }

    monkeypatch.setattr(module, "entity_usage_chain", fake_entity_usage_chain)

    audit = module.live_scenario_usage_chain_audit(
        aoa_root=tmp_path / ".aoa",
        probes=[
            {
                "name": "happy",
                "anchor": "aoa-session-memory-mcp",
                "kind": "mcp",
                "required_usage_actions": ["called", "read", "used", "validated", "observed"],
            },
            {
                "name": "missing",
                "anchor": "missing-action",
                "kind": "tool",
                "required_usage_actions": ["validated"],
            },
        ],
    )

    assert audit["ok"] is False
    assert audit["quality"]["sample_count"] == 2
    assert audit["quality"]["failed_count"] == 1
    assert audit["quality"]["usage_action_counts"]["called"] == 2
    assert audit["samples"][1]["quality_flags"] == ["usage_chain_probe_missing_action:validated"]


def test_live_scenario_usage_chain_audit_scopes_foreign_correlation_to_source_edge(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    usage_a = {
        "doc_id": "event:session-a:000001",
        "event_id": "000001",
        "session_id": "session-a",
        "correlation_id": "call-a",
    }
    usage_b = {
        "doc_id": "event:session-a:000002",
        "event_id": "000002",
        "session_id": "session-a",
        "correlation_id": "call-b",
    }
    result_a = {
        "doc_id": "event:session-a:000003",
        "event_id": "000003",
        "session_id": "session-a",
        "correlation_id": "call-a",
    }

    def payload_with_rejected_source(source: dict[str, Any]) -> dict[str, Any]:
        return {
            "ok": True,
            "kind": "mcp",
            "requested_kind": "mcp",
            "counts": {
                "event_count": 3,
                "usage_event_count": 2,
                "result_event_count": 1,
                "outcome_event_count": 0,
                "consequence_event_count": 0,
            },
            "usage_chain": {
                "chains": [
                    {
                        "usage_event": usage_a,
                        "result_or_consequence_events": [result_a],
                    },
                    {
                        "usage_event": usage_b,
                        "result_or_consequence_events": [],
                    },
                ],
                "false_correlation_events": [
                    {
                        **result_a,
                        "source_doc_id": source["doc_id"],
                        "source_correlation_id": source["correlation_id"],
                        "rejected_correlation_id": result_a["correlation_id"],
                        "refs": {
                            "raw": "raw:line:3",
                            "segment": "000.md#event-000003",
                        },
                    }
                ],
            },
            "usage_action_counts": {"called": 2, "used": 2, "observed": 1},
            "primary_usage_action_counts": {"called": 2, "observed": 1},
            "quality": {
                "skipped_graph_rag_packet": True,
                "skipped_graph_neighborhood": True,
                "skipped_raw_preview_neighborhood": True,
            },
            "evidence_refs": [
                {"kind": "raw_line", "value": "raw:line:1"},
                {"kind": "segment_markdown", "value": "000.md#event-000001"},
            ],
            "first_ref": {"raw": "raw:line:1", "segment": "000.md#event-000001"},
            "diagnostics": [],
        }

    monkeypatch.setattr(
        module,
        "entity_usage_chain",
        lambda **kwargs: payload_with_rejected_source(usage_b),
    )
    parallel = module.live_scenario_usage_chain_audit(
        aoa_root=tmp_path / ".aoa",
        probes=[
            {
                "name": "parallel",
                "anchor": "aoa-session-memory-mcp",
                "kind": "mcp",
                "required_usage_actions": ["called", "used", "observed"],
            }
        ],
    )

    assert parallel["ok"] is True
    assert parallel["quality"]["foreign_correlation_consequence_violation_count"] == 0

    monkeypatch.setattr(
        module,
        "entity_usage_chain",
        lambda **kwargs: payload_with_rejected_source(usage_a),
    )
    leaked = module.live_scenario_usage_chain_audit(
        aoa_root=tmp_path / ".aoa",
        probes=[
            {
                "name": "leaked",
                "anchor": "aoa-session-memory-mcp",
                "kind": "mcp",
                "required_usage_actions": ["called", "used", "observed"],
            }
        ],
    )

    assert leaked["ok"] is False
    assert leaked["samples"][0]["quality_flags"] == [
        "usage_chain_probe_foreign_correlation_in_consequences:000003"
    ]


