def test_graph_bridge_does_not_accept_fuzzy_path_as_explicit_typed_target(
    tmp_path: Path, monkeypatch: Any
) -> None:
    aoa_root = tmp_path / ".aoa"
    aoa_root.mkdir(parents=True)
    source_anchor = "sample_tool"
    target_anchor = "sample_surface"
    source_node_id = module.graph_route_node_id("tool", source_anchor)
    session_node_id = "session:sample-session"
    fuzzy_target_node_id = module.graph_route_node_id(
        "path", "schemas_sample_surface_schema_json"
    )

    source_ref = {
        "event_id": "000010",
        "session_id": "sample-session",
        "segment_id": "000",
        "refs": {
            "raw": "raw:line:10",
            "segment": "sessions/sample-session/segments/000.md",
            "session": "sessions/sample-session/session.manifest.json",
        },
    }
    target_candidate_ref = {
        "event_id": "000020",
        "session_id": "sample-session",
        "segment_id": "000",
        "refs": {
            "raw": "raw:line:20",
            "segment": "sessions/sample-session/segments/000.md",
            "session": "sessions/sample-session/session.manifest.json",
        },
    }
    unrelated_neighbor_ref = {
        "event_id": "000030",
        "session_id": "unrelated-session",
        "segment_id": "000",
        "refs": {
            "raw": "raw:line:30",
            "segment": "sessions/unrelated-session/segments/000.md",
            "session": "sessions/unrelated-session/session.manifest.json",
        },
    }
    source_event_id = "event:sample-session:000:000010"
    target_candidate_event_id = "event:sample-session:000:000020"
    source_packet = {
        "ok": True,
        "nodes": [
            {"id": source_node_id, "type": "tool", "route_key": source_anchor},
            {"id": session_node_id, "type": "session"},
            {
                "id": source_event_id,
                "type": "event",
                "event_id": "000010",
                "session_id": "sample-session",
                "segment_id": "000",
                "line": 10,
                "timestamp": "2026-07-16T00:00:10Z",
                "evidence_refs": [source_ref],
            },
        ],
        "edges": [
            {
                "id": "edge:source-session",
                "type": "session_has_route_signal",
                "source": source_node_id,
                "target": session_node_id,
            }
        ],
        "resolved": {
            "anchor": source_anchor,
            "kind": "tool",
            "start_node_ids": [source_node_id],
            "resolver_strategy": "exact_route_node",
        },
        "evidence_refs": [source_ref, unrelated_neighbor_ref],
        "freshness": {"status": "bounded_current", "needs_maintenance": False},
        "diagnostics": [],
    }
    target_packet = {
        "ok": True,
        "nodes": [
            {"id": session_node_id, "type": "session"},
            {
                "id": fuzzy_target_node_id,
                "type": "path",
                "route_key": "schemas_sample_surface_schema_json",
            },
            {
                "id": target_candidate_event_id,
                "type": "event",
                "event_id": "000020",
                "session_id": "sample-session",
                "segment_id": "000",
                "line": 20,
                "timestamp": "2026-07-16T00:00:20Z",
                "evidence_refs": [target_candidate_ref],
            },
        ],
        "edges": [
            {
                "id": "edge:session-fuzzy-path",
                "type": "session_has_route_signal",
                "source": session_node_id,
                "target": fuzzy_target_node_id,
            },
            {
                "id": "edge:fuzzy-path-event",
                "type": "mentions_route_signal",
                "source": target_candidate_event_id,
                "target": fuzzy_target_node_id,
            },
        ],
        "resolved": {
            "anchor": target_anchor,
            "kind": "entity",
            "start_node_ids": [fuzzy_target_node_id],
            "resolver_strategy": "fuzzy_alias_candidates",
        },
        "evidence_refs": [target_candidate_ref],
        "freshness": {"status": "bounded_current", "needs_maintenance": False},
        "diagnostics": [],
    }

    monkeypatch.setattr(
        module,
        "graph_neighborhood",
        lambda **kwargs: source_packet
        if kwargs["anchor"] == source_anchor
        else target_packet,
    )
    monkeypatch.setattr(
        module,
        "graph_freshness",
        lambda *_args, **_kwargs: {
            "status": "bounded_current",
            "graph_source": "synthetic_owner_neutral_regression",
            "needs_maintenance": False,
        },
    )

    bridge = module.graph_bridge(
        aoa_root=aoa_root,
        source_anchor=source_anchor,
        target_anchor=target_anchor,
        source_kind="tool",
        target_kind="entity",
        limit=4,
        max_depth=4,
    )

    assert bridge["bridge"]["path_found"] is False
    assert bridge["bridge"]["nodes"] == []
    assert bridge["normalized_entities"]["source"]["resolution_status"] == "exact"
    assert bridge["normalized_entities"]["target"]["resolution_status"] == "candidate_only"
    assert bridge["usage_chain"]["target_event_count"] == 0
    assert bridge["candidate_context"]["target_event_count"] == 1
    assert bridge["candidate_context"]["target_node_ids"] == [fuzzy_target_node_id]
    assert bridge["candidate_context"]["target_evidence_refs"][0]["refs"]["raw"] == "raw:line:20"
    assert {
        ref.get("refs", {}).get("raw")
        for ref in bridge["evidence_refs"]
        if isinstance(ref, dict)
    } == {"raw:line:10"}
    assert "typed_target_requires_exact_resolution" in bridge["noise_flags"]


def test_graph_bridge_rejects_exact_typed_path_built_only_from_session_route_rollups(
    tmp_path: Path, monkeypatch: Any
) -> None:
    aoa_root = tmp_path / ".aoa"
    aoa_root.mkdir(parents=True)
    source_anchor = "source_packet_tool"
