    bridge = module.graph_bridge(
        aoa_root=aoa_root,
        source_anchor=source_anchor,
        target_anchor=target_anchor,
        source_kind="tool",
        target_kind="tool",
        limit=4,
        max_depth=4,
    )

    assert bridge["bridge"]["path_found"] is False
    assert bridge["bridge"]["nodes"] == []
    assert bridge["bridge"]["edges"] == []
    assert "bridge_path_rejected_discovery_only" in bridge["noise_flags"]
    assert bridge["candidate_context"]["bridge_path"]["path_found"] is True
    assert bridge["candidate_context"]["bridge_path"]["status"] == "rejected_discovery_only"
    assert {edge["type"] for edge in bridge["candidate_context"]["bridge_path"]["edges"]} == {
        "session_has_route_signal"
    }

    admitted_dependency = module.graph_bridge_path_admission(
        [{"type": "depends_on", "source": source_node_id, "target": target_node_id}]
    )
    structural_only = module.graph_bridge_path_admission(
        [{"type": "has_event", "source": session_node_id, "target": source_node_id}]
    )
    assert admitted_dependency["status"] == "admitted_typed_relation"
    assert admitted_dependency["admitted"] is True
    assert structural_only["status"] == "rejected_structural_only"
    assert structural_only["admitted"] is False


