def test_graph_freshness_separates_scoped_current_evidence_from_global_stale(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    source_key = module.graph_source_key("segment", "scope-session", "007")
    source_sha = "scope-source-sha"
    event_node = {
        "id": "event:scope-session:007:000042",
        "type": "event",
        "title": "Scoped current event",
        "session_id": "scope-session",
        "segment_id": "007",
        "event_id": "000042",
        "refs": {
            "raw": "raw:line:42",
            "segment": "007__compaction-to-compaction.md#event-000042",
            "session": "sessions/scope-session/session.manifest.json",
        },
    }
    contribution = {
        "source": {
            "source_key": source_key,
            "source_type": "segment",
            "session_id": "scope-session",
            "session_label": "2026-07-16__001__scope-session",
            "segment_id": "007",
            "source_path": str(aoa_root / "sessions" / "scope-session" / "segments" / "007.index.json"),
            "source_paths": [],
            "source_sha": source_sha,
            "source_mtime": 1.0,
            "graph_schema_version": module.GRAPH_SCHEMA_VERSION,
            "graph_store_schema_version": module.GRAPH_STORE_SCHEMA_VERSION,
            "graph_event_route_signal_edge_policy": module.GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
            "route_signal_classifier_version": module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
        },
        "nodes": [event_node],
        "edges": [],
    }
    store = module.GraphSqliteStore(aoa_root, reset=True)
    store.replace_source(contribution)
    store.conn.commit()
    store.close()
    module.write_graph_source_state_ledger(
        aoa_root,
        {
            "sources": {
                source_key: {
                    "source_key": source_key,
                    "status": "clean",
                    "source_sha": source_sha,
                    "last_checked": "2026-07-16T14:32:33Z",
                }
            }
        },
    )

    freshness = module.graph_freshness(
        aoa_root,
        {
            "source": "sqlite_graph_store_direct_timeline",
            "generated_at": "2026-07-16T14:32:32Z",
        },
        scope_nodes=[event_node],
        scope_edges=[],
    )

    assert freshness["status"] == "graph_store_stale"
    assert freshness["scope_status"] == "scope_current"
    assert freshness["scope_source_count"] == 1
    assert freshness["scope_current_source_count"] == 1
    assert freshness["scope_stale_source_count"] == 0
    assert freshness["global_recall_status"] == "partial_stale"
    assert freshness["scope_sources_sample"][0]["source_key"] == source_key
    assert freshness["scope_sources_sample"][0]["status"] == "current"

    ledger = module.read_graph_source_state_ledger(aoa_root)
    ledger["sources"][source_key]["status"] = "dirty"
    module.write_graph_source_state_ledger(aoa_root, ledger)
    stale = module.graph_freshness(
        aoa_root,
        {
            "source": "sqlite_graph_store_direct_timeline",
            "generated_at": "2026-07-16T14:32:32Z",
        },
        scope_nodes=[event_node],
        scope_edges=[],
    )

    assert stale["status"] == "graph_store_stale"
    assert stale["scope_status"] == "scope_stale"
    assert stale["scope_current_source_count"] == 0
    assert stale["scope_stale_source_count"] == 1


def test_storage_maintenance_checkpoints_sqlite_wal(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    search_path = module.search_db_path(aoa_root)
    graph_path = module.graph_paths(aoa_root)["store"]

    def open_wal_db(path: Path) -> sqlite3.Connection:
        path.parent.mkdir(parents=True, exist_ok=True)
        conn = sqlite3.connect(str(path))
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA wal_autocheckpoint=0")
        conn.execute("CREATE TABLE payloads(value TEXT)")
        conn.executemany("INSERT INTO payloads(value) VALUES (?)", [("x" * 1000,) for _ in range(1000)])
        conn.commit()
        assert Path(str(path) + "-wal").exists()
        assert Path(str(path) + "-wal").stat().st_size > 0
        return conn

    search_conn = open_wal_db(search_path)
    graph_conn = open_wal_db(graph_path)
    try:
        payload = module.storage_maintenance(aoa_root=aoa_root, write_report=True)
        assert search_conn.execute("SELECT COUNT(*) FROM payloads").fetchone()[0] == 1000
        assert graph_conn.execute("SELECT COUNT(*) FROM payloads").fetchone()[0] == 1000
    finally:
        search_conn.close()
        graph_conn.close()

    assert payload["artifact_type"] == "session_memory_storage_maintenance"
    assert payload["ok"] is True
    assert payload["mutates"] is True
    assert payload["status"] == "checkpointed"
    assert payload["reclaimed_bytes"] > 0
    assert payload["actions"]["sqlite_wal_checkpoint_truncate"]["search_store"]["status"] == "checkpointed"
    assert payload["actions"]["sqlite_wal_checkpoint_truncate"]["graph_store"]["status"] == "checkpointed"
    assert module.path_total_size(Path(str(search_path) + "-wal")) == 0
    assert module.path_total_size(Path(str(graph_path) + "-wal")) == 0
    assert Path(payload["report_json"]).exists()
    assert Path(payload["report_markdown"]).exists()


def test_maintenance_cleanup_clears_stale_active_job_and_orphaned_graph_tmp(tmp_path: Path, monkeypatch: Any) -> None:
    aoa_root = tmp_path / ".aoa"
    graph_root = aoa_root / module.GRAPH_ROOT
    graph_root.mkdir(parents=True)
    tmp_store = graph_root / ".graph.sqlite3.987654.rebuild.tmp"
    tmp_wal = Path(f"{tmp_store}-wal")
    tmp_journal = Path(f"{tmp_store}-journal")
    tmp_store.write_bytes(b"x" * 1024)
    tmp_wal.write_bytes(b"y" * 512)
    tmp_journal.write_bytes(b"j" * 256)
    owner = {
        **module.maintenance_owner_packet(
            aoa_root=aoa_root,
            owner_job="graph-build",
            mode="manual-bulk",
            target="all",
            reason="operator_requested",
            touched_surfaces=["graph"],
            budget_seconds=5400,
        ),
        "pid": 987654,
    }
    module.write_maintenance_coordinator_active(aoa_root, owner)
    monkeypatch.setattr(module, "process_is_alive", lambda pid: False)

    dry_run = module.maintenance_cleanup(aoa_root=aoa_root, apply=False)

    assert dry_run["status"] == "cleanup_needed"
    assert dry_run["mutates"] is False
    assert dry_run["stale_active_job"] is True
    assert dry_run["graph_rebuild_temps"]["orphaned_count"] == 1
    assert "orphaned_graph_store_rebuild_tmp" in dry_run["diagnostics"]
    assert tmp_store.exists()
    assert tmp_wal.exists()
    assert tmp_journal.exists()

    applied = module.maintenance_cleanup(aoa_root=aoa_root, apply=True, write_report=True)
    state = module.read_maintenance_coordinator_state(aoa_root)

    assert applied["ok"] is True
    assert applied["status"] == "applied"
    assert applied["mutates"] is True
    assert applied["action_counts"]["stale_active_job_cleared"] == 1
    assert applied["action_counts"]["graph_rebuild_tmp_removed"] == 1
    assert applied["removed_bytes"] == 1792
    assert not tmp_store.exists()
    assert not tmp_wal.exists()
    assert not tmp_journal.exists()
    assert state["active_job"] == {}
    assert state["last_stale_job"]["owner_job"] == "graph-build"
    assert state["last_event"]["status"] == "stale_active_job_cleared"
    assert Path(applied["report_json"]).exists()
    assert Path(applied["report_markdown"]).exists()


