def test_graph_store_rebuild_refreshes_duplicate_aggregate_evidence(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    shared_node_id = module.graph_route_node_id("entity", "shared_graph_anchor")
    shared_edge_id = module.graph_edge_id("session:first", shared_node_id, "mentions_route_signal")

    def contribution(source_key: str, session_id: str, raw_ref: str, *, title: str = "") -> dict[str, Any]:
        refs = {"raw": raw_ref, "session": f"sessions/{session_id}/session.manifest.json"}
        node = {
            "id": shared_node_id,
            "type": "route_entity",
            "route_layer": "entity",
            "route_key": "shared_graph_anchor",
            "route_signal": "entity:shared_graph_anchor",
            "evidence_refs": [{"session_id": session_id, "refs": refs}],
        }
        if title:
            node["title"] = title
        return {
            "source": {
                "source_key": source_key,
                "source_type": "segment",
                "session_id": session_id,
                "session_label": session_id,
                "segment_id": "000",
                "source_path": f"sessions/{session_id}/segments/000.index.json",
                "source_paths": [f"sessions/{session_id}/segments/000.index.json"],
                "source_sha": f"sha-{session_id}",
                "source_mtime": 1,
                "graph_schema_version": module.GRAPH_SCHEMA_VERSION,
                "graph_store_schema_version": module.GRAPH_STORE_SCHEMA_VERSION,
                "route_signal_classifier_version": module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
            },
            "nodes": [node],
            "edges": [
                {
                    "id": shared_edge_id,
                    "source": "session:first",
                    "target": shared_node_id,
                    "type": "mentions_route_signal",
                    "evidence_refs": [{"session_id": session_id, "refs": refs}],
                }
            ],
        }

    store = module.GraphSqliteStore(aoa_root, reset=True)
    try:
        rebuilt = store.rebuild(
            [
                contribution("segment:first:000", "first", "raw:line:1"),
                contribution("segment:second:000", "second", "raw:line:2", title="second anchor title"),
            ]
        )
        node_row = store.conn.execute("SELECT payload_json, count FROM nodes WHERE id = ?", (shared_node_id,)).fetchone()
        edge_row = store.conn.execute("SELECT payload_json, count FROM edges WHERE id = ?", (shared_edge_id,)).fetchone()
        node_contrib_row = store.conn.execute(
            "SELECT node_id, node_type, payload_json FROM node_contribs WHERE node_id = ? LIMIT 1",
            (shared_node_id,),
        ).fetchone()
        edge_contrib_row = store.conn.execute(
            "SELECT edge_id, edge_type, source_node, target_node, payload_json FROM edge_contribs WHERE edge_id = ? LIMIT 1",
            (shared_edge_id,),
        ).fetchone()
        assert node_row is not None
        assert edge_row is not None
        assert node_contrib_row is not None
        assert edge_contrib_row is not None
        stored_node = json.loads(str(node_row["payload_json"]))
        stored_edge = json.loads(str(edge_row["payload_json"]))
        node_contrib = json.loads(str(node_contrib_row["payload_json"]))
        edge_contrib = json.loads(str(edge_contrib_row["payload_json"]))
        hydrated_node = next(payload for payload in store.iter_payloads("nodes") if payload["id"] == shared_node_id)
        hydrated_edge = next(payload for payload in store.iter_payloads("edges") if payload["id"] == shared_edge_id)
    finally:
        store.close()

    assert rebuilt["duplicate_node_refresh"]["requested_count"] == 1
    assert rebuilt["duplicate_edge_refresh"]["requested_count"] == 1
    assert int(node_row["count"]) == 2
    assert int(edge_row["count"]) == 2
    assert stored_node["count"] == 2
    assert stored_node["evidence_ref_count"] == 2
    assert stored_node["title"] == "second anchor title"
    assert stored_edge["count"] == 2
    assert stored_edge["evidence_ref_count"] == 2
    assert node_contrib["contrib_payload_mode"] == module.GRAPH_STORE_CONTRIB_PAYLOAD_MODE
    assert edge_contrib["contrib_payload_mode"] == module.GRAPH_STORE_CONTRIB_PAYLOAD_MODE
    assert node_contrib_row["node_id"] == shared_node_id
    assert node_contrib_row["node_type"] == "route_entity"
    assert "id" not in node_contrib
    assert "type" not in node_contrib
    assert edge_contrib_row["edge_id"] == shared_edge_id
    assert edge_contrib_row["edge_type"] == "mentions_route_signal"
    assert edge_contrib_row["source_node"] == "session:first"
    assert edge_contrib_row["target_node"] == shared_node_id
    for key in ("id", "source", "target", "type"):
        assert key not in edge_contrib
    assert stored_node["id"] == shared_node_id
    assert stored_node["type"] == "route_entity"
    assert stored_edge["id"] == shared_edge_id
    assert stored_edge["source"] == "session:first"
    assert stored_edge["target"] == shared_node_id
    assert stored_edge["type"] == "mentions_route_signal"
    assert node_contrib["evidence_refs"][0]["refs"]["raw"] == "raw:line:1"
    assert edge_contrib["evidence_refs"][0]["refs"]["raw"] == "raw:line:1"
    assert "session_index" not in node_contrib["evidence_refs"][0]["refs"]
    assert "segment_index" not in edge_contrib["evidence_refs"][0]["refs"]
    assert {ref["session_id"] for ref in hydrated_node["evidence_refs"]} == {"first", "second"}
    assert {ref["session_id"] for ref in hydrated_edge["evidence_refs"]} == {"first", "second"}


def test_graph_store_creates_edge_type_composite_indexes(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    store = module.GraphSqliteStore(aoa_root, reset=True)
    try:
        rows = store.conn.execute("PRAGMA index_list('edges')").fetchall()
        index_names = {str(row["name"]) for row in rows}
    finally:
        store.close()

    assert "idx_edges_source_type" in index_names
    assert "idx_edges_target_type" in index_names


def test_graph_cooccurrence_uses_direct_store_for_dense_route_anchor(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    anchor_node = module.graph_route_node_id("tool", "exec_command")
    apply_node = module.graph_route_node_id("tool", "apply_patch")
    skill_node = module.graph_route_node_id("skill", "aoa_decision")
    event_one = "event:session-cooccurrence:000:000001"
    event_two = "event:session-cooccurrence:000:000002"

    def route_node(layer: str, key: str) -> dict[str, Any]:
        return {
            "id": module.graph_route_node_id(layer, key),
            "type": module.graph_route_node_type(layer, key),
            "label": f"{layer}:{key}",
            "route_layer": layer,
            "route_key": key,
            "route_signal": f"{layer}:{key}",
        }

    def event_node(event_id: str, raw_ref: str, title: str) -> dict[str, Any]:
        return {
            "id": event_id,
            "type": "event",
            "label": title,
            "title": title,
            "session_id": "session-cooccurrence",
            "session_label": "2026-07-07__001__cooccurrence",
            "segment_id": "000",
            "event_id": event_id.rsplit(":", 1)[-1],
            "refs": {
                "raw": raw_ref,
                "segment": "000__initial-to-latest.md",
                "session": "sessions/2026-07-07__001__cooccurrence/session.manifest.json",
            },
        }

    def mention_edge(event_id: str, route_id: str, raw_ref: str) -> dict[str, Any]:
        return {
            "id": module.graph_edge_id(event_id, route_id, "mentions_route_signal"),
            "source": event_id,
            "target": route_id,
            "type": "mentions_route_signal",
            "evidence_refs": [
                {
                    "session_id": "session-cooccurrence",
                    "segment_id": "000",
                    "refs": {"raw": raw_ref, "segment": "000__initial-to-latest.md"},
                }
            ],
        }

    contribution = {
        "source": {
            "source_key": "segment:session-cooccurrence:000",
            "source_type": "segment",
            "session_id": "session-cooccurrence",
            "session_label": "2026-07-07__001__cooccurrence",
            "segment_id": "000",
            "source_path": str(tmp_path / "000.index.json"),
            "source_paths": [str(tmp_path / "000.index.json")],
            "source_sha": "sha-cooccurrence",
            "source_mtime": 1.0,
            "graph_schema_version": module.GRAPH_SCHEMA_VERSION,
            "graph_store_schema_version": module.GRAPH_STORE_SCHEMA_VERSION,
            "route_signal_classifier_version": module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
        },
        "nodes": [
            route_node("tool", "exec_command"),
            route_node("tool", "apply_patch"),
            route_node("skill", "aoa_decision"),
            event_node(event_one, "raw:line:1", "Tool call: exec_command"),
            event_node(event_two, "raw:line:2", "Tool call: exec_command"),
        ],
        "edges": [
            mention_edge(event_one, anchor_node, "raw:line:1"),
            mention_edge(event_one, apply_node, "raw:line:1"),
            mention_edge(event_two, anchor_node, "raw:line:2"),
            mention_edge(event_two, skill_node, "raw:line:2"),
        ],
    }
    store = module.GraphSqliteStore(aoa_root, reset=True)
    try:
        store.rebuild([contribution])
    finally:
        store.close()

    payload = module.graph_cooccurrence(aoa_root=aoa_root, anchor="exec_command", kind="tool", limit=5)

    assert payload["ok"] is True
    assert payload["source"] == "sqlite_graph_store_direct_cooccurrence"
    assert payload["anchor_event_count"] == 2
    assert payload["cooccurrence_count"] == 2
    assert payload["quality"]["bounded_store_query"] is True
    assert payload["evidence_refs"]
    assert payload["evidence_refs"][0]["refs"]["raw"].startswith("raw:line:")
    cooccurring_ids = {item["node"]["id"] for item in payload["cooccurrences"]}
    assert apply_node in cooccurring_ids
    assert skill_node in cooccurring_ids
    assert anchor_node not in cooccurring_ids


def test_graph_cooccurrence_prefers_aggregate_store_with_raw_ref_hydration(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    session_id = "session-cooccurrence-aggregate"
    session_label = "2026-07-07__002__cooccurrence-aggregate"
    segment_id = "000"
    session_dir = aoa_root / module.SESSION_ROOT / session_id
    segment_dir = session_dir / "segments"
    segment_dir.mkdir(parents=True)
    manifest_path = session_dir / "session.manifest.json"
    segment_markdown = segment_dir / "000__initial-to-latest.md"
    segment_index_path = segment_dir / "000__initial-to-latest.index.json"
    anchor_node = module.graph_route_node_id("tool", "exec_command")
    apply_node = module.graph_route_node_id("tool", "apply_patch")
    skill_node = module.graph_route_node_id("skill", "aoa_decision")
    segment_node = f"segment:{session_id}:{segment_id}"

    def signal(layer: str, key: str) -> dict[str, str]:
        return {"layer": layer, "key": key}

    write_json(
        segment_index_path,
        {
            "segment_id": segment_id,
            "markdown": str(segment_markdown),
            "source_block": {"rel": "raw/blocks/000.jsonl"},
            "events": [
                {
                    "event_id": "000001",
                    "title": "Tool call: exec_command + apply_patch",
                    "raw_ref": "raw:line:10",
                    "md_anchor": f"{segment_markdown}#event-000001",
                    "facets": {
                        "route_signals": [
                            signal("tool", "exec_command"),
                            signal("tool", "apply_patch"),
                        ]
                    },
                },
                {
                    "event_id": "000002",
                    "title": "Tool call: exec_command after aoa_decision route",
                    "raw_ref": "raw:line:20",
                    "md_anchor": f"{segment_markdown}#event-000002",
                    "facets": {
                        "route_signals": [
                            signal("tool", "exec_command"),
                            signal("skill", "aoa_decision"),
                        ]
                    },
                },
            ],
        },
    )

    def evidence() -> list[dict[str, Any]]:
        return [
            {
                "session_id": session_id,
                "segment_id": segment_id,
                "refs": {
                    "session": str(manifest_path),
                    "segment": str(segment_markdown),
                    "segment_index": str(segment_index_path),
                },
            }
        ]

    def route_node(layer: str, key: str) -> dict[str, Any]:
        return {
            "id": module.graph_route_node_id(layer, key),
            "type": module.graph_route_node_type(layer, key),
            "label": f"{layer}:{key}",
            "route_layer": layer,
            "route_key": key,
            "route_signal": f"{layer}:{key}",
            "evidence_refs": evidence(),
        }

    def segment_route_edge(route_id: str, count: int) -> dict[str, Any]:
        return {
            "id": module.graph_edge_id(segment_node, route_id, "segment_has_route_signal"),
            "source": segment_node,
            "target": route_id,
            "type": "segment_has_route_signal",
            "session_id": session_id,
            "segment_id": segment_id,
            "count": count,
            "evidence_refs": evidence(),
        }

    contribution = {
        "source": {
            "source_key": f"segment:{session_id}:{segment_id}",
            "source_type": "segment",
            "session_id": session_id,
            "session_label": session_label,
            "segment_id": segment_id,
            "source_path": str(segment_index_path),
            "source_paths": [str(segment_index_path)],
            "source_sha": "sha-cooccurrence-aggregate",
            "source_mtime": 1.0,
            "graph_schema_version": module.GRAPH_SCHEMA_VERSION,
            "graph_store_schema_version": module.GRAPH_STORE_SCHEMA_VERSION,
            "graph_event_route_signal_edge_policy": module.GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
            "route_signal_classifier_version": module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
        },
        "nodes": [
            {
                "id": segment_node,
                "type": "segment",
                "label": f"{session_label} segment {segment_id}",
                "session_id": session_id,
                "session_label": session_label,
                "segment_id": segment_id,
                "evidence_refs": evidence(),
            },
            route_node("tool", "exec_command"),
            route_node("tool", "apply_patch"),
            route_node("skill", "aoa_decision"),
        ],
        "edges": [
            segment_route_edge(anchor_node, 2),
            segment_route_edge(apply_node, 1),
            segment_route_edge(skill_node, 1),
        ],
    }
    store = module.GraphSqliteStore(aoa_root, reset=True)
    try:
        store.rebuild([contribution])
        edge_types = {
            str(row["edge_type"])
            for row in store.conn.execute("SELECT DISTINCT edge_type FROM edges").fetchall()
        }
    finally:
        store.close()

    payload = module.graph_cooccurrence(aoa_root=aoa_root, anchor="exec_command", kind="tool", limit=5)

    assert "mentions_route_signal" not in edge_types
    assert payload["ok"] is True
    assert payload["source"] == "sqlite_graph_store_aggregate_cooccurrence"
    assert payload["cooccurrence_basis"] == "aggregate_segment_route_signal_edges_session_diversified"
    assert payload["context_selection_policy"] == module.GRAPH_COOCCURRENCE_CONTEXT_SELECTION_POLICY
    assert payload["cooccurrence_ranking_policy"] == module.GRAPH_COOCCURRENCE_RANKING_POLICY
    assert payload["anchor_context_count"] == 1
    assert payload["anchor_context_population_count"] == 1
    assert payload["anchor_context_session_count"] == 1
    assert payload["quality"]["uses_session_has_route_signal_edges"] is False
    assert payload["anchor_event_count_basis"] == "aggregate_route_contexts"
    assert payload["quality"]["aggregate_route_signal_query"] is True
    assert payload["quality"]["uses_event_mentions_route_signal_edges"] is False
    assert payload["quality"]["raw_ref_count"] >= 1
    assert payload["quality"]["segment_ref_count"] >= 1
    assert any(str(ref["refs"].get("raw", "")).startswith("raw:line:") for ref in payload["evidence_refs"])
    cooccurring_ids = {item["node"]["id"] for item in payload["cooccurrences"]}
    assert apply_node in cooccurring_ids
    assert skill_node in cooccurring_ids
    assert anchor_node not in cooccurring_ids


def test_graph_cooccurrence_aggregate_diversifies_sessions_under_same_budgets(tmp_path: Path) -> None:
    """Regression derived from the manual 2026071601 dense-anchor A/B wave."""
    aoa_root = tmp_path / ".aoa"
    anchor_node = module.graph_route_node_id("tool", "exec_command")
    cluster_noise_node = module.graph_route_node_id("script", "cluster_only_noise")
    diversified_node = module.graph_route_node_id("tool", "cross_session_neighbor")
    nodes: list[dict[str, Any]] = [
        {"id": anchor_node, "type": "tool", "route_layer": "tool", "route_key": "exec_command"},
        {"id": cluster_noise_node, "type": "script", "route_layer": "script", "route_key": "cluster_only_noise"},
        {"id": diversified_node, "type": "tool", "route_layer": "tool", "route_key": "cross_session_neighbor"},
    ]
    edges: list[dict[str, Any]] = []

    def add_context(session_id: str, segment_id: str, neighbor_node: str, neighbor_count: int) -> None:
        segment_node = f"segment:{session_id}:{segment_id}"
        refs = {
            "session": f"sessions/{session_id}/session.manifest.json",
            "segment": f"sessions/{session_id}/segments/{segment_id}.md",
        }
        evidence_refs = [{"session_id": session_id, "segment_id": segment_id, "refs": refs}]
        nodes.append(
            {
                "id": segment_node,
                "type": "segment",
                "session_id": session_id,
                "segment_id": segment_id,
                "evidence_refs": evidence_refs,
            }
        )
        for target, count in ((anchor_node, 1), (neighbor_node, neighbor_count)):
            edges.append(
                {
                    "id": module.graph_edge_id(segment_node, target, "segment_has_route_signal"),
                    "source": segment_node,
                    "target": target,
                    "type": "segment_has_route_signal",
                    "count": count,
                    "session_id": session_id,
                    "segment_id": segment_id,
                    "evidence_refs": evidence_refs,
                }
            )

    for index in range(60):
        add_context("000-cluster-session", f"{index:03d}", cluster_noise_node, 100)
    for index in range(60):
        add_context(f"{index + 100:03d}-diverse-session", "000", diversified_node, 1)

    contribution = {
        "source": {
            "source_key": "segment:cooccurrence-diversity:000",
            "source_type": "segment",
            "session_id": "cooccurrence-diversity",
            "session_label": "2026-07-16__001__cooccurrence-diversity",
            "segment_id": "000",
            "source_path": str(tmp_path / "cooccurrence-diversity.index.json"),
            "source_paths": [str(tmp_path / "cooccurrence-diversity.index.json")],
            "source_sha": "sha-cooccurrence-diversity",
            "source_mtime": 1.0,
            "graph_schema_version": module.GRAPH_SCHEMA_VERSION,
            "graph_store_schema_version": module.GRAPH_STORE_SCHEMA_VERSION,
            "graph_event_route_signal_edge_policy": module.GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
            "route_signal_classifier_version": module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
        },
        "nodes": nodes,
        "edges": edges,
    }
    store = module.GraphSqliteStore(aoa_root, reset=True)
    try:
        store.rebuild([contribution])
        legacy_rows = store.conn.execute(
            """
            SELECT source_node
            FROM edges INDEXED BY idx_edges_target_type
            WHERE target_node = ? AND edge_type = 'segment_has_route_signal'
            LIMIT 40
            """,
            (anchor_node,),
        ).fetchall()
    finally:
        store.close()
    legacy_sessions = {str(row["source_node"]).split(":", 2)[1] for row in legacy_rows}
    assert legacy_sessions == {"000-cluster-session"}

    payload = module.graph_cooccurrence_from_store_aggregate(
        aoa_root=aoa_root,
        anchor="exec_command",
        kind="tool",
        limit=2,
    )
    alias_payload = module.graph_cooccurrence_from_store_aggregate(
        aoa_root=aoa_root,
        anchor="exec-command",
        kind="tool",
        limit=2,
    )

    assert payload is not None
    assert alias_payload is not None
    assert payload["anchor_context_population_count"] == 120
    assert payload["anchor_context_count"] == 40
    assert payload["anchor_context_session_count"] == 40
    assert payload["anchor_context_max_session_share"] == 0.025
    assert payload["route_edge_sample_limit"] == 320
    assert payload["cooccurrences"][0]["node"]["id"] == diversified_node
    assert payload["cooccurrences"][0]["session_count"] >= 39
    assert all(item["node"]["id"] != cluster_noise_node for item in payload["cooccurrences"][:1])
    assert payload["resolved"]["start_node_ids"] == alias_payload["resolved"]["start_node_ids"]
    assert payload["cooccurrences"] == alias_payload["cooccurrences"]


def test_graph_cooccurrence_packet_diagnoses_truncated_empty_routes() -> None:
    anchor_node = module.graph_route_node_id("tool", "exec_command")
    event_node = {
        "id": "event:session:000:000001",
        "type": "event",
        "title": "Tool call: exec_command",
        "session_id": "session",
        "segment_id": "000",
        "event_id": "000001",
        "refs": {"raw": "raw:line:1", "segment": "000.md"},
    }
    payload = module.graph_cooccurrence_from_packet(
        aoa_root=Path("/tmp/nonexistent-aoa"),
        anchor="exec_command",
        kind="tool",
        packet={
            "nodes": [
                {"id": anchor_node, "type": "tool", "label": "tool:exec_command"},
                event_node,
            ],
            "edges": [
                {
                    "id": "edge:1",
                    "type": "mentions_route_signal",
                    "source": event_node["id"],
                    "target": anchor_node,
                }
            ],
            "resolved": {"start_node_ids": [anchor_node]},
            "truncated": True,
            "freshness": {"status": "graph_store_stale"},
        },
    )

    assert payload["ok"] is False
    assert payload["anchor_event_count"] == 1
    assert payload["cooccurrence_count"] == 0
    assert "graph_cooccurrence_no_route_neighbors_in_bounded_packet" in payload["diagnostics"]
    assert "graph_cooccurrence_bounded_packet_truncated_before_cooccurrence_routes" in payload["diagnostics"]
    assert "graph-neighborhood" in payload["next_route"]


def test_graph_source_fingerprint_tracks_contrib_payload_mode(tmp_path: Path, monkeypatch: Any) -> None:
    source_path = tmp_path / "000.index.json"
    source_path.write_text("{}\n", encoding="utf-8")

    first = module.graph_source_metadata(
        source_type="segment",
        session_id="fingerprint-mode",
        session_label="fingerprint-mode",
        segment_id="000",
        source_paths=[source_path],
    )
    monkeypatch.setattr(module, "GRAPH_STORE_CONTRIB_PAYLOAD_MODE", "fixture_other_payload_mode")
    second = module.graph_source_metadata(
        source_type="segment",
        session_id="fingerprint-mode",
        session_label="fingerprint-mode",
        segment_id="000",
        source_paths=[source_path],
    )

    assert first["source_sha"] != second["source_sha"]


def test_graph_cardinality_projection_refreshes_and_tracks_incremental_changes(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"

    def contribution(source_key: str, node_type: str, edge_type: str) -> dict[str, Any]:
        node_id = f"{source_key}:node"
        return {
            "source": {
                "source_key": source_key,
                "source_type": "segment",
                "session_id": "session-cardinality",
                "session_label": "2026-06-21__001__cardinality",
                "segment_id": "000",
                "source_path": str(tmp_path / f"{source_key}.json"),
                "source_paths": [str(tmp_path / f"{source_key}.json")],
                "source_sha": source_key,
                "source_mtime": 1.0,
                "graph_schema_version": module.GRAPH_SCHEMA_VERSION,
                "graph_store_schema_version": module.GRAPH_STORE_SCHEMA_VERSION,
                "route_signal_classifier_version": module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
            },
            "nodes": [
                {"id": node_id, "type": node_type, "label": node_type},
            ],
            "edges": [
                {
                    "id": f"{source_key}:edge",
                    "source": node_id,
                    "target": f"{source_key}:target",
                    "type": edge_type,
                    "label": edge_type,
                }
            ],
        }

    store = module.GraphSqliteStore(aoa_root, reset=True)
    try:
        rebuild = store.rebuild([contribution("source-one", "event", "mentions_route_signal")])
        assert rebuild["type_counts_projection"]["status"] == "current"
    finally:
        store.close()

    initial = module.graph_cardinality(aoa_root=aoa_root)
    assert initial["ok"] is True
    assert initial["projection"]["counts"]["node"]["event"] == 1
    assert initial["projection"]["counts"]["edge"]["mentions_route_signal"] == 1

    store = module.GraphSqliteStore(aoa_root)
    try:
        store.replace_sources([contribution("source-one", "task_episode", "has_event")])
        store.conn.commit()
    finally:
        store.close()

    updated = module.graph_cardinality(aoa_root=aoa_root)
    assert updated["ok"] is True
    assert "event" not in updated["projection"]["counts"]["node"]
    assert updated["projection"]["counts"]["node"]["task_episode"] == 1
    assert "mentions_route_signal" not in updated["projection"]["counts"]["edge"]
    assert updated["projection"]["counts"]["edge"]["has_event"] == 1


def test_graph_source_version_state_tracks_event_route_signal_policy_mismatch(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    contribution = {
        "source": {
            "source_key": "segment:policy-mismatch:000",
            "source_type": "segment",
            "session_id": "policy-mismatch",
            "session_label": "2026-06-21__001__policy-mismatch",
            "segment_id": "000",
            "source_path": str(tmp_path / "000.index.json"),
            "source_paths": [str(tmp_path / "000.index.json")],
            "source_sha": "sha-policy-mismatch",
            "source_mtime": 1.0,
            "graph_schema_version": module.GRAPH_SCHEMA_VERSION,
            "graph_store_schema_version": module.GRAPH_STORE_SCHEMA_VERSION,
            "graph_event_route_signal_edge_policy": module.GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
            "route_signal_classifier_version": module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
        },
        "nodes": [{"id": "event:policy-mismatch:000:000001", "type": "event"}],
        "edges": [],
    }

    store = module.GraphSqliteStore(aoa_root, reset=True)
    try:
        store.rebuild([contribution])
        current = store.source_version_state()
        assert current["status"] == "current"
        store.conn.execute("UPDATE graph_sources SET graph_event_route_signal_edge_policy = ''")
        dirty = store.source_version_state()
    finally:
        store.close()

    assert dirty["status"] == "dirty"
    assert dirty["reason_group_counts"]["graph_event_route_signal_edge_policy_mismatch"] == 1
    assert dirty["expected_versions"]["graph_event_route_signal_edge_policy"] == module.GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY
    assert dirty["observed_versions"]["graph_event_route_signal_edge_policy"] == [""]


def test_graph_raw_ref_prune_removes_generated_materialization_only(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    session_id = "session-raw-ref-prune"
