def test_index_maintenance_repair_limit_bounds_route_schema_drift(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    repo = workspace / "aoa-session-memory"
    repo.mkdir(parents=True)
    aoa_root = workspace / ".aoa"
    session_ids = ["route-batch-alpha", "route-batch-beta", "route-batch-gamma"]
    for index, session_id in enumerate(session_ids):
        transcript = tmp_path / f"rollout-2026-06-04T00-0{index}-00-{session_id}.jsonl"
        write_jsonl(
            transcript,
            [
                {"timestamp": f"2026-06-04T00:0{index}:00Z", "type": "session_meta", "payload": {"id": session_id, "cwd": str(repo)}},
                {"timestamp": f"2026-06-04T00:0{index}:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": f"Route schema batch {session_id}"}]}},
                {"timestamp": f"2026-06-04T00:0{index}:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Route schema baseline indexed."}]}},
            ],
        )
        module.handle_hook_event(
            "Stop",
            {
                "session_id": session_id,
                "transcript_path": str(transcript),
                "cwd": str(repo),
                "hook_event_name": "Stop",
            },
            workspace_root=workspace,
            aoa_root=aoa_root,
        )

    module.search_index_sessions(aoa_root=aoa_root, target="all")
    module.build_agent_atlas(aoa_root=aoa_root, target="all")
    for session_id in session_ids:
        record = module.resolve_session_record(aoa_root, session_id)
        session_index_path = module.session_dir_from_record(record) / module.SESSION_INDEX_JSON
        session_index = module.read_json(session_index_path, {})
        session_index["task_episode_schema_version"] = module.TASK_EPISODE_SCHEMA_VERSION - 1
        module.write_json(session_index_path, session_index)
    first_record = module.resolve_session_record(aoa_root, session_ids[0])
    first_manifest = module.read_json(
        module.session_dir_from_record(first_record) / "session.manifest.json",
        {},
    )
    first_raw = Path(str(first_manifest["raw"]["path"]))
    with first_raw.open("ab") as handle:
        handle.write(b" " * 16384)
    second_record = module.resolve_session_record(aoa_root, session_ids[1])
    second_manifest = module.read_json(
        module.session_dir_from_record(second_record) / "session.manifest.json",
        {},
    )
    route_max_raw_bytes = Path(str(second_manifest["raw"]["path"])).stat().st_size + 1024

    plan = module.maintain_indexes(
        aoa_root=aoa_root,
        target="all",
        repair_limit=1,
        route_max_raw_bytes=route_max_raw_bytes,
        repair_graph=False,
        repair_token_accounting=False,
    )
    actions = {action["id"]: action for action in plan["actions"]}

    assert plan["route_drift_count"] == 3
    assert plan["route_repair_candidate_count"] == 2
    assert plan["route_repair_session_count"] == 1
    assert plan["route_repair_remaining_count"] == 1
    assert plan["route_repair_limited"] is True
    assert plan["route_repair_deferred_count"] == 1
    assert plan["route_repair_deferred"][0]["session_id"] == session_ids[0]
    assert plan["route_repair_deferred"][0]["status"] == "deferred_heavy"
    assert plan["route_repair_sessions"][0]["session_id"] == session_ids[1]
    assert actions["reindex_route_indexes"]["selection_count"] == 1
    assert actions["reindex_route_indexes"]["dirty_count"] == 3
    assert actions["reindex_route_indexes"]["deferred_count"] == 1
    assert actions["reindex_route_indexes"]["selection_policy"] == "oldest_dirty_first"

    applied = module.maintain_indexes(
        aoa_root=aoa_root,
        target="all",
        repair_limit=1,
        route_max_raw_bytes=route_max_raw_bytes,
        repair_graph=False,
        repair_token_accounting=False,
        apply=True,
    )
    applied_actions = {action["id"]: action for action in applied["actions"]}

    assert applied_actions["reindex_route_indexes"]["status"] == "applied_partial", json.dumps(
        applied_actions["reindex_route_indexes"], ensure_ascii=False, indent=2
    )
    assert applied_actions["reindex_route_indexes"]["result"]["selected_count"] == 1
    route_changed_session_id = session_ids[1]
    assert applied_actions["reindex_route_indexes"]["result"]["completed_session_ids"] == [
        route_changed_session_id
    ]
    search_action = applied_actions["rebuild_search_index"]
    assert search_action["upstream_changed_session_ids"] == [route_changed_session_id]
    assert search_action["selected_priority_session_ids"] == [route_changed_session_id]
    assert search_action["result"]["completed_session_ids"] == [route_changed_session_id]
    episode_action = applied_actions["refresh_episode_semantic_projection"]
    assert episode_action["upstream_changed_session_ids"] == [route_changed_session_id]
    assert episode_action["covered_by_search_index_session_ids"] == [
        route_changed_session_id
    ]
    assert route_changed_session_id not in episode_action["deferred_priority_session_ids"]
    atlas_action = applied_actions["rebuild_agent_atlas"]
    assert atlas_action["upstream_changed_session_ids"] == [route_changed_session_id]
    assert atlas_action["selected_priority_session_ids"] == [route_changed_session_id]
    assert atlas_action["result"]["completed_session_ids"] == [route_changed_session_id]
    coherence = applied["route_projection_dependency_coherence"]
    assert coherence["status"] == "passed", json.dumps(coherence, ensure_ascii=False, indent=2)
    assert coherence["upstream_changed_session_ids"] == [route_changed_session_id]
    assert coherence["pending_session_ids"] == []
    for state_key in (
        "final_search_index",
        "final_atlas_index",
        "final_episode_semantic_projection",
    ):
        assert route_changed_session_id not in set(
            applied[state_key].get("dirty_session_ids", [])
        ), state_key
    remaining = module.maintain_indexes(
        aoa_root=aoa_root,
        target="all",
        repair_limit=1,
        route_max_raw_bytes=route_max_raw_bytes,
        repair_graph=False,
        repair_token_accounting=False,
    )
    assert remaining["route_drift_count"] == 2


def test_index_maintenance_keeps_query_demand_ahead_of_same_cycle_route_backlog(
    tmp_path: Path,
) -> None:
    workspace = tmp_path / "AbyssOS"
    repo = workspace / "aoa-session-memory"
    repo.mkdir(parents=True)
    aoa_root = workspace / ".aoa"
    route_session_ids = [
        "route-priority-alpha",
        "route-priority-beta",
        "route-priority-gamma",
    ]
    demanded_session_id = "query-demanded-projection"
    session_ids = [*route_session_ids, demanded_session_id]
    for index, session_id in enumerate(session_ids):
        transcript = tmp_path / f"rollout-2026-06-05T00-0{index}-00-{session_id}.jsonl"
        write_jsonl(
            transcript,
            [
                {
                    "timestamp": f"2026-06-05T00:0{index}:00Z",
                    "type": "session_meta",
                    "payload": {"id": session_id, "cwd": str(repo)},
                },
                {
                    "timestamp": f"2026-06-05T00:0{index}:01Z",
                    "type": "response_item",
                    "payload": {
                        "type": "message",
                        "role": "user",
                        "content": [
                            {
                                "type": "input_text",
                                "text": f"Projection priority case {session_id}",
                            }
                        ],
                    },
                },
                {
                    "timestamp": f"2026-06-05T00:0{index}:02Z",
                    "type": "response_item",
                    "payload": {
                        "type": "message",
                        "role": "assistant",
                        "content": [
                            {
                                "type": "output_text",
                                "text": "Projection priority baseline indexed.",
                            }
                        ],
                    },
                },
            ],
        )
        module.handle_hook_event(
            "Stop",
            {
                "session_id": session_id,
                "transcript_path": str(transcript),
                "cwd": str(repo),
                "hook_event_name": "Stop",
            },
            workspace_root=workspace,
            aoa_root=aoa_root,
        )

    module.search_index_sessions(aoa_root=aoa_root, target="all")
    module.build_agent_atlas(aoa_root=aoa_root, target="all")

    for session_id in route_session_ids:
        record = module.resolve_session_record(aoa_root, session_id)
        session_index_path = module.session_dir_from_record(record) / module.SESSION_INDEX_JSON
        session_index = module.read_json(session_index_path, {})
        session_index["task_episode_schema_version"] = module.TASK_EPISODE_SCHEMA_VERSION - 1
        module.write_json(session_index_path, session_index)

    demanded_record = module.resolve_session_record(aoa_root, demanded_session_id)
    demanded_manifest = module.read_json(
        module.session_dir_from_record(demanded_record) / "session.manifest.json",
        {},
    )
    demanded_segment_index_path = Path(str(demanded_manifest["segments"][0]["index"]))
    demanded_segment_index = module.read_json(demanded_segment_index_path, {})
    demanded_segment_index["search_projection_changed_after_baseline"] = True
    module.write_json(demanded_segment_index_path, demanded_segment_index)

    applied = module.maintain_indexes(
        aoa_root=aoa_root,
        target="all",
        repair_limit=3,
        search_repair_limit=3,
        search_max_cost_class="heavy",
        route_max_raw_bytes=1024 * 1024,
        repair_graph=False,
        repair_token_accounting=False,
        apply=True,
        query_demand={
            "status": "observed",
            "priority_session_ids": [demanded_session_id],
            "demand_counts": {demanded_session_id: 3},
            "diagnostics": [],
        },
    )
    actions = {action["id"]: action for action in applied["actions"]}
    search_action = actions["rebuild_search_index"]
    selection = search_action["selection"]

    assert selection["selected_session_ids"][0] == demanded_session_id
    assert demanded_session_id in search_action["result"]["completed_session_ids"]
    assert len(
        set(route_session_ids) & set(selection["deferred_priority_limited_session_ids"])
    ) == 1


def test_index_maintenance_refreshes_search_state_without_reindexing_when_documents_are_current(tmp_path: Path, monkeypatch: Any) -> None:
    workspace = tmp_path / "AbyssOS"
    repo = workspace / "aoa-session-memory"
    repo.mkdir(parents=True)
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-06-02T00-00-00-search-state.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-06-02T00:00:00Z", "type": "session_meta", "payload": {"id": "search-state-refresh", "cwd": str(repo)}},
            {"timestamp": "2026-06-02T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Refresh search state"}]}},
            {"timestamp": "2026-06-02T00:00:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Search state should not rebuild."}]}},
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "search-state-refresh",
            "transcript_path": str(transcript),
            "cwd": str(repo),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    module.search_index_sessions(aoa_root=aoa_root, target="all")
    record = module.resolve_session_record(aoa_root, "search-state-refresh")

    old_full_projection = module.session_projection_fingerprint(record, include_rendered_markdown=True)
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=False)
    module.upsert_search_session_state(
        conn,
        projection_state=old_full_projection,
        indexed_at=module.utc_now(),
        document_count=module.search_document_count_for_projection(conn, old_full_projection),
    )
    conn.execute(
        "UPDATE session_index_state SET projection_fingerprint_mode = ? WHERE session_id = ?",
        ("legacy_with_rendered_markdown_v0", "search-state-refresh"),
    )
    conn.commit()
    conn.close()

    def fail_per_projection_count(*_args: Any, **_kwargs: Any) -> int:
        raise AssertionError("refresh_search_projection_states should use bulk document counts")

    monkeypatch.setattr(module, "search_document_count_for_projection", fail_per_projection_count)

    plan = module.maintain_indexes(aoa_root=aoa_root, target="search-state-refresh", repair_graph=False)
    actions = {action["id"]: action for action in plan["actions"]}
    assert plan["search_dirty_session_count"] == 1
    assert plan["search_state_refresh_count"] == 1
    assert plan["search_reindex_session_count"] == 0
    assert actions["refresh_search_projection_state"]["needed"] is True
    assert "rebuild_search_index" not in actions

    applied = module.maintain_indexes(aoa_root=aoa_root, target="search-state-refresh", apply=True, repair_graph=False)
    applied_actions = {action["id"]: action for action in applied["actions"]}
    assert applied_actions["refresh_search_projection_state"]["status"] == "applied"
    assert applied_actions["refresh_search_projection_state"]["result"]["updated_count"] == 1
    assert "rebuild_search_index" not in applied_actions

    refreshed = module.maintain_indexes(aoa_root=aoa_root, target="search-state-refresh", repair_graph=False)
    assert refreshed["search_dirty_session_count"] == 0
    assert refreshed["final_search_index"]["status"] == "current"


def test_index_maintenance_refreshes_missing_operational_route_rollup(tmp_path: Path, monkeypatch: Any) -> None:
    aoa_root = tmp_path / ".aoa"
    session_dir = aoa_root / "sessions" / "2026-06-28__001__rollup-maintenance"
    session_dir.mkdir(parents=True)
    write_json(session_dir / "session.manifest.json", {"archive_status": "indexed"})
    record = {
        "session_id": "rollup-maintenance",
        "session_label": "2026-06-28__001__rollup-maintenance",
        "path": str(session_dir),
    }
    refreshed = {"value": False}

    def fake_rollup_status(*, aoa_root: Path, search_shards: dict[str, Any] | None = None) -> dict[str, Any]:
        if refreshed["value"]:
            return {
                "status": "current",
                "needs_refresh": False,
                "shard_count": 2,
                "route_rollup_row_count": 10,
                "candidate_route_posting_count": 25,
                "truth_status": "generated_search_route_rollup_projection_not_archive_truth",
            }
        return {
            "status": "missing",
            "needs_refresh": True,
            "shard_count": 2,
            "diagnostics": ["operational_route_rollup_missing"],
            "truth_status": "generated_search_route_rollup_projection_not_archive_truth",
        }

    def fake_refresh_rollup(**_kwargs: Any) -> dict[str, Any]:
        refreshed["value"] = True
        return {
            "ok": True,
            "status": "current",
            "written": True,
            "target_db": str(aoa_root / "search" / "operational-route-rollup.sqlite3"),
            "write_result": {"size_human": "24.5 MiB"},
            "totals": {"route_rollup_row_count": 10, "candidate_route_posting_count": 25},
            "elapsed_ms": 12,
            "diagnostics": [],
        }

    monkeypatch.setattr(module, "latest_index_source_mtime", lambda *_args, **_kwargs: (1.0, []))
    monkeypatch.setattr(module, "route_index_drift_records", lambda _records: [])
    monkeypatch.setattr(module, "sqlite_search_index_hot_state", lambda _aoa_root: {"needs_refresh": False, "reasons": []})
    monkeypatch.setattr(module, "atlas_index_hot_state", lambda _aoa_root: {"needs_refresh": False, "reasons": []})
    monkeypatch.setattr(module, "sqlite_search_index_state", lambda *_args, **_kwargs: {"status": "current", "needs_refresh": False, "dirty_sessions": [], "dirty_session_ids": [], "reasons": [], "diagnostics": []})
    monkeypatch.setattr(module, "atlas_index_state", lambda *_args, **_kwargs: {"status": "current", "needs_refresh": False, "dirty_sessions": [], "dirty_session_ids": [], "reasons": [], "diagnostics": []})
    monkeypatch.setattr(module, "graph_store_state", lambda *_args, **_kwargs: {"status": "current", "needs_maintenance": False, "needs_full_rebuild": False, "diagnostics": []})
    monkeypatch.setattr(module, "entity_registry_maintenance_status", lambda _aoa_root: {"status": "current", "needs_maintenance": False, "diagnostics": []})
    monkeypatch.setattr(module, "session_memory_search_shard_projection_summary", lambda _aoa_root: {"status": "current", "shard_count": 2, "largest_shards": []})
    monkeypatch.setattr(module, "session_memory_operational_route_rollup_status", fake_rollup_status)
    monkeypatch.setattr(module, "session_memory_search_operational_route_rollup", fake_refresh_rollup)
    monkeypatch.setattr(module, "route_layer_readiness", lambda **_kwargs: {"ok": True, "covered_requirement_count": 0, "required_requirement_count": 0, "remaining": [], "diagnostics": []})

    payload = module.maintain_indexes(
        aoa_root=aoa_root,
        apply=True,
        repair_token_accounting=False,
        repair_graph=True,
        selected_records=[record],
        budget_seconds=60,
    )

