    assert payload["ok"] is False
    assert payload["status"] == "applied_with_remaining_backlog"
    assert payload["mutates"] is True
    assert payload["child_result_verified"] is True
    assert payload["child_status"] == "applied_with_remaining_backlog"
    assert payload["child_progressed_with_remaining"] is True
    assert payload["child_progress_evidence"]["verified"] is True
    assert payload["child_progress_evidence"]["applied_action_count"] == 8
    assert payload["child_progress_evidence"]["remaining_projection_count"] >= 508
    assert module.auto_maintenance_resource_status_progressed(
        "applied_with_remaining_backlog",
        payload,
    ) is True
    assert payload["child"]["search_shards_repair_needed"] is True
    assert payload["child"]["search_shards_repair_remaining_count"] == 508
    assert payload["child"]["final_search_shards"]["stale_session_count"] == 508
    shard_action = next(
        action
        for action in payload["child"]["actions"]
        if action["id"] == "refresh_search_shards"
    )
    assert shard_action["progress"]["remaining_count"] == 508
    assert payload["automatic_retry"]["status"] == "scheduled"
    assert payload["recommended_exit_code"] == 0
    assert set(queue["items"]) == {"backlog:all"}


