def test_maintenance_child_bounded_progress_requires_progress_and_remaining_work() -> None:
    child = {
        "artifact_type": "session_memory_auto_maintenance",
        "ok": False,
        "status": "applied",
        "mutates": True,
        "apply": True,
        "maintenance": {
            "ok": False,
            "budget_exhausted": True,
            "action_counts": {
                "applied_partial_budget_exhausted": 1,
                "deferred_budget_exhausted": 2,
            },
        },
    }

    proven = module.maintenance_child_bounded_progress_evidence(child)
    assert proven["verified"] is True
    assert proven["applied_action_count"] == 1
    assert proven["remaining_action_count"] == 3

    no_progress = json.loads(json.dumps(child))
    no_progress["maintenance"]["action_counts"] = {
        "deferred_budget_exhausted": 2,
    }
    assert module.maintenance_child_bounded_progress_evidence(no_progress)[
        "verified"
    ] is False

    no_remaining = json.loads(json.dumps(child))
    no_remaining["maintenance"]["action_counts"] = {"applied": 1}
    assert module.maintenance_child_bounded_progress_evidence(no_remaining)[
        "verified"
    ] is False

    not_mutating = json.loads(json.dumps(child))
    not_mutating["mutates"] = False
    assert module.maintenance_child_bounded_progress_evidence(not_mutating)[
        "verified"
    ] is False


