def test_compact_auto_maintenance_keeps_cardinality_freshness_and_backlog() -> None:
    compact = module.auto_maintenance_print_payload(
        {
            "artifact_type": "auto_maintenance",
            "freshness_before": {
                "episode_posting_cardinality": {"status": "partial"},
                "episode_posting_cardinality_repair_needed": True,
            },
            "freshness_after": {
                "episode_posting_cardinality": {"status": "current"},
                "episode_posting_cardinality_repair_needed": False,
            },
            "maintenance": {
                "episode_posting_cardinality_metadata_incomplete_session_count": 7,
                "episode_posting_cardinality_metadata_remaining_count": 3,
                "episode_posting_cardinality": {"status": "partial"},
                "final_episode_posting_cardinality": {"status": "partial"},
            },
        }
    )

    assert compact["freshness_before"]["episode_posting_cardinality"]["status"] == "partial"
    assert compact["freshness_before"]["episode_posting_cardinality_repair_needed"] is True
    assert compact["freshness_after"]["episode_posting_cardinality"]["status"] == "current"
    assert compact["freshness_after"]["episode_posting_cardinality_repair_needed"] is False
    maintenance = compact["maintenance"]
    assert maintenance["episode_posting_cardinality_metadata_incomplete_session_count"] == 7
    assert maintenance["episode_posting_cardinality_metadata_remaining_count"] == 3
    assert maintenance["episode_posting_cardinality"]["status"] == "partial"
    assert maintenance["final_episode_posting_cardinality"]["status"] == "partial"


def test_catchup_index_drip_floor_prefers_larger_learned_demand_and_is_retryable(
    tmp_path: Path, monkeypatch: Any
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)
    calls: list[list[str]] = []

    def fake_run(command: list[str], **_kwargs: Any) -> subprocess.CompletedProcess[str]:
        calls.append(command)
        if len(calls) == 1:
            stdout = json.dumps(
                {
                    "schema": "abyss_machine_resource_plan_v1",
                    "ok": False,
                    "blocked_reasons": ["indexing_unattended_memory_reserve"],
                    "denied_reasons": [],
                    "request": {"class": "medium", "kind": "indexing"},
                    "execution": {"ok": None, "returncode": None},
                }
            )
        elif len(calls) == 2:
            stdout = json.dumps(
                {
                    "schema": "abyss_machine_resource_plan_v1",
                    "ok": True,
                    "inputs": {
                        "startup_demand": {
                            "requested": {
                                "demand_mib": 5100.0,
                                "calibration": "learned",
                                "estimate_source": "runtime_observed_unit_peak",
                                "estimate_confidence": "observed",
                                "learned_sample_count": 4,
                            }
                        }
                    },
                }
            )
        else:
            stdout = json.dumps(
                {
                    "schema": "abyss_machine_resource_launch_v1",
                    "ok": True,
                    "blocked_reasons": [],
                    "denied_reasons": [],
                    "request": {"class": "probe", "kind": "indexing"},
                    "execution": {
                        "ok": True,
                        "returncode": 0,
                        "stdout_tail": '{"ok": true, "status": "applied"}',
                    },
                }
            )
        return subprocess.CompletedProcess(command, 0, stdout=stdout, stderr="")

    monkeypatch.setattr(module.subprocess, "run", fake_run)

    payload = module.auto_maintenance_resource_launch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="catchup",
        apply=True,
        reason="timer_catchup",
        index_drip_on_block=True,
        index_drip_memory_demand_floor_mib=4000,
        index_drip_estimate_source="observed_index_drip_peak_plus_25pct",
        index_drip_estimate_confidence="medium",
    )

    assert payload["status"] == "resource_blocked_index_drip_completed"
    assert len(calls) == 3
    assert calls[1][:3] == ["abyss-machine", "resource", "plan"]
    fallback_command = calls[2]
    assert fallback_command[fallback_command.index("--memory-demand-mib") + 1] == "5100"
    assert fallback_command[fallback_command.index("--estimate-source") + 1] == (
        "runtime_observed_unit_peak_above_owner_floor"
    )
    assert fallback_command[fallback_command.index("--estimate-confidence") + 1] == "observed"
    resolution = payload["fallback_index_drip"]["resource_demand_floor_resolution"]
    assert resolution["floor_mib"] == 4000.0
    assert resolution["learned_mib"] == 5100.0
    assert resolution["effective_mib"] == 5100.0
    assert resolution["calibration"] == "learned_above_owner_floor"
    assert resolution["learned_sample_count"] == 4
    for key in (
        "index_drip_memory_demand_floor_mib",
        "index_drip_estimate_source",
        "index_drip_estimate_confidence",
    ):
        assert key in module.AUTO_MAINTENANCE_RETRY_OPTION_KEYS

    parsed = module.build_parser().parse_args(
        [
            "auto-maintenance-resource",
            "catchup",
            "--index-drip-memory-demand-floor-mib",
            "4000",
            "--index-drip-estimate-source",
            "observed_index_drip_peak_plus_25pct",
            "--index-drip-estimate-confidence",
            "medium",
        ]
    )
    assert parsed.index_drip_memory_demand_floor_mib == 4000
    assert parsed.index_drip_estimate_source == "observed_index_drip_peak_plus_25pct"
    assert parsed.index_drip_estimate_confidence == "medium"


def test_index_drip_fallback_reports_child_lock_conflict(tmp_path: Path, monkeypatch: Any) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)
    calls: list[list[str]] = []

    def fake_run(command: list[str], **_kwargs: Any) -> subprocess.CompletedProcess[str]:
        calls.append(command)
        if len(calls) == 1:
            stdout = json.dumps(
                {
                    "schema": "abyss_machine_resource_plan_v1",
                    "ok": False,
                    "blocked_reasons": ["indexing_unattended_swap_used_pressure"],
                    "denied_reasons": [],
                    "request": {"class": "medium", "kind": "indexing"},
                    "execution": {"ok": None, "returncode": None},
                }
            )
        else:
            child = {
                "schema_version": 1,
                "artifact_type": "session_memory_maintenance_lock_conflict",
                "ok": True,
                "status": "skipped_lock_held",
                "mutates": False,
                "target": "all",
                "diagnostics": ["lock_held"],
            }
            stdout = json.dumps(
                {
                    "schema": "abyss_machine_resource_launch_v1",
                    "ok": True,
                    "blocked_reasons": [],
                    "denied_reasons": [],
                    "request": {"class": "probe", "kind": "indexing"},
                    "execution": {
                        "ok": True,
                        "returncode": 0,
                        "stdout_tail": json.dumps(child),
                    },
                }
            )
        return subprocess.CompletedProcess(command, 0, stdout=stdout, stderr="")

    monkeypatch.setattr(module.subprocess, "run", fake_run)

    payload = module.auto_maintenance_resource_launch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="catchup",
        apply=True,
        reason="timer_catchup",
        index_drip_on_block=True,
    )

    assert payload["status"] == "resource_blocked_index_drip_failed"
    assert payload["mutates"] is False
    assert payload["fallback_index_drip"]["ok"] is False
    assert payload["fallback_index_drip"]["status"] == "skipped_lock_held"
    assert payload["fallback_index_drip"]["child"]["status"] == "skipped_lock_held"
    assert "lock_held" in payload["fallback_index_drip"]["diagnostics"]
    assert "index_drip_fallback_skipped_lock_held" in payload["diagnostics"]


