def test_graph_queue_apply_tops_up_demanded_sources_from_nonempty_ledger(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    aoa_root = tmp_path / ".aoa"
    demanded_dir = aoa_root / "sessions" / "2026-07-16__001__demanded"
    backlog_dir = aoa_root / "sessions" / "2026-07-15__001__backlog"
    (demanded_dir / "segments").mkdir(parents=True)
    (backlog_dir / "segments").mkdir(parents=True)
    sources: dict[str, dict[str, Any]] = {}
    for session_id, session_dir, count in (
        ("demanded", demanded_dir, 2),
        ("backlog", backlog_dir, 3),
    ):
        for index in range(count):
            source_key = f"segment:{session_id}:{index:03d}"
            source_path = session_dir / "segments" / f"{index:03d}.index.json"
            source_path.write_text("{}\n", encoding="utf-8")
            sources[source_key] = {
                "source_key": source_key,
                "source_type": "segment",
                "session_id": session_id,
                "session_label": session_dir.name,
                "segment_id": f"{index:03d}",
                "session_dir": str(session_dir),
                "source_path": str(source_path),
                "status": "missing",
                "stored_node_count": 0,
                "stored_edge_count": 0,
                "source_size_bytes": 1,
            }
    module.write_graph_source_state_ledger(aoa_root, {"sources": sources})
    module.write_graph_maintenance_queue(
        aoa_root,
        {
            "items": {
                source_key: item
                for source_key, item in sources.items()
                if item["session_id"] == "backlog"
            }
        },
    )
    observed: dict[str, Any] = {}

    def fake_graph_source_states(**kwargs: Any) -> dict[str, Any]:
        source_key_filters = list(kwargs.get("source_key_filters") or [])
        observed["source_key_filters"] = source_key_filters
        return {
            "states": [dict(sources[source_key]) for source_key in source_key_filters],
            "diagnostics": [],
            "existing_source_count": len(source_key_filters),
        }

    class FakeConn:
        def commit(self) -> None:
            observed["committed"] = True

        def rollback(self) -> None:
            observed["rolled_back"] = True

    class FakeStore:
        def __init__(self, *_: Any, **__: Any) -> None:
            self.conn = FakeConn()

        def source_contribution_ids(self, _source_key: str) -> tuple[set[str], set[str]]:
            return set(), set()

        def replace_sources(
            self,
            contributions: list[dict[str, Any]],
            *,
            budget_deadline: float | None = None,
        ) -> dict[str, Any]:
            del budget_deadline
            updated_keys = [item["source"]["source_key"] for item in contributions]
            return {
                "results": [
                    {"source_key": source_key, "status": "updated", "diagnostics": []}
                    for source_key in updated_keys
                ],
                "refreshed_node_count": len(updated_keys),
                "refreshed_edge_count": 0,
                "node_refresh": {
                    "requested_count": len(updated_keys),
                    "chunk_count": 1,
                    "row_count": len(updated_keys),
                    "missing_count": 0,
                },
                "edge_refresh": {
                    "requested_count": 0,
                    "chunk_count": 0,
                    "row_count": 0,
                    "missing_count": 0,
                },
                "refresh_chunk_size": 64,
            }

        def close(self) -> None:
            observed["closed"] = True

    def fake_graph_contributions_for_record(
        record: dict[str, Any],
        *,
        source_keys: set[str] | None = None,
    ) -> tuple[list[dict[str, Any]], list[str]]:
        del record
        return (
            [
                {
                    "source": {"source_key": source_key, "source_type": "segment"},
                    "nodes": [{"id": f"node:{source_key}"}],
                    "edges": [],
                }
                for source_key in sorted(source_keys or set())
            ],
            [],
        )

    monkeypatch.setattr(module, "graph_source_states", fake_graph_source_states)
    monkeypatch.setattr(module, "GraphSqliteStore", FakeStore)
    monkeypatch.setattr(module, "graph_contributions_for_record", fake_graph_contributions_for_record)

    payload = module.graph_maintenance(
        aoa_root=aoa_root,
        use_queue=True,
        apply=True,
        batch_limit=2,
        query_demand={"priority_session_ids": ["demanded"]},
        reason="automatic_graph_demand_regression",
    )

    assert [item["session_id"] for item in payload["selected"]] == ["demanded", "demanded"]
    assert payload["maintenance_detail"]["queue_priority_top_up"]["selected_sources"] == [
        "segment:demanded:000",
        "segment:demanded:001",
    ]
    assert set(observed["source_key_filters"]) == set(sources)
    remaining_queue = module.read_graph_maintenance_queue(aoa_root)["items"]
    assert {item["session_id"] for item in remaining_queue.values()} == {"backlog"}


