def test_graph_maintenance_compact_stdout_keeps_report_marker_in_bounded_tail(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    diagnostics_dir = aoa_root / "diagnostics"
    diagnostics_dir.mkdir(parents=True)
    report_path = diagnostics_dir / "20260716T102308Z__graph-maintenance.json"
    report_payload = {
        "artifact_type": "session_memory_graph_maintenance",
        "ok": True,
        "selected_count": 25,
        "remaining_count": 75,
    }
    module.write_json(report_path, report_payload)
    payload = {
        **report_payload,
        "report_json": str(report_path),
        "report_markdown": str(report_path.with_suffix(".md")),
        "selected": [
            {"source_key": f"segment:session-with-long-source-key-{index:03d}:" + ("x" * 320)}
            for index in range(40)
        ],
        "maintenance_detail": {
            "selected_sources": [
                f"segment:session-with-long-source-key-{index:03d}:" + ("x" * 320)
                for index in range(40)
            ]
        },
    }

    compact = module.compact_graph_maintenance_stdout_payload(payload)
    rendered = json.dumps(compact, indent=2, ensure_ascii=False)
    truncated_tail = rendered[-1024:]

    assert list(compact)[-1] == "report_json"
    assert not truncated_tail.lstrip().startswith("{")
    recovered = module.child_json_payload_from_stdout_tail(truncated_tail, aoa_root=aoa_root)
    assert recovered == report_payload


