def test_auto_maintenance_retry_dispatch_uses_profile_deadlines_with_aging(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    (aoa_root / "diagnostics").mkdir(parents=True)
    now_epoch = 2_000.0
    queue_payload = {
        "items": {
            "backlog:all": {
                "queue_key": "backlog:all",
                "profile": "backlog",
                "target": "all",
                "status": "pending",
                "in_flight": False,
                "attempts_started": 0,
                "max_attempts": 4,
                "occurrence_count": 1,
                "next_attempt_epoch": 1_148.0,
                "next_attempt_at": module.auto_maintenance_retry_iso(1_148.0),
                "options": {},
            },
            "catchup:all": {
                "queue_key": "catchup:all",
                "profile": "catchup",
                "target": "all",
                "status": "pending",
                "in_flight": False,
                "attempts_started": 0,
                "max_attempts": 4,
                "occurrence_count": 1,
                "next_attempt_epoch": 1_995.0,
                "next_attempt_at": module.auto_maintenance_retry_iso(1_995.0),
                "options": {},
            },
            "hot:all": {
                "queue_key": "hot:all",
                "profile": "hot",
                "target": "all",
                "status": "pending",
                "in_flight": False,
                "attempts_started": 0,
                "max_attempts": 4,
                "occurrence_count": 1,
                "next_attempt_epoch": 2_005.0,
                "next_attempt_at": module.auto_maintenance_retry_iso(2_005.0),
                "options": {},
            },
        },
        "history": [],
    }
    module.write_auto_maintenance_retry_queue(
        aoa_root,
        queue_payload,
        now_epoch=now_epoch,
    )

    initial = module.auto_maintenance_retry_queue_status(
        aoa_root,
        now_epoch=now_epoch,
    )
    assert initial["dispatch_order_due_keys"] == ["catchup:all", "backlog:all"]
    assert initial["due_items"][0]["dispatch_wait_target_seconds"] == 300
    assert initial["due_items"][1]["dispatch_target_breached"] is False
    compact = module.compact_maintenance_status_payload(
        {"automatic_retry": initial}
    )
    assert compact["automatic_retry"]["dispatch_policy"]["version"] == 2
    assert compact["automatic_retry"]["dispatch_order_due_keys"] == [
        "catchup:all",
        "backlog:all",
    ]
    assert compact["automatic_retry"]["due_item_samples"][0]["queue_key"] == "catchup:all"

    plan = module.auto_maintenance_retry_dispatch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        apply=False,
        limit=1,
        now_epoch=now_epoch,
    )
    assert plan["dispatch_policy"]["version"] == 2
    assert plan["planned_queue_keys"] == ["catchup:all"]
    assert plan["planned_items"][0]["dispatch_deadline_epoch"] == 2_295.0

    calls: list[dict[str, Any]] = []

    def completed_launch(**kwargs: Any) -> dict[str, Any]:
        calls.append(kwargs)
        return {
            "schema_version": 1,
            "artifact_type": "auto_maintenance_resource_launch",
            "ok": True,
            "status": "completed",
            "child_result_verified": True,
        }

    monkeypatch.setattr(module, "auto_maintenance_resource_launch", completed_launch)
    dispatched = module.auto_maintenance_retry_dispatch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        apply=True,
        limit=1,
        now_epoch=now_epoch,
    )
    assert calls[0]["profile"] == "catchup"
    assert dispatched["results"][0]["dispatch_selection"]["queue_key"] == "catchup:all"

    aged = module.auto_maintenance_retry_queue_status(
        aoa_root,
        now_epoch=2_010.0,
    )
    assert aged["dispatch_order_due_keys"] == ["hot:all", "backlog:all"]


def test_auto_maintenance_retry_dispatch_recovers_interrupted_in_flight_claim(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)

    def blocked_run(command: list[str], **_kwargs: Any) -> subprocess.CompletedProcess[str]:
        stdout = json.dumps(
            {
                "schema": "abyss_machine_resource_plan_v1",
                "ok": False,
                "blocked_reasons": ["startup_projected_mem_available_below_hard_reserve"],
                "denied_reasons": [],
                "request": {"class": "medium", "kind": "indexing"},
                "execution": {"ok": None, "returncode": None},
            }
        )
        return subprocess.CompletedProcess(command, 0, stdout=stdout, stderr="")

    monkeypatch.setattr(module.subprocess, "run", blocked_run)
    module.auto_maintenance_resource_launch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="catchup",
        apply=True,
        reason="timer_catchup",
        graph_drip_on_block=False,
    )
    queued = module.auto_maintenance_retry_queue_status(aoa_root)
    restart_epoch = queued["items"]["catchup:all"]["next_attempt_epoch"] + 1

    def leave_interrupted_claim(queue_payload: dict[str, Any]) -> tuple[None, bool]:
        item = queue_payload["items"]["catchup:all"]
        item["attempts_started"] = 1
        item["in_flight"] = True
        item["status"] = "in_flight"
        item["last_attempt_started_epoch"] = restart_epoch - 30
        item["last_attempt_started_at"] = module.auto_maintenance_retry_iso(restart_epoch - 30)
        return None, True

    module.mutate_auto_maintenance_retry_queue(
        aoa_root,
        leave_interrupted_claim,
        now_epoch=restart_epoch - 30,
    )

    def blocked_launch(**_kwargs: Any) -> dict[str, Any]:
        return {
            "schema_version": 1,
            "artifact_type": "auto_maintenance_resource_launch",
            "ok": False,
            "status": "resource_blocked",
            "blocked_reasons": ["startup_projected_mem_available_below_hard_reserve"],
        }

    monkeypatch.setattr(module, "auto_maintenance_resource_launch", blocked_launch)
    dispatched = module.auto_maintenance_retry_dispatch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        apply=True,
        limit=1,
        now_epoch=restart_epoch,
    )

    after = module.auto_maintenance_retry_queue_status(aoa_root, now_epoch=restart_epoch)
    retry_item = after["items"]["catchup:all"]
    assert dispatched["queue_before"]["status"] == "in_flight"
    assert dispatched["recovered_in_flight_count"] == 1
    assert dispatched["processed_count"] == 1
    assert dispatched["results"][0]["attempt"] == 2
    assert dispatched["results"][0]["disposition"] == "rescheduled"
    assert retry_item["in_flight"] is False
    assert retry_item["status"] == "pending"
    assert retry_item["recovered_after_dispatcher_restart_at"] == module.auto_maintenance_retry_iso(restart_epoch)
    assert retry_item["last_attempt_started_at"] == module.auto_maintenance_retry_iso(restart_epoch)


