def test_auto_maintenance_retry_dispatch_records_finish_time_and_backs_off_from_completion(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)

    def blocked_run(command: list[str], **_kwargs: Any) -> subprocess.CompletedProcess[str]:
        stdout = json.dumps(
            {
                "schema": "abyss_machine_resource_plan_v1",
                "ok": False,
                "blocked_reasons": ["startup_projected_mem_available_below_hard_reserve"],
                "denied_reasons": [],
                "request": {"class": "medium", "kind": "indexing"},
                "execution": {"ok": None, "returncode": None},
            }
        )
        return subprocess.CompletedProcess(command, 0, stdout=stdout, stderr="")

    monkeypatch.setattr(module.subprocess, "run", blocked_run)
    module.auto_maintenance_resource_launch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="backlog",
        apply=True,
        reason="timer_backlog",
        graph_drip_on_block=False,
    )
    queued = module.auto_maintenance_retry_queue_status(aoa_root)
    due_epoch = queued["items"]["backlog:all"]["next_attempt_epoch"] + 1
    finish_epoch = due_epoch + 37

    def blocked_launch(**_kwargs: Any) -> dict[str, Any]:
        return {
            "schema_version": 1,
            "artifact_type": "auto_maintenance_resource_launch",
            "ok": False,
            "status": "resource_blocked",
            "blocked_reasons": ["startup_projected_mem_available_below_hard_reserve"],
        }

    clock = iter([due_epoch, finish_epoch])
    monkeypatch.setattr(module, "auto_maintenance_resource_launch", blocked_launch)
    monkeypatch.setattr(module.time, "time", lambda: next(clock))

    dispatched = module.auto_maintenance_retry_dispatch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        apply=True,
        limit=1,
    )

    after = module.auto_maintenance_retry_queue_status(aoa_root, now_epoch=finish_epoch)
    retry_item = after["items"]["backlog:all"]
    assert retry_item["last_attempt_started_epoch"] == due_epoch
    assert retry_item["last_attempt_finished_epoch"] == finish_epoch
    assert retry_item["last_attempt_finished_at"] == module.auto_maintenance_retry_iso(finish_epoch)
    assert retry_item["next_attempt_epoch"] == finish_epoch + retry_item["next_delay_seconds"]
    assert dispatched["started_at"] == module.auto_maintenance_retry_iso(due_epoch)
    assert dispatched["completed_at"] == module.auto_maintenance_retry_iso(finish_epoch)
    assert dispatched["elapsed_ms"] == 37_000
    assert dispatched["results"][0]["completed_at"] == module.auto_maintenance_retry_iso(finish_epoch)


def test_deep_auto_maintenance_resource_defaults_to_graph_drip_fallback(tmp_path: Path, monkeypatch: Any) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)
    calls: list[list[str]] = []

    def fake_run(command: list[str], **_kwargs: Any) -> subprocess.CompletedProcess[str]:
        calls.append(command)
        if len(calls) == 1:
            stdout = json.dumps(
                {
                    "schema": "abyss_machine_resource_plan_v1",
                    "generated_at": "2026-06-25T10:22:26-06:00",
                    "ok": False,
                    "blocked_reasons": ["mode_unattended_cap_medium"],
                    "denied_reasons": [],
                    "request": {"class": "heavy", "kind": "indexing"},
                    "execution": {"ok": None, "returncode": None},
                }
            )
        else:
            stdout = json.dumps(
                {
                    "schema": "abyss_machine_resource_launch_v1",
                    "generated_at": "2026-06-25T10:22:40-06:00",
                    "ok": True,
                    "blocked_reasons": [],
                    "denied_reasons": [],
                    "request": {"class": "probe", "kind": "indexing"},
                    "execution": {
                        "ok": True,
                        "returncode": 0,
                        "stdout_tail": json.dumps(
                            {
                                "artifact_type": "session_memory_graph_maintenance",
                                "ok": True,
                                "status": "applied",
                            }
                        ),
                    },
                }
            )
        return subprocess.CompletedProcess(command, 0, stdout=stdout, stderr="")

    monkeypatch.setattr(module.subprocess, "run", fake_run)

    payload = module.auto_maintenance_resource_launch(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="deep",
        apply=True,
        write_report=True,
        reason="timer_deep",
    )

    assert payload["status"] == "resource_blocked_graph_drip_completed"
    assert payload["graph_drip_on_block"] is True
    assert payload["graph_drip_on_block_source"] == "profile_default"
    assert payload["mutates"] is True
    assert payload["fallback_graph_drip"]["batch_limit"] == module.AUTO_MAINTENANCE_PROFILES["deep"]["graph_drip_batch_limit"]
    assert payload["fallback_graph_drip"]["budget_seconds"] == module.AUTO_MAINTENANCE_PROFILES["deep"]["graph_drip_budget_seconds"]
    assert payload["fallback_graph_drip"]["candidate_pool_limit"] == module.AUTO_MAINTENANCE_PROFILES["deep"]["graph_drip_candidate_pool_limit"]
    assert calls[0][3:5] == ["--class", "heavy"]
    assert calls[1][3:5] == ["--class", "probe"]
    assert "--use-queue" in calls[1]
    assert "--seed-queue-from-ledger" in calls[1]
    assert calls[1][calls[1].index("--queue-seed-limit") + 1] == "250"
    assert "--write-queue" in calls[1]
    assert "--write-ledger" in calls[1]
    assert "graph_drip_fallback_completed" in payload["diagnostics"]


