def test_search_index_sessions_applies_explicit_context_tail_omission_policy(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    aoa_root = tmp_path / ".aoa"
    aoa_root.mkdir(parents=True)
    db_path = tmp_path / "search" / "aoa-search.sqlite3"
    session_label = "2026-06-29__001__omission-policy"

    def event_doc(doc_id: str, **overrides: Any) -> dict[str, Any]:
        route_signal = str(overrides.pop("route_signal", "") or "")
        return {
            "id": doc_id,
            "doc_type": "event",
            "session_id": "session-omission",
            "session_label": session_label,
            "session_title": "Omission policy",
            "session_date": "2026-06-29",
            "event_id": doc_id,
            "event_type": overrides.pop("event_type", "CONTEXT_STATE"),
            "usage_role": overrides.pop("usage_role", "context"),
            "agent_event": overrides.pop("agent_event", ""),
            "task_episode_id": overrides.pop("task_episode_id", ""),
            "session_act": "tool_context" if route_signal else "",
            "route_layers": module.packed_route_values(["tool"]) if route_signal else "",
            "route_signals": module.packed_route_values([route_signal]) if route_signal else "",
            "title": doc_id,
            "body": f"body {doc_id}",
            "raw_ref": f"raw:line:{doc_id}",
            "segment_ref": "segments/000__initial-to-latest.md",
            "segment_index_path": "",
            "payload_json": "{}",
            **overrides,
        }

    documents = [
        event_doc("usage-doc", event_type="TOOL_CALL", usage_role="usage"),
        event_doc("agent-answer-context", agent_event="assistant_answer"),
        event_doc("task-context", task_episode_id="task-1"),
        event_doc("protected-context", event_type="ASSISTANT_MESSAGE"),
        event_doc("candidate-with-route", route_signal=module.route_signal_token("tool", "exec_command")),
        event_doc("candidate-without-route"),
    ]

    monkeypatch.setattr(
        module,
        "session_projection_fingerprint",
        lambda _record, include_rendered_markdown=False: {
            "session_id": "session-omission",
            "session_label": session_label,
            "fingerprint": "fingerprint-1",
            "latest_source_mtime": 1.0,
            "source_path_count": 1,
        },
    )
    monkeypatch.setattr(
        module,
        "search_documents_for_record",
        lambda *_args, **_kwargs: (
            list(documents),
            {
                "status": "indexed",
                "session_id": "session-omission",
                "session_label": session_label,
                "raw_text_status": "skipped_structured_projection",
                "diagnostics": [],
            },
        ),
    )

    payload = module.search_index_sessions(
        aoa_root=aoa_root,
        selected_records=[{"session_id": "session-omission", "session_label": session_label}],
        rebuild=True,
        db_path_override=db_path,
        refresh_catalog=False,
        include_entity_registry=False,
        include_raw_event_text=False,
        store_raw_text=False,
        context_tail_omission_policy=module.SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED,
    )

    assert payload["ok"] is True
    assert payload["document_count"] == 5
    assert payload["event_document_count"] == 5
    assert payload["context_tail_omission"]["omitted_document_count"] == 1
    assert payload["context_tail_omission"]["counts"]["candidate_context_tail_count"] == 2
    assert payload["context_tail_omission"]["counts"]["route_ref_backed_omission_candidate_count"] == 1
    assert payload["context_tail_omission"]["counts"]["unrouted_keep_candidate_count"] == 1

    conn = module.connect_existing_search_db(db_path)
    try:
        ids = {str(row[0]) for row in conn.execute("SELECT id FROM documents").fetchall()}
        omitted_rows = [
            dict(row)
            for row in conn.execute(
                "SELECT * FROM omitted_context_tail_route_refs ORDER BY layer, key, raw_ref"
            ).fetchall()
        ]
        metadata = module.search_index_metadata(conn)
    finally:
        conn.close()
    assert "candidate-with-route" not in ids
    assert "candidate-without-route" in ids
    assert len(omitted_rows) == 1
    assert omitted_rows[0]["doc_id"] == "candidate-with-route"
    assert omitted_rows[0]["layer"] == "tool"
    assert omitted_rows[0]["key"] == "exec_command"
    assert omitted_rows[0]["route_signal"] == module.route_signal_token("tool", "exec_command")
    assert omitted_rows[0]["raw_ref"] == "raw:line:candidate-with-route"
    assert omitted_rows[0]["segment_ref"] == "segments/000__initial-to-latest.md"
    assert metadata["search_context_tail_omission_policy"] == module.SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED


def test_search_shards_auto_context_tail_policy_inherits_existing_shard_meta(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    aoa_root = tmp_path / ".aoa"
    shard = "month/2026-05"
    shard_db = module.search_shard_db_path(aoa_root, shard)
    conn = module.init_search_db(shard_db, rebuild=True)
    try:
        conn.execute(
            "INSERT OR REPLACE INTO meta(key, value) VALUES (?, ?)",
            ("search_context_tail_omission_policy", module.SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED),
        )
        conn.commit()
    finally:
        conn.close()
    records = [{"session_id": "may-dirty", "session_label": "2026-05-01__001__dirty-session"}]
    calls: dict[str, Any] = {}

    def fake_records(
        _aoa_root: Path,
        *,
        target: str,
        since: str | None,
        until: str | None,
        limit: int | None,
    ) -> list[dict[str, Any]]:
        return list(records)

    def fake_dirty_filter(
        _aoa_root: Path,
        selected_records: list[dict[str, Any]],
        *,
        shard: str | None = None,
        include_deferred_live: bool = False,
    ) -> tuple[list[dict[str, Any]], dict[str, Any]]:
        return list(selected_records), {
            "dirty_candidate_count": len(selected_records),
            "deferred_live_skipped_count": 0,
            "pre_filter_selected_count": len(selected_records),
            "dirty_selected_count": len(selected_records),
            "skipped_current_count": 0,
        }

    def fake_search_index_sessions(**kwargs: Any) -> dict[str, Any]:
        calls["context_tail_omission_policy"] = kwargs["context_tail_omission_policy"]
        selected_records = kwargs["selected_records"]
        return {
            "ok": True,
            "processed_count": len(selected_records),
            "document_count": len(selected_records),
            "session_document_count": len(selected_records),
            "segment_document_count": 0,
            "event_document_count": 0,
            "incident_document_count": 0,
            "entity_registry_document_count": 0,
            "goal_lifecycle_document_count": 0,
            "task_episode_document_count": 0,
            "context_tail_omission_policy": kwargs["context_tail_omission_policy"],
            "context_tail_omission": {
                "policy": kwargs["context_tail_omission_policy"],
                "counts": {},
                "omitted_document_count": 0,
                "omitted_route_ref_row_count": 0,
            },
            "slow_sessions": [],
            "slow_session_warning_count": 0,
            "diagnostics": [],
        }

    def fake_build_search_catalog(*_args: Any, **kwargs: Any) -> dict[str, Any]:
        return {
            "ok": True,
            "status": "current",
            "catalog_state_basis": "selected_records",
            "selected_state_key_count": len(kwargs.get("selected_records") or []),
        }

    monkeypatch.setattr(module, "search_records_for_target", fake_records)
    monkeypatch.setattr(module, "filter_search_records_to_dirty_shard_sessions", fake_dirty_filter)
    monkeypatch.setattr(module, "search_index_sessions", fake_search_index_sessions)
    monkeypatch.setattr(module, "build_search_catalog", fake_build_search_catalog)

    payload = module.materialize_search_shards(
        aoa_root=aoa_root,
        target="all",
        shard=shard,
        rebuild_shards=False,
        dirty_only=True,
    )

    assert payload["ok"] is True
    assert payload["requested_context_tail_omission_policy"] == module.SEARCH_CONTEXT_TAIL_OMISSION_POLICY_AUTO
    assert payload["context_tail_omission_policy"] == module.SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED
    assert calls["context_tail_omission_policy"] == module.SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED
    assert payload["context_tail_omission_policy_resolution"]["source"] == "existing_shard_meta"
    assert payload["context_tail_omission_policy_resolution"]["shard_policies"][0]["policy"] == module.SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED


