def test_graph_usage_replacement_does_not_match_foreign_session_aggregate(
    monkeypatch: Any,
) -> None:
    registry_node_id = "entity_registry:skill:sample_skill"
    foreign_edge_id = module.graph_edge_id(
        "session:foreign-session",
        registry_node_id,
        module.GRAPH_ENTITY_USAGE_REPLACEMENT_AGGREGATE_EDGE_TYPE,
    )
    conn = sqlite3.connect(":memory:")
    conn.row_factory = sqlite3.Row
    conn.execute(
        """
        CREATE TABLE edges (
          id TEXT PRIMARY KEY,
          target_node TEXT NOT NULL,
          edge_type TEXT NOT NULL
        )
        """
    )
    conn.execute(
        "INSERT INTO edges(id, target_node, edge_type) VALUES (?, ?, ?)",
        (
            foreign_edge_id,
            registry_node_id,
            module.GRAPH_ENTITY_USAGE_REPLACEMENT_AGGREGATE_EDGE_TYPE,
        ),
    )
    monkeypatch.setattr(module, "graph_store_fetch_payloads", lambda *_args, **_kwargs: [])

    try:
        result = module.graph_entity_usage_replacement_matching_edges(
            conn,
            usage_events=[
                {
                    "session_id": "expected-session",
                    "segment_id": "001",
                    "event_id": "000001",
                    "role": "usage",
                    "refs": {
                        "raw": "raw:line:1",
                        "segment": "001.md#event-000001",
                    },
                }
            ],
            registry_node_ids=[registry_node_id],
            sample_limit=1,
            post_prune_aggregate_mode=True,
        )
    finally:
        conn.close()

    assert result["checked_count"] == 1
    assert result["matched_count"] == 0
    assert result["missing_count"] == 1
    assert result["missing_usage_events"][0]["session_id"] == "expected-session"


