def test_search_schema_transition_unknown_or_structural_drift_still_requires_deep() -> None:
    unknown_transition = {
        "search_index": {
            "status": "stale",
            "has_documents": True,
            "has_route_index": True,
            "has_route_terms": True,
            "search_schema_version": "19",
            "expected_search_schema_version": module.SEARCH_SCHEMA_VERSION,
            "reasons": ["search_schema_mismatch"],
            "diagnostics": ["search_schema_mismatch"],
        }
    }
    structural_drift = {
        "search_index": {
            "status": "stale",
            "has_documents": True,
            "has_route_index": True,
            "has_route_terms": True,
            "search_schema_version": "20",
            "expected_search_schema_version": module.SEARCH_SCHEMA_VERSION,
            "reasons": ["search_schema_mismatch"],
            "diagnostics": [
                "search_schema_mismatch",
                "search_schema_missing_column:documents.usage_role",
            ],
        }
    }

    assert module.auto_maintenance_search_schema_transition(unknown_transition)["status"] == "requires_full_rebuild"
    assert module.auto_maintenance_search_full_rebuild_reasons(unknown_transition) == ["search_schema_mismatch"]
    structural = module.auto_maintenance_search_schema_transition(structural_drift)
    assert structural["status"] == "requires_full_rebuild"
    assert structural["structural_blockers"] == ["search_schema_missing_column:documents.usage_role"]
    assert module.auto_maintenance_search_full_rebuild_reasons(structural_drift) == ["search_schema_mismatch"]


