def test_catchup_full_rebuild_guard_shares_outer_budget_and_skips_post_probe_after_exhaustion(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """The full-rebuild guard must not give every sidecar a fresh full budget."""
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)
    clock = {"now": 0.0}
    calls: dict[str, Any] = {
        "freshness": 0,
        "episode_budget": None,
        "cardinality_budget": None,
    }

    def fake_freshness(**kwargs: Any) -> dict[str, Any]:
        calls["freshness"] += 1
        return {
            "ok": False,
            "target": kwargs["target"],
            "selected_count": 2,
            "needs_index_maintenance": True,
            "needs_graph_maintenance": False,
            "diagnostics": ["index_maintenance_needed"],
            "search_index": {
                "status": "stale",
                "needs_refresh": True,
                "reasons": ["search_schema_mismatch"],
                "dirty_session_count": 0,
            },
            "atlas_index": {
                "status": "current",
                "needs_refresh": False,
                "dirty_session_count": 0,
            },
            "graph_store": {
                "status": "current",
                "needs_maintenance": False,
            },
            "episode_semantic_projection": {
                "status": "partial",
                "needs_refresh": True,
                "dirty_session_count": 2,
            },
            "episode_posting_cardinality": {
                "status": "partial",
                "metadata_complete_session_count": 0,
                "metadata_incomplete_session_count": 1,
            },
            "episode_posting_cardinality_repair_needed": True,
            "episode_dense_projection": {
                "status": "disabled",
                "enabled": False,
                "needs_refresh": False,
                "dirty_session_count": 0,
            },
        }

    def fake_episode_index(**kwargs: Any) -> dict[str, Any]:
        calls["episode_budget"] = kwargs["budget_seconds"]
        clock["now"] = 11.0
        return {
            "ok": False,
            "selected_count": 2,
            "processed_count": 1,
            "successful_count": 1,
            "completed_session_ids": ["guard-budget-1"],
            "remaining_count": 1,
            "budget_seconds": kwargs["budget_seconds"],
            "budget_exhausted": True,
            "indexed_episode_count": 1,
            "elapsed_ms": 11000,
            "queue": {
                "final": {
                    "remaining_count": 1,
                    "runnable_count": 1,
                    "deferred_count": 0,
                }
            },
            "diagnostics": [],
        }

    def fake_cardinality_refresh(**kwargs: Any) -> dict[str, Any]:
        calls["cardinality_budget"] = kwargs["budget_seconds"]
        return {
            "ok": False,
            "status": "budget_exhausted",
            "selected_count": 1,
            "processed_count": 0,
            "completed_session_ids": [],
            "remaining_count": 1,
            "budget_seconds": kwargs["budget_seconds"],
            "budget_exhausted": True,
            "elapsed_ms": 0,
            "diagnostics": [],
        }

    monkeypatch.setattr(module.time, "monotonic", lambda: clock["now"])
    monkeypatch.setattr(module, "route_cache_freshness_gates", fake_freshness)
    monkeypatch.setattr(
        module,
        "graph_freshness_gates",
        lambda **_: (_ for _ in ()).throw(
            AssertionError("catchup should use route-cache freshness")
        ),
    )
    monkeypatch.setattr(
        module,
        "maintain_indexes",
        lambda **_: (_ for _ in ()).throw(
            AssertionError("full search rebuild must stay deferred")
        ),
    )
    monkeypatch.setattr(
        module,
        "episode_semantic_index_sessions",
        fake_episode_index,
    )
    monkeypatch.setattr(
        module,
        "refresh_episode_posting_cardinality_metadata",
        fake_cardinality_refresh,
    )

    payload = module.auto_maintenance(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="catchup",
        apply=True,
        budget_seconds=10.0,
    )

    assert calls["freshness"] == 1
    assert 0 < calls["episode_budget"] <= 10.0
    assert calls["cardinality_budget"] == sys.float_info.epsilon
    assert payload["ok"] is True
    assert payload["status"] == "deferred_full_search_rebuild_to_deep"
    assert payload["maintenance"]["budget_exhausted"] is True
    assert payload["post_maintenance_freshness_probe"]["status"] == (
        "deferred_budget_exhausted"
    )
    assert payload["post_maintenance_freshness_probe"]["ran"] is False
    assert payload["post_maintenance_freshness_probe"][
        "current_claim_allowed"
    ] is False
    assert (
        "post_maintenance_freshness_probe_deferred_budget_exhausted"
        in payload["diagnostics"]
    )
    assert (
        payload["freshness_after"]["post_maintenance_observation"]
        == payload["post_maintenance_freshness_probe"]
    )


