    assert dense_action["result"]["completed_session_ids"] == ["dense-guard-session"]
    assert dense_action["result"]["selection"]["policy"] == (
        "cost_class_then_recent_with_oldest_fairness_v1"
    )
    assert calls["dense"][0]["dirty_only"] is True
    assert calls["dense"][0]["limit"] == 4
    assert calls["freshness"] == 2


