def test_hot_auto_maintenance_repairs_route_cache_and_advances_graph(tmp_path: Path, monkeypatch: Any) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)
    calls: dict[str, Any] = {"freshness_count": 0}

    def fake_freshness(**kwargs: Any) -> dict[str, Any]:
        calls["freshness_count"] += 1
        if calls["freshness_count"] == 1:
            return {
                "ok": False,
                "target": kwargs["target"],
                "selected_count": 1,
                "needs_index_maintenance": True,
                "needs_graph_maintenance": True,
                "diagnostics": ["search_stale", "graph_dirty"],
            }
        return {
            "ok": False,
            "target": kwargs["target"],
            "selected_count": 1,
            "needs_index_maintenance": False,
            "needs_graph_maintenance": True,
            "diagnostics": ["graph_dirty"],
        }

    def fake_maintenance(**kwargs: Any) -> dict[str, Any]:
        calls["maintenance"] = kwargs
        return {
            "ok": True,
            "apply": kwargs["apply"],
            "target": kwargs["target"],
            "selected_count": 1,
            "route_drift_count": 0,
            "deferred_session_count": 0,
            "repair_indexes": kwargs["repair_indexes"],
            "repair_graph": kwargs["repair_graph"],
            "index_repair_needed": False,
            "graph_repair_needed": True,
            "action_counts": {"applied": 2, "deferred": 1},
            "diagnostics": [],
        }

    monkeypatch.setattr(module, "route_cache_freshness_gates", fake_freshness)
    monkeypatch.setattr(module, "graph_freshness_gates", lambda **_: (_ for _ in ()).throw(AssertionError("hot profile should use route-cache freshness")))
    monkeypatch.setattr(module, "maintain_indexes", fake_maintenance)

    payload = module.auto_maintenance(workspace_root=workspace, aoa_root=aoa_root, profile="hot", apply=True)

    assert payload["ok"] is True
    assert payload["status"] == "applied_with_deferred_graph"
    assert payload["repair_indexes"] is True
    assert payload["repair_graph"] is True
    assert payload["allow_deferred_graph"] is True
    assert payload["deferred_graph_after"] is True
    assert "search_stale" in payload["preflight_diagnostics"]
    assert payload["diagnostics"] == []
    assert payload["graph_batch_limit"] == module.AUTO_MAINTENANCE_PROFILES["hot"]["graph_batch_limit"]
    assert calls["maintenance"]["repair_indexes"] is True
    assert calls["maintenance"]["repair_graph"] is True
    assert calls["maintenance"]["graph_batch_limit"] == module.AUTO_MAINTENANCE_PROFILES["hot"]["graph_batch_limit"]


def test_hot_auto_maintenance_reports_budget_remaining_backlog(tmp_path: Path, monkeypatch: Any) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)
    calls: dict[str, int] = {"freshness": 0}

    def fake_freshness(**kwargs: Any) -> dict[str, Any]:
        calls["freshness"] += 1
        return {
            "ok": False,
            "target": kwargs["target"],
            "selected_count": 7,
            "needs_index_maintenance": True,
            "needs_graph_maintenance": True,
            "diagnostics": ["index_maintenance_needed", "graph_maintenance_needed"],
        }

    def fake_maintenance(**kwargs: Any) -> dict[str, Any]:
        return {
            "ok": False,
            "apply": kwargs["apply"],
            "target": kwargs["target"],
            "selected_count": 7,
            "repair_indexes": kwargs["repair_indexes"],
            "repair_graph": kwargs["repair_graph"],
            "repair_limit": kwargs["repair_limit"],
            "budget_exhausted": True,
            "search_repair_limited": False,
            "search_repair_remaining_count": 3,
            "atlas_repair_limited": False,
            "atlas_repair_remaining_count": 0,
            "action_counts": {"applied": 1, "deferred_budget_exhausted": 2},
            "diagnostics": ["search_index_budget_exhausted"],
        }

    monkeypatch.setattr(module, "route_cache_freshness_gates", fake_freshness)
    monkeypatch.setattr(module, "maintain_indexes", fake_maintenance)

    payload = module.auto_maintenance(workspace_root=workspace, aoa_root=aoa_root, profile="hot", apply=True)

    assert payload["ok"] is True
    assert payload["status"] == "applied_with_remaining_backlog"
    assert payload["expected_remaining_backlog"] is True
    assert payload["expected_catchup_remaining"] is False
    assert payload["hard_diagnostics"] == []
    assert "search_index_budget_exhausted" in payload["diagnostics"]
    assert (
        "post_maintenance_freshness_probe_deferred_budget_exhausted"
        in payload["diagnostics"]
    )
    assert calls["freshness"] == 1
    post_probe = payload["post_maintenance_freshness_probe"]
    assert post_probe["status"] == "deferred_budget_exhausted"
    assert post_probe["ran"] is False
    assert (
        post_probe["snapshot_source"]
        == "freshness_before_conservative_fallback"
    )
    assert post_probe["budget_seconds"] == payload["budget_seconds"]
    assert (
        post_probe["maintenance_budget_seconds"]
        == payload["maintenance_budget_seconds"]
    )
    assert post_probe["preflight_elapsed_seconds"] >= 0
    assert (
        post_probe["min_seconds"]
        >= module.MAINTENANCE_FINAL_FRESHNESS_SNAPSHOT_MIN_SECONDS
    )
    assert post_probe["current_claim_allowed"] is False
    assert (
        post_probe["truth_status"]
        == "post_maintenance_currentness_not_observed"
    )
    assert (
        payload["freshness_after"]["post_maintenance_observation"]
        == payload["post_maintenance_freshness_probe"]
    )
    assert 0 < payload["maintenance_budget_seconds"] <= payload["budget_seconds"]


def test_backlog_auto_maintenance_retries_registry_source_advance_after_verified_refresh(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """A source mutation after a verified registry refresh is new work, not a terminal child failure."""
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)

    def fake_freshness(**kwargs: Any) -> dict[str, Any]:
        return {
            "ok": False,
            "target": kwargs["target"],
            "selected_count": 3,
            "needs_index_maintenance": True,
            "needs_graph_maintenance": False,
            "search_index": {
                "status": "stale",
                "has_documents": True,
                "has_route_index": True,
                "has_route_terms": True,
                "search_schema_version": str(module.SEARCH_SCHEMA_VERSION),
                "expected_search_schema_version": module.SEARCH_SCHEMA_VERSION,
                "reasons": ["session_projection_dirty"],
                "diagnostics": [],
            },
            "diagnostics": [
                "entity_registry_missing_or_stale",
                "source_newer_than_entity_registry",
            ],
        }

    def fake_maintenance(**kwargs: Any) -> dict[str, Any]:
        return {
            "ok": True,
            "apply": kwargs["apply"],
            "target": kwargs["target"],
            "selected_count": 3,
            "repair_indexes": kwargs["repair_indexes"],
            "repair_graph": kwargs["repair_graph"],
            "search_repair_limited": True,
            "search_repair_remaining_count": 1,
            "action_counts": {"applied": 4, "covered_by_search_index": 1},
            "actions": [
                {
                    "id": "refresh_entity_registry",
                    "needed": True,
                    "status": "covered_by_search_index",
                    "result": {"ok": True},
                }
            ],
            "final_entity_registry": {
                "status": "needs_maintenance",
                "needs_maintenance": True,
                "generated_at_epoch": 100.0,
                "source_surface": {"latest_source_mtime": 101.0},
                "diagnostics": ["source_newer_than_entity_registry"],
            },
            "diagnostics": [],
        }

    monkeypatch.setattr(module, "route_cache_freshness_gates", fake_freshness)
    monkeypatch.setattr(module, "graph_freshness_gates", fake_freshness)
    monkeypatch.setattr(module, "maintain_indexes", fake_maintenance)

    payload = module.auto_maintenance(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="backlog",
        apply=True,
    )

    assert payload["ok"] is True
    assert payload["status"] == "applied_with_remaining_backlog"
    assert payload["expected_remaining_backlog"] is True
    assert payload["entity_registry_concurrent_source_followup"]["eligible"] is True
    assert payload["hard_diagnostics"] == []
    assert payload["diagnostics"] == [
        "entity_registry_missing_or_stale",
        "index_maintenance_needed",
        "source_newer_than_entity_registry",
    ]


def test_backlog_auto_maintenance_retries_registry_source_advance_seen_by_post_probe(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """A post-probe source advance after a verified refresh keeps bounded work queued."""
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    aoa_root.mkdir(parents=True)
    calls = {"freshness": 0}
    initial_registry = {
        "status": "needs_maintenance",
        "needs_maintenance": True,
        "generated_at_epoch": 100.0,
        "source_surface": {"latest_source_mtime": 101.0},
        "diagnostics": ["source_newer_than_entity_registry"],
    }
    refreshed_registry = {
        "status": "current",
        "needs_maintenance": False,
        "generated_at_epoch": 200.0,
        "source_surface": {"latest_source_mtime": 199.0},
        "diagnostics": [],
    }
    post_probe_registry = {
        "status": "needs_maintenance",
        "needs_maintenance": True,
        "generated_at_epoch": 200.0,
        "source_surface": {"latest_source_mtime": 201.0},
        "diagnostics": ["source_newer_than_entity_registry"],
    }

    def fake_freshness(**kwargs: Any) -> dict[str, Any]:
        calls["freshness"] += 1
        registry = initial_registry if calls["freshness"] == 1 else post_probe_registry
        return {
            "ok": False,
            "target": kwargs["target"],
            "selected_count": 3,
            "needs_index_maintenance": True,
            "needs_graph_maintenance": False,
            "search_index": {
                "status": "stale",
                "has_documents": True,
                "has_route_index": True,
                "has_route_terms": True,
                "search_schema_version": str(module.SEARCH_SCHEMA_VERSION),
                "expected_search_schema_version": module.SEARCH_SCHEMA_VERSION,
                "reasons": ["session_projection_dirty"],
                "diagnostics": [],
            },
            "entity_registry": registry,
            "diagnostics": [
                "entity_registry_missing_or_stale",
                "source_newer_than_entity_registry",
            ],
        }

    def fake_maintenance(**kwargs: Any) -> dict[str, Any]:
        return {
            "ok": True,
            "apply": kwargs["apply"],
            "target": kwargs["target"],
            "selected_count": 3,
            "repair_indexes": kwargs["repair_indexes"],
            "repair_graph": kwargs["repair_graph"],
            "search_repair_limited": True,
            "search_repair_remaining_count": 2,
            "action_counts": {"applied": 4, "covered_by_search_index": 1},
            "actions": [
                {
                    "id": "refresh_entity_registry",
                    "needed": True,
                    "status": "covered_by_search_index",
                    "result": {"ok": True},
                }
            ],
            "entity_registry": initial_registry,
            "final_entity_registry": refreshed_registry,
            "diagnostics": [],
        }

    monkeypatch.setattr(module, "graph_freshness_gates", fake_freshness)
    monkeypatch.setattr(module, "maintain_indexes", fake_maintenance)

    payload = module.auto_maintenance(
        workspace_root=workspace,
        aoa_root=aoa_root,
        profile="backlog",
        apply=True,
    )

    assert calls["freshness"] == 2
    assert payload["ok"] is True
    assert payload["status"] == "applied_with_remaining_backlog"
    assert payload["expected_remaining_backlog"] is True
    followup = payload["entity_registry_concurrent_source_followup"]
    assert followup["eligible"] is True
    assert followup["eligibility_basis"] == "verified_refresh"
    assert followup["registry_observation_source"] == "post_freshness_probe"
    assert payload["hard_diagnostics"] == []


