def test_search_index_routes_queries_to_evidence_refs_and_freshness(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-search-index.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "search-index-session", "cwd": str(workspace)}},
            {
                "timestamp": "2026-05-12T00:00:01Z",
                "type": "response_item",
                "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Важная мысль: имена должны держать мост-якорь"}]},
            },
            {
                "timestamp": "2026-05-12T00:00:02Z",
                "type": "response_item",
                "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Ты не понял, имена слишком общие"}]},
            },
            {
                "timestamp": "2026-05-12T00:00:03Z",
                "type": "response_item",
                "payload": {"type": "function_call", "name": "exec_command", "call_id": "call-hook", "arguments": json.dumps({"cmd": "pytest -q"})},
            },
            {
                "timestamp": "2026-05-12T00:00:04Z",
                "type": "response_item",
                "payload": {"type": "function_call_output", "call_id": "call-hook", "output": "Stop hook failed: error: hook timed out after 20s"},
            },
            {
                "timestamp": "2026-05-12T00:00:05Z",
                "type": "response_item",
                "payload": {
                    "type": "message",
                    "role": "assistant",
                    "content": [
                            {
                                "type": "output_text",
                                "text": "План: сверю search-index по raw refs " + ("длинный-контекст " * 45) + "compressed_body_tail_anchor",
                            }
                    ],
                },
            },
        ],
    )

    module.handle_hook_event(
        "Stop",
        {
            "session_id": "search-index-session",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    missing = tmp_path / "missing.jsonl"
    module.handle_hook_event(
        "SessionStart",
        {
            "session_id": "raw-missing-session",
            "transcript_path": str(missing),
            "cwd": str(workspace),
            "hook_event_name": "SessionStart",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    bounded_indexed = module.search_index_sessions(aoa_root=aoa_root, target="all", max_raw_bytes=1)
    assert bounded_indexed["ok"] is True
    assert bounded_indexed["max_raw_bytes"] == 1
    assert bounded_indexed["event_document_count"] == 6
    assert any(item.get("raw_text_status") == "skipped_raw_too_large" for item in bounded_indexed["sessions"])

    indexed = module.search_index_sessions(aoa_root=aoa_root, target="all", write_report=True)

    assert indexed["ok"] is True
    assert indexed["max_raw_bytes"] == module.SEARCH_RAW_LEXICAL_DEFAULT_MAX_BYTES
    assert indexed["raw_lexical_policy"]["mode"] == module.SEARCH_RAW_LEXICAL_POLICY_MODE
    assert indexed["raw_lexical_policy"]["source"] == "default"
    assert indexed["raw_text_status_counts"]["available"] >= 1
    assert indexed["inline_optimize_policy"]["rebuild_every"] == 0
    assert indexed["inline_optimize_policy"]["incremental_every"] == module.SEARCH_INCREMENTAL_INLINE_OPTIMIZE_EVERY
    assert indexed["inline_optimize_count"] == 0
    assert indexed["search_catalog"]["status"] == "current"
    assert indexed["search_catalog"]["active_projection"] == module.SEARCH_ACTIVE_PROJECTION_MONOLITH
    assert indexed["search_catalog"]["shard_strategy"] == module.SEARCH_SHARD_STRATEGY
    phase_names = {item.get("phase") for item in indexed["phase_timings"]}
    assert {"session_bulk_index", "sqlite_index_build", "entity_registry_refresh"}.issubset(phase_names)
    assert indexed["session_document_count"] == 2
    assert indexed["event_document_count"] == 6
    assert indexed["incident_document_count"] >= 1
    assert Path(indexed["db_path"]).exists()
    assert module.search_catalog_path(aoa_root).exists()
    assert Path(indexed["report_json"]).exists()
    catalog = module.read_search_catalog(aoa_root)
    assert catalog["ok"] is True
    assert catalog["status"] == "current"
    assert catalog["active_projection"] == module.SEARCH_ACTIVE_PROJECTION_MONOLITH
    assert catalog["shard_strategy"] == module.SEARCH_SHARD_STRATEGY
    assert catalog["session_count"] == 2
    assert any(item.get("shard") == "month/2026-05" for item in catalog["sessions"])
    search_session_catalog = next(item for item in catalog["sessions"] if item.get("session_id") == "search-index-session")
    assert search_session_catalog["schema_versions"]["search_schema_version"] == str(module.SEARCH_SCHEMA_VERSION)
    assert search_session_catalog["freshness"]["status"] == "current"
    conn = sqlite3.connect(str(module.search_db_path(aoa_root)))
    body_meta = conn.execute("SELECT value FROM meta WHERE key = ?", ("search_body_storage_mode",)).fetchone()[0]
    payload_meta = conn.execute("SELECT value FROM meta WHERE key = ?", ("search_payload_storage_mode",)).fetchone()[0]
    index_profile_meta = conn.execute("SELECT value FROM meta WHERE key = ?", ("search_index_profile",)).fetchone()[0]
    ref_path_policy_meta = conn.execute("SELECT value FROM meta WHERE key = ?", ("search_ref_path_storage_policy",)).fetchone()[0]
    lexical_policy_meta = conn.execute("SELECT value FROM meta WHERE key = ?", ("search_raw_lexical_policy_mode",)).fetchone()[0]
    lexical_max_meta = conn.execute("SELECT value FROM meta WHERE key = ?", ("search_raw_lexical_max_bytes",)).fetchone()[0]
    preview_len, compressed_count = conn.execute(
        "SELECT MAX(LENGTH(body)), COUNT(*) FROM documents JOIN document_bodies ON document_bodies.doc_rowid = documents.rowid"
    ).fetchone()
    route_preview_len, payload_len = conn.execute("SELECT MAX(LENGTH(route_signals)), MAX(LENGTH(payload_json)) FROM documents").fetchone()
    script_registry_payload = json.loads(
        conn.execute(
            "SELECT payload_json FROM documents WHERE id = ?",
            ("entity_registry:tool:search_operational_direct_event_rollup_query",),
        ).fetchone()[0]
    )
    raw_unavailable_state = conn.execute(
        "SELECT status, reason FROM search_freshness_state WHERE session_id = ?",
        ("raw-missing-session",),
    ).fetchone()
    conn.close()
    assert body_meta == module.SEARCH_BODY_STORAGE_MODE
    assert payload_meta == module.SEARCH_PAYLOAD_STORAGE_MODE
    assert index_profile_meta == module.SEARCH_INDEX_PROFILE
    assert ref_path_policy_meta == module.SEARCH_REF_PATH_STORAGE_POLICY_DERIVED
    assert lexical_policy_meta == module.SEARCH_RAW_LEXICAL_POLICY_MODE
    assert lexical_max_meta == str(module.SEARCH_RAW_LEXICAL_DEFAULT_MAX_BYTES)
    assert preview_len <= module.SEARCH_BODY_PREVIEW_CHARS
    assert route_preview_len <= module.SEARCH_ROUTE_SIGNALS_PREVIEW_CHARS
    assert payload_len < 1000
    assert script_registry_payload["entity_registry"]["source_refs_sample"][0]["path"] == (
        "scripts/aoa_session_memory.py"
    )
    assert compressed_count == indexed["document_count"]
    assert raw_unavailable_state == ("current", "indexed")

    hook_results = module.search_sessions(aoa_root=aoa_root, query="hook timed out", explain=True)
    assert hook_results["ok"] is True
    assert hook_results["result_count"] >= 1
    hook_hit = hook_results["results"][0]
    assert hook_hit["doc_type"] == "event"
    assert hook_hit["refs"]["raw"] == "raw:line:5"
    assert hook_hit["refs"]["segment"]
    assert hook_hit["refs"]["segment_index"]
    assert Path(hook_hit["refs"]["segment_index"]).exists()
    assert hook_hit["refs"]["raw_block"] == "raw/blocks/000__initial-to-latest.raw.jsonl"
    assert hook_hit["search_catalog"]["shard"] == "month/2026-05"
    assert hook_hit["search_catalog"]["active_projection"] == module.SEARCH_ACTIVE_PROJECTION_MONOLITH
    assert hook_hit["freshness"]["status"] == "fresh"
    assert hook_hit["explain"]["why_this_is_not_authority"]
    conn = sqlite3.connect(str(module.search_db_path(aoa_root)))
    hot_ref_row = conn.execute("SELECT raw_path, segment_index_path FROM documents WHERE id = ?", (hook_hit["doc_id"],)).fetchone()
    conn.close()
    assert hot_ref_row == ("", "")

    tail_results = module.search_sessions(aoa_root=aoa_root, query="compressed_body_tail_anchor", explain=True)
    assert tail_results["ok"] is True
    assert tail_results["result_count"] >= 1

    correction_results = module.search_sessions(
        aoa_root=aoa_root,
        query="имена общие",
        conversation_act="operator_correction",
        explain=True,
    )
    assert correction_results["result_count"] == 1
    assert correction_results["results"][0]["conversation_act"] == "operator_correction"
    assert correction_results["results"][0]["refs"]["raw"] == "raw:line:3"

    raw_unavailable = module.search_sessions(aoa_root=aoa_root, query="raw unavailable", archive_status="raw_unavailable")
    assert raw_unavailable["result_count"] >= 1
    assert raw_unavailable["results"][0]["archive_status"] == "raw_unavailable"

    session_dir = aoa_root / "sessions" / "2026-05-12__001__важная-мысль-имена-должны-держать-мост-якорь"
    index_path = session_dir / "segments" / "000__initial-to-latest.index.json"
    broken = json.loads(index_path.read_text(encoding="utf-8"))
    broken["stale_marker"] = True
    index_path.write_text(json.dumps(broken, ensure_ascii=False), encoding="utf-8")

    stale_results = module.search_sessions(aoa_root=aoa_root, query="hook timed out", explain=True)
    assert stale_results["results"][0]["freshness"]["status"] == "stale"
    assert "segment_index_sha_mismatch" in stale_results["results"][0]["freshness"]["reasons"]

    fresh_filler_index = tmp_path / "fresh-filler.index.json"
    fresh_filler_index.write_text(json.dumps({"status": "fresh"}) + "\n", encoding="utf-8")
    fresh_filler_sha = module.sha256_file(fresh_filler_index)
    conn = sqlite3.connect(str(module.search_db_path(aoa_root)))
    conn.row_factory = sqlite3.Row
    try:
        source_row = conn.execute(
            "SELECT * FROM documents WHERE body LIKE ? ORDER BY rowid DESC LIMIT 1",
            ("%hook timed out%",),
        ).fetchone()
        assert source_row is not None
        columns = [str(row["name"]) for row in conn.execute("PRAGMA table_info(documents)").fetchall()]
        insert_columns = [column for column in columns if column != "rowid"]
        placeholders = ", ".join("?" for _ in insert_columns)
        column_sql = ", ".join(insert_columns)
        for index in range(205):
            body = f"hook timed out fresh filler {index}"
            row_payload = {column: source_row[column] for column in insert_columns}
            row_payload.update(
                {
                    "id": f"fresh-filler-{index}",
                    "session_id": "fresh-filler-session",
                    "session_label": f"9999-12-31__{index:03d}__fresh-filler",
                    "session_title": "fresh filler",
                    "session_date": "9999-12-31",
                    "segment_index_path": str(fresh_filler_index),
                    "segment_index_sha256": fresh_filler_sha,
                    "freshness_status": "current",
                    "stale_reason": "",
                    "title": body,
                    "body": body,
                    "payload_json": "{}",
                }
            )
            cursor = conn.execute(
                f"INSERT INTO documents ({column_sql}) VALUES ({placeholders})",
                [row_payload[column] for column in insert_columns],
            )
            rowid = int(cursor.lastrowid)
            conn.execute(
                "INSERT INTO documents_fts(rowid, title, body, session_label, session_title) VALUES (?, ?, ?, ?, ?)",
                (rowid, body, body, row_payload["session_label"], row_payload["session_title"]),
            )
            body_bytes = body.encode("utf-8")
            conn.execute(
                "INSERT OR REPLACE INTO document_bodies(doc_rowid, body_zlib, body_sha256, body_chars) VALUES (?, ?, ?, ?)",
                (
                    rowid,
                    sqlite3.Binary(module.zlib.compress(body_bytes, level=6)),
                    module.hashlib.sha256(body_bytes).hexdigest(),
                    len(body),
                ),
            )
        conn.commit()
    finally:
        conn.close()

    live_stale_filtered = module.search_sessions(
        aoa_root=aoa_root,
        query="hook timed out",
        freshness_status="stale",
        explain=True,
    )
    assert live_stale_filtered["result_count"] >= 1
    assert live_stale_filtered["results"][0]["freshness"]["status"] == "stale"
    assert "segment_index_sha_mismatch" in live_stale_filtered["results"][0]["freshness"]["reasons"]
    assert "freshness_status_filter_applied_after_live_check:stale" in live_stale_filtered["diagnostics"]
    candidate_count = next(
        int(item.split(":", 1)[1])
        for item in live_stale_filtered["diagnostics"]
        if item.startswith("freshness_status_candidate_count:")
    )
    assert candidate_count > 200


def test_literal_query_plan_keeps_exact_literals_ahead_of_generic_embedded_entities(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    aoa_root = tmp_path / ".aoa"
    empty_codex_home = tmp_path / "empty-codex-home"
    empty_mcp_services_root = tmp_path / "empty-mcp-services"
    empty_codex_home.mkdir()
    empty_mcp_services_root.mkdir()
    monkeypatch.setenv("CODEX_HOME", str(empty_codex_home))
    monkeypatch.setenv("AOA_ENTITY_REGISTRY_MCP_SERVICES_ROOTS", str(empty_mcp_services_root))

    entries = [
        {
            "entity_id": f"{kind}:{key}",
            "kind": kind,
            "canonical_key": key,
            "aliases": aliases,
            "status": "active",
            "source_surface": "manual_exact_literal_regression_fixture",
            "source_refs": [],
        }
        for kind, key, aliases in (
            ("owner_route", "tests", ["tests"]),
            ("skill", "index", ["index"]),
            ("playbook", "source", ["source"]),
            ("skill", "aoa_decision", ["aoa-decision"]),
            ("tool", "search_hotset_audit", ["search-hotset-audit"]),
        )
    ]
    write_json(
        aoa_root / module.ENTITY_REGISTRY_PATH,
        {
            "schema_version": module.ENTITY_REGISTRY_SCHEMA_VERSION,
            "artifact_type": "entity_registry_snapshot",
            "generated_at": "2999-01-01T00:00:00Z",
            "generated_at_epoch": 32472144000.0,
            "ok": True,
            "aoa_root": str(aoa_root),
            "registry_path": str(aoa_root / module.ENTITY_REGISTRY_PATH),
            "source_surfaces": ["manual_exact_literal_regression_fixture"],
            "counts_by_kind": {},
            "counts_by_status": {"active": len(entries)},
            "entries": entries,
        },
    )

    generic_collisions = (
        ("7 tests / 72 subtests", "tests"),
        ("cf7102e Index reviewed live dispatch smoke", "index"),
        ("source_record_restored -> historical_raw", "source"),
    )
    for query, rejected_anchor in generic_collisions:
        plan = module.literal_query_plan(aoa_root=aoa_root, query=query)

        assert plan["query_shape"]["primary"] == "exact_phrase"
        assert plan["route_anchor_source"] == "query"
        assert plan["route_anchor"] == query
        assert plan["primary_route"]["route_id"] != "entity_usage_chain"
        suppressed = plan["query_shape"]["suppressed_embedded_entity_anchor"]
        assert suppressed["anchor"] == rejected_anchor
        assert suppressed["suppression_reason"] == "generic_single_term_inside_exact_phrase"
        assert plan["classifications"]["suppressed_embedded_entity_anchor"] is True

    explicit_usage = module.literal_query_plan(
        aoa_root=aoa_root,
        query="как агент использовал aoa-decision",
    )
    exact_entity = module.literal_query_plan(
        aoa_root=aoa_root,
        query="search-hotset-audit",
    )

    assert explicit_usage["route_anchor_source"] == "embedded_entity_registry"
    assert explicit_usage["route_anchor"] == "aoa_decision"
    assert explicit_usage["primary_route"]["route_id"] == "entity_usage_chain"
    assert exact_entity["route_anchor_source"] == "embedded_entity_registry"
    assert exact_entity["route_anchor"] == "search_hotset_audit"
    assert exact_entity["primary_route"]["route_id"] == "entity_usage_chain"


def test_compositional_episode_query_suppresses_ambiguous_embedded_entity_alias(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """Regression derived from randomized manual wave seed 2026071701."""

    aoa_root = tmp_path / ".aoa"
    registry = {
        "entries": [
            {
                "entity_id": "mcp_service:project_alpha_memory_mcp",
                "kind": "mcp_service",
                "canonical_key": "project_alpha_memory_mcp",
                "aliases": [
                    "project-alpha",
                    "project_alpha",
                    "project-alpha-memory-mcp",
                ],
                "status": "active",
                "source_surface": "synthetic_owner_neutral_collision_fixture",
                "source_refs": [],
            },
            {
                "entity_id": "technique:review",
                "kind": "technique",
                "canonical_key": "review",
                "aliases": ["review"],
                "status": "observed",
                "source_surface": "synthetic_owner_neutral_collision_fixture",
                "source_refs": [],
            },
        ]
    }

    def load_registry(_aoa_root: Path, **_kwargs: Any) -> dict[str, Any]:
        return registry

    monkeypatch.setattr(module, "load_entity_registry", load_registry)

    alias_collision_query = (
        "Какой порядок рефакторинга project-alpha задал пользователь, "
        "что проверили первым, и был ли будущий MCP уже подключён?"
    )
    generic_collision_query = (
        "During adversarial review which skills were read, "
        "what skill-usage diff was inspected, and was completion proven?"
    )
    alias_collision = module.literal_query_plan(
        aoa_root=aoa_root,
        query=alias_collision_query,
        session="session-alpha",
        date_from="2026-07-10",
        date_to="2026-07-10",
        time_from="2026-07-10T22:08:15Z",
        time_to="2026-07-10T22:09:00Z",
    )
    generic_collision = module.literal_query_plan(
        aoa_root=aoa_root,
        query=generic_collision_query,
        session="session-beta",
        date_from="2026-07-11",
        date_to="2026-07-11",
        time_from="2026-07-11T04:31:05Z",
        time_to="2026-07-11T04:32:26Z",
    )
    generic_memory_plan = module.memory_query_plan(
        aoa_root=aoa_root,
        query=generic_collision_query,
        session="synthetic-session",
        time_from="2026-07-11T04:31:05Z",
        time_to="2026-07-11T04:32:26Z",
    )
    canonical_entity = module.literal_query_plan(
        aoa_root=aoa_root,
        query="как агент использовал project-alpha-memory-mcp и к чему это привело",
    )
    adjacent_kind_identity = module.literal_query_plan(
        aoa_root=aoa_root,
        query="how was project-alpha-memory MCP used and what failed",
    )

    for plan, suppressed_anchor, suppression_reason in (
        (
            alias_collision,
            "project_alpha_memory_mcp",
            "compositional_query_ambiguous_entity_alias",
        ),
        (
            generic_collision,
            "review",
            "compositional_query_generic_entity",
        ),
    ):
        assert plan["query_shape"]["compositional_human_query"] is True
        assert plan["query_shape"]["primary"] == "human_phrase"
        assert plan["route_anchor_source"] == "query"
        assert plan["embedded_entity_anchor"] == {}
        suppressed = plan["query_shape"]["suppressed_embedded_entity_anchor"]
        assert suppressed["anchor"] == suppressed_anchor
        assert suppressed["suppression_reason"] == suppression_reason
        assert plan["structured_route_signal_candidates"] == []
        assert plan["primary_route"]["route_id"] == "episode_semantic_search"
        assert " episode-search " in plan["primary_route"]["command"]
        assert "--session session-" in plan["primary_route"]["command"]
        assert "--date-from 2026-07-" in plan["primary_route"]["command"]
        assert "--date-to 2026-07-" in plan["primary_route"]["command"]
        assert "--time-from 2026-07-" in plan["primary_route"]["command"]
        assert "--time-to 2026-07-" in plan["primary_route"]["command"]

    assert generic_memory_plan["primary_route"]["route_id"] == "episode_semantic_search"
    assert "--time-from 2026-07-11T04:31:05Z" in generic_memory_plan["next_command"]
    assert "--time-to 2026-07-11T04:32:26Z" in generic_memory_plan["next_command"]
    assert generic_memory_plan["literal_subplan"]["route_anchor"] == generic_collision_query
    assert canonical_entity["route_anchor_source"] == "embedded_entity_registry"
    assert canonical_entity["route_anchor"] == "project_alpha_memory_mcp"
    assert canonical_entity["primary_route"]["route_id"] == "entity_usage_chain"
    assert adjacent_kind_identity["query_shape"]["compositional_human_query"] is True
    assert adjacent_kind_identity["route_anchor_source"] == "embedded_entity_registry"
    assert adjacent_kind_identity["route_anchor"] == "project_alpha_memory_mcp"
    assert adjacent_kind_identity["primary_route"]["route_id"] == "entity_usage_chain"


