def test_literal_query_shape_distinguishes_structured_identifiers_from_exact_phrases() -> None:
    call_id = "call_MiXeD9A7b6C5d4E3"
    function_call_id = "fc_05f76e09575cce29016a438db9602c81"
    actions_job_id = "12345678901/job/98765432109"
    actions_job_url = (
        "https://github.com/example/project/actions/runs/"
        "12345678901/job/98765432109"
    )

    call_shape = module.literal_query_shape(call_id)
    function_call_shape = module.literal_query_shape(function_call_id)
    actions_job_shape = module.literal_query_shape(actions_job_id)
    actions_job_url_shape = module.literal_query_shape(actions_job_url)
    entity_shape = module.literal_query_shape("aoa_session_memory")
    hyphenated_label_shape = module.literal_query_shape("run-book-2026")
    path_collision_shape = module.literal_query_shape(
        "reports/12345678901/job/98765432109.txt"
    )
    project_record_path_shape = module.literal_query_shape("reports/F-0012.md")

    assert call_shape["primary"] == module.LITERAL_QUERY_KIND_IDENTIFIER
    assert call_shape["signals"] == [module.LITERAL_QUERY_KIND_IDENTIFIER]
    assert call_shape["identifier_anchor"] == call_id
    assert function_call_shape["primary"] == module.LITERAL_QUERY_KIND_IDENTIFIER
    assert function_call_shape["identifier_anchor"] == function_call_id
    assert actions_job_shape["primary"] == module.LITERAL_QUERY_KIND_IDENTIFIER
    assert actions_job_shape["signals"] == [module.LITERAL_QUERY_KIND_IDENTIFIER]
    assert actions_job_shape["identifier_anchor"] == actions_job_id
    assert actions_job_shape["path_anchor"] == ""
    assert actions_job_url_shape["primary"] == module.LITERAL_QUERY_KIND_IDENTIFIER
    assert actions_job_url_shape["identifier_anchor"] == actions_job_url
    assert actions_job_url_shape["path_anchor"] == ""
    assert entity_shape["primary"] == module.LITERAL_QUERY_KIND_ENTITY_ANCHOR
    assert entity_shape["identifier_anchor"] == ""
    assert hyphenated_label_shape["primary"] == module.LITERAL_QUERY_KIND_EXACT_PHRASE
    assert hyphenated_label_shape["identifier_anchor"] == ""
    assert path_collision_shape["primary"] == module.LITERAL_QUERY_KIND_PATH
    assert path_collision_shape["identifier_anchor"] == ""
    assert project_record_path_shape["primary"] == module.LITERAL_QUERY_KIND_PATH
    assert project_record_path_shape["identifier_anchor"] == ""


def test_literal_query_embedded_project_record_identifier_anchors_context_ranking(
    tmp_path: Path,
) -> None:
    query = (
        "Which failed change said R-0042 still needed owner approval "
        "and post-land parity?"
    )

    shape = module.literal_query_shape(query)
    plan = module.exact_literal_fts_query_plan_from_user(query)
    aoa_root = tmp_path / ".aoa"
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)
    conn.close()
    route_plan = module.literal_query_plan(aoa_root=aoa_root, query=query)

    assert shape["primary"] == module.LITERAL_QUERY_KIND_IDENTIFIER
    assert shape["identifier_anchor"] == "R-0042"
    assert plan["mode"] == "identifier_context_or_rank"
    assert plan["anchor_type"] == "project_record_identifier"
    assert route_plan["route_anchor"] == "R-0042"
    assert route_plan["route_anchor_source"] == "identifier_anchor"
    assert route_plan["exact_recall_query"] == "R-0042"
    fallback_command = shlex.split(route_plan["fallback_plan"]["command"])
    assert fallback_command[fallback_command.index("--query") + 1] == "R-0042"

    ranking_conn = sqlite3.connect(":memory:")
    ranking_conn.execute("CREATE VIRTUAL TABLE exact_rows USING fts5(text)")
    ranking_conn.executemany(
        "INSERT INTO exact_rows(rowid, text) VALUES (?, ?)",
        [
            (1, "R-0042 appeared in a routine inventory."),
            (
                2,
                "apply_patch verification failed: R-0042 remains open; "
                "owner approval and post-land parity are still needed.",
            ),
            (3, "R-0042 change failed without owner or parity context."),
        ],
    )
    rows = ranking_conn.execute(
        "SELECT rowid FROM exact_rows WHERE exact_rows MATCH ? "
        "ORDER BY bm25(exact_rows), rowid",
        (plan["fts_query"],),
    ).fetchall()
    ranking_conn.close()

    assert rows
    assert rows[0][0] == 2


def test_literal_query_plan_keeps_external_job_identifier_off_path_usage_and_graph_routes(
    tmp_path: Path,
) -> None:
    aoa_root = tmp_path / ".aoa"
    query = "12345678901/job/98765432109"
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)
    conn.close()

    plan = module.literal_query_plan(
        aoa_root=aoa_root,
        query=query,
        session="gold-session",
    )
    exact_plan = module.exact_literal_fts_query_plan_from_user(query)
    commit_plan = module.exact_literal_fts_query_plan_from_user(
        "cf7102e Index reviewed live dispatch smoke"
    )
    route_ids = [route["route_id"] for route in plan["ordered_routes"]]

    assert plan["query_shape"]["primary"] == module.LITERAL_QUERY_KIND_IDENTIFIER
    assert plan["query_shape"]["path_anchor"] == ""
    assert plan["route_anchor"] == query
    assert plan["route_anchor_source"] == "identifier_anchor"
    assert plan["route_anchor_kind"] == "external"
    assert all(
        route_id
        not in {
            "route_signal_structured_search",
            "entity_usage_chain",
            "entity_usage_audit",
            "trace_route",
            "graph_neighborhood",
        }
        for route_id in route_ids
    )
    assert exact_plan["mode"] == "ordered_token_phrase"
    assert exact_plan["anchor_type"] == ""
    assert commit_plan["mode"] == "identifier_subject_near_16"
    assert commit_plan["anchor_type"] == "git_commit_identifier"


def test_literal_query_plan_routes_structurally_flagged_ps_command_without_allowlist(
    tmp_path: Path,
) -> None:
    aoa_root = tmp_path / ".aoa"
    query = "ps -p 765901 -o pid,stat,etime,pcpu,pmem,rss,args"
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)
    conn.close()

    plan = module.literal_query_plan(
        aoa_root=aoa_root,
        query=query,
        session="gold-session",
    )

    assert plan["query_shape"]["primary"] == "command"
    assert plan["query_shape"]["command_anchor"] == "ps"
    assert plan["route_anchor"] == "ps"
    assert plan["route_anchor_source"] == "command_anchor"
    assert plan["literal_route_strategy"]["query_class"] == "command"
    assert module.literal_query_shape("use --force only with --review")["primary"] != "command"
    assert module.literal_query_shape("проверь --force и --review")["primary"] != "command"


def test_literal_session_id_keeps_rehydrate_first_when_live_tail_is_deferred(
    tmp_path: Path,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    session_id = "31313131-4242-4535-8646-575757575757"
    transcript = tmp_path / "rollout-2026-06-11T00-00-00-live-session-id.jsonl"
    write_jsonl(
        transcript,
        [
            {
                "timestamp": "2026-06-11T00:00:00Z",
                "type": "session_meta",
                "payload": {"id": session_id, "cwd": str(workspace)},
            },
            {
                "timestamp": "2026-06-11T00:00:01Z",
                "type": "response_item",
                "payload": {
                    "type": "message",
                    "role": "user",
                    "content": [{"type": "input_text", "text": "initial archived intent"}],
                },
            },
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": session_id,
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    module.search_index_sessions(aoa_root=aoa_root, target="all")
    with transcript.open("a", encoding="utf-8") as handle:
        handle.write(
            json.dumps(
                {
                    "timestamp": "2026-06-11T00:00:02Z",
                    "type": "response_item",
                    "payload": {
                        "type": "message",
                        "role": "user",
                        "content": [{"type": "input_text", "text": "unarchived live continuation"}],
                    },
                }
            )
            + "\n"
        )

    plan = module.literal_query_plan(
        aoa_root=aoa_root,
        query=session_id,
    )
    route_ids = [str(item.get("route_id") or "") for item in plan["ordered_routes"]]

    assert plan["query_shape"]["primary"] == "session_id"
    assert (
        plan["search_projection"]["exact_literal_postings"]["scope_status"]
        == "scope_deferred_live"
    )
    assert plan["primary_route"]["route_id"] == "session_rehydrate"
    assert route_ids[:2] == ["session_rehydrate", "session_structured_search"]
    assert "live_tail_exact_fallback" not in route_ids
    assert "freshness_diagnostic" not in route_ids


