def test_archived_session_exact_fallback_preserves_retrieval_call_correlation_evidence(
    tmp_path: Path,
) -> None:
    """Regression from the manually adjudicated W1 MCP-to-writeback span."""
    workspace = tmp_path / "AbyssOS"
