def test_exact_literal_postings_compact_long_patch_transitions_without_cross_key_correlation(
    tmp_path: Path,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    session_id = "23232323-3434-4545-8666-777777777777"
    transcript = tmp_path / "rollout-2026-06-11T00-00-00-long-patch-transition.jsonl"
    prefix = "\n".join(f" unchanged prefix line {index:03d}" for index in range(130))
    suffix = "\n".join(f" unchanged suffix line {index:03d}" for index in range(130))
    patch_input = (
        "*** Begin Patch\n"
        "*** Update File: /workspace/project/routes.json\n"
        "@@\n"
        " HEAD_ANCHOR_KEEP_7D1\n"
        f"{prefix}\n"
        '-      "status": "source_record_restored"\n'
        '+      "status": "historical_raw"\n'
        '-      "old_status": "foreign_old"\n'
        '+      "new_status": "foreign_new"\n'
        f"{suffix}\n"
        "*** End Patch\n"
    )
    assert patch_input.find("source_record_restored") > module.SEARCH_EXACT_LITERAL_POSTINGS_MAX_CHARS
    assert patch_input.rfind("historical_raw") < len(patch_input) - module.SEARCH_EXACT_LITERAL_POSTINGS_MAX_CHARS // 2
    write_jsonl(
        transcript,
        [
            {
                "timestamp": "2026-06-11T00:00:00Z",
                "type": "session_meta",
                "payload": {"id": session_id, "cwd": str(workspace)},
            },
            {
                "timestamp": "2026-06-11T00:00:01Z",
                "type": "response_item",
                "payload": {
                    "type": "custom_tool_call",
                    "name": "apply_patch",
                    "call_id": "call-long-patch-transition",
                    "input": patch_input,
                },
            },
            {
                "timestamp": "2026-06-11T00:00:02Z",
                "type": "response_item",
                "payload": {
                    "type": "custom_tool_call_output",
                    "call_id": "call-long-patch-transition",
                    "output": "Exit code: 0\nOutput:\nSuccess. Updated routes.json\n",
                },
            },
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": session_id,
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    (aoa_root / "sessions" / session_id).mkdir(parents=True, exist_ok=True)
    indexed = module.search_index_sessions(aoa_root=aoa_root, target="all")

    transition = module.search_sessions(
        aoa_root=aoa_root,
        query="source_record_restored -> historical_raw",
        session=session_id,
        limit=5,
        literal_postings_only=True,
    )
    preserved_head = module.search_sessions(
        aoa_root=aoa_root,
        query="HEAD_ANCHOR_KEEP_7D1",
        session=session_id,
        limit=5,
        literal_postings_only=True,
    )
    rejected_cross_key = module.search_sessions(
        aoa_root=aoa_root,
        query="foreign_old -> foreign_new",
        session=session_id,
        limit=5,
        literal_postings_only=True,
    )

    assert indexed["ok"] is True
    assert transition["result_count"] == 1
    assert transition["results"][0]["raw_ref"] == "raw:line:2"
    assert transition["results"][0]["match_channel"] == "exact_literal_transition_postings"
    assert transition["cost_profile"]["literal_postings_query_mode"] == "patch_transition_phrase"
    assert transition["cost_profile"]["literal_postings_anchor_type"] == "same_field_patch_transition"
    assert preserved_head["result_count"] == 1
    assert preserved_head["results"][0]["raw_ref"] == "raw:line:2"
    assert preserved_head["results"][0]["match_channel"] == "exact_literal_postings"
    assert rejected_cross_key["result_count"] == 0
    with sqlite3.connect(indexed["db_path"]) as conn:
        assert conn.execute("SELECT MAX(text_chars) FROM exact_literal_posting_meta").fetchone()[0] <= 2400
        assert (
            conn.execute("SELECT MAX(text_chars) FROM exact_literal_transition_posting_meta").fetchone()[0]
            <= 600
        )


