def test_search_shard_dirty_selection_skips_deferred_live_by_default(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    module.write_json(
        module.search_catalog_path(aoa_root),
        {
            "schema_version": module.SCHEMA_VERSION,
            "artifact_type": "session_memory_search_catalog",
            "ok": True,
            "sessions": [
                {
                    "session_id": "current-session",
                    "session_label": "2026-06-01__001__current",
                    "shard": "month/2026-06",
                    "shard_status": "current",
                    "shard_materialized": True,
                    "freshness": {"status": "current"},
                },
                {
                    "session_id": "deferred-session",
                    "session_label": "2026-06-02__001__deferred",
                    "shard": "month/2026-06",
                    "shard_status": "stale",
                    "shard_materialized": False,
                    "freshness": {"status": "deferred_live"},
                },
                {
                    "session_id": "stale-session",
                    "session_label": "2026-06-03__001__stale",
                    "shard": "month/2026-06",
                    "shard_status": "stale",
                    "shard_materialized": False,
                    "freshness": {"status": "current"},
                },
            ],
        },
    )
    records = [
        {"session_id": "current-session", "session_label": "2026-06-01__001__current"},
        {"session_id": "deferred-session", "session_label": "2026-06-02__001__deferred"},
        {"session_id": "stale-session", "session_label": "2026-06-03__001__stale"},
    ]

    selected, stats = module.filter_search_records_to_dirty_shard_sessions(
        aoa_root,
        records,
        shard="month/2026-06",
    )

    assert [item["session_id"] for item in selected] == ["stale-session"]
    assert stats["dirty_candidate_count"] == 1
    assert stats["dirty_selected_count"] == 1
    assert stats["selection_order"] == "catalog_document_count_asc"
    assert stats["deferred_live_skipped_count"] == 1
    assert stats["skipped_current_count"] == 1

    selected_with_deferred, stats_with_deferred = module.filter_search_records_to_dirty_shard_sessions(
        aoa_root,
        records,
        shard="month/2026-06",
        include_deferred_live=True,
    )

    assert [item["session_id"] for item in selected_with_deferred] == ["deferred-session", "stale-session"]
    assert stats_with_deferred["dirty_candidate_count"] == 2
    assert stats_with_deferred["deferred_live_skipped_count"] == 0


def test_search_shard_dirty_selection_prioritizes_small_catalog_rows(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    module.write_json(
        module.search_catalog_path(aoa_root),
        {
            "schema_version": module.SCHEMA_VERSION,
            "artifact_type": "session_memory_search_catalog",
            "ok": True,
            "sessions": [
                {
                    "session_id": "heavy-session",
                    "session_label": "2026-06-13__003__heavy",
                    "shard": "month/2026-06",
                    "shard_status": "stale",
                    "shard_materialized": False,
                    "document_count": 208490,
                    "freshness": {"status": "current"},
                },
                {
                    "session_id": "small-session",
                    "session_label": "2026-06-29__001__small",
                    "shard": "month/2026-06",
                    "shard_status": "stale",
                    "shard_materialized": False,
                    "document_count": 5,
                    "freshness": {"status": "current"},
                },
            ],
        },
    )
    records = [
        {"session_id": "heavy-session", "session_label": "2026-06-13__003__heavy"},
        {"session_id": "small-session", "session_label": "2026-06-29__001__small"},
    ]

    selected, stats = module.filter_search_records_to_dirty_shard_sessions(
        aoa_root,
        records,
        shard="month/2026-06",
    )

    assert [item["session_id"] for item in selected] == ["small-session", "heavy-session"]
    assert stats["selection_order"] == "catalog_document_count_asc"
    assert [item["session_id"] for item in stats["dirty_selected_sessions"]] == ["small-session", "heavy-session"]
    assert [item["document_count"] for item in stats["dirty_selected_sessions"]] == [5, 208490]


def test_agent_event_route_uses_search_shards_without_stream_copy_limit_noise(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"

    may_transcript = tmp_path / "rollout-2026-05-12T00-00-00-agent-answer-shard.jsonl"
    write_jsonl(
        may_transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "agent-answer-shard", "cwd": str(workspace)}},
            {"timestamp": "2026-05-12T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Need a shard-routed answer"}]}},
            {"timestamp": "2026-05-12T00:00:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Here is the shard-routed answer."}]}},
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "agent-answer-shard",
            "transcript_path": str(may_transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    june_transcript = tmp_path / "rollout-2026-06-13T00-00-00-agent-progress-shard.jsonl"
    stream_rows = [
        {
            "timestamp": f"2026-06-13T00:00:{second:02d}Z",
            "type": "event_msg",
            "payload": {"type": "agent_message", "message": "Сейчас проверяю shard route."},
        }
        for second in range(4, 18)
    ]
    write_jsonl(
        june_transcript,
        [
            {"timestamp": "2026-06-13T00:00:00Z", "type": "session_meta", "payload": {"id": "agent-progress-shard", "cwd": str(workspace)}},
            {"timestamp": "2026-06-13T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Show progress"}]}},
            {"timestamp": "2026-06-13T00:00:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Сейчас проверяю shard route."}]}},
            {"timestamp": "2026-06-13T00:00:03Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Почти готово, проверка shard route заканчивается."}]}},
            *stream_rows,
            {"timestamp": "2026-06-13T00:00:18Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Here is the first ordinary routed answer."}]}},
            {"timestamp": "2026-06-13T00:00:19Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "Here is the later ordinary routed answer."}]}},
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "agent-progress-shard",
            "transcript_path": str(june_transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    indexed = module.search_index_sessions(aoa_root=aoa_root, target="all", rebuild=True)
    assert indexed["ok"] is True
    shards = module.materialize_search_shards(aoa_root=aoa_root, target="all")
    assert shards["ok"] is True
    assert shards["shard_count"] == 2

    answers = module.agent_event_route_search(
        aoa_root=aoa_root,
        agent_events=["assistant_answer"],
        limit=5,
        explain=True,
    )
    assert answers["ok"] is True
    assert answers["search_projection"]["mode"] == module.SEARCH_ACTIVE_PROJECTION_SHARD_FANOUT
    assert answers["cost_profile"]["uses_shards"] is True
    assert answers["cost_profile"]["uses_fts"] is False
    assert answers["cost_profile"]["hydrates_body"] is False
    assert answers["cost_profile"]["raw_ref_preview"] is True
    assert answers["results"][0]["search_catalog"]["active_projection"] == module.SEARCH_ACTIVE_PROJECTION_SHARD
    assert str(answers["results"][0]["preview_source"]).startswith("raw")
    assert "Here is the later ordinary routed answer" in answers["results"][0]["bounded_preview"]
    assert answers["quality"]["ordered_by"] == "query_rank_then_session_date_then_event_position_desc"
    assert answers["quality"]["raw_ref_present_count"] == answers["result_count"]
    assert answers["quality"]["raw_preview_result_count"] == answers["result_count"]
    monolith_answers = module.agent_event_route_search(
        aoa_root=aoa_root,
        agent_events=["assistant_answer"],
        limit=5,
        use_shards=False,
        explain=True,
    )
    assert monolith_answers["ok"] is True
    assert monolith_answers["search_projection"] == {}
    assert monolith_answers["cost_profile"].get("uses_shards") is not True
    assert monolith_answers["cost_profile"]["hydrates_body"] is False
    assert monolith_answers["cost_profile"]["raw_ref_preview"] is True
    assert monolith_answers["results"][0]["search_catalog"]["active_projection"] == module.SEARCH_ACTIVE_PROJECTION_MONOLITH
    assert str(monolith_answers["results"][0]["preview_source"]).startswith("raw")
    assert "Here is the later ordinary routed answer" in monolith_answers["results"][0]["bounded_preview"]

    latest_session_answers = module.agent_event_route_search(
        aoa_root=aoa_root,
        session="agent-progress-shard",
        agent_events=["assistant_answer"],
        limit=2,
        use_shards=True,
        explain=True,
    )
    assert latest_session_answers["ok"] is True
    assert [item["event_id"] for item in latest_session_answers["results"]] == ["000020", "000019"]
    assert latest_session_answers["quality"]["latest_result"]["event_id"] == "000020"
    assert latest_session_answers["quality"]["agent_event_counts"] == {"assistant_answer": 2}
    assert latest_session_answers["quality"]["source_counts"] == {"response_item": 2}
    assert latest_session_answers["quality"]["freshness_counts"] == {"fresh": 2}

    progress = module.agent_event_route_search(
        aoa_root=aoa_root,
        agent_events=["assistant_progress_update"],
        limit=2,
        use_shards=True,
        explain=True,
    )
    assert progress["ok"] is True
    assert progress["result_count"] == 2
    assert progress["search_projection"]["mode"] == module.SEARCH_ACTIVE_PROJECTION_SHARD_FANOUT
    assert progress["search_projection"]["queried_shard_count"] == 2
    assert progress["cost_profile"]["lightweight_route"] is True
    assert progress["cost_profile"]["uses_shards"] is True
    assert progress["cost_profile"]["uses_fts"] is False
    assert progress["cost_profile"]["semantic_preview"] is False
    assert progress["cost_profile"]["raw_ref_preview"] is True
    assert all(str(item["preview_source"]).startswith("raw") for item in progress["results"])
    assert all(item["agent_event_source"] != "event_msg_stream" for item in progress["results"])
    assert {item["event_id"] for item in progress["results"]} == {"000003", "000004"}

    latest_progress = module.agent_event_route_search(
        aoa_root=aoa_root,
        session="latest",
        agent_events=["assistant_progress_update"],
        limit=2,
        use_shards=True,
        explain=True,
    )
    assert latest_progress["ok"] is True
    assert latest_progress["result_count"] == 2
    assert latest_progress["search_projection"]["route_kind"] == "agent_event_session_segment_index"
    assert latest_progress["cost_profile"]["uses_session_segment_indexes"] is True
    assert latest_progress["search_projection"]["session_scope"]["resolved_session_label"].startswith("2026-06-13__")
    assert {item["session_id"] for item in latest_progress["results"]} == {"agent-progress-shard"}

    truncated = module.agent_event_route_search(
        aoa_root=aoa_root,
        agent_events=["assistant_progress_update"],
        limit=1,
        use_shards=True,
        max_shards=1,
    )
    assert truncated["search_projection"]["truncated"] is True
    assert "agent-responses" in truncated["search_projection"]["next_expansion_command"]
    assert "--agent-event assistant_progress_update" in truncated["search_projection"]["next_expansion_command"]


def test_search_index_default_raw_lexical_policy_is_bounded_but_compact_exact_survives(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-search-raw-budget.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "search-raw-budget", "cwd": str(workspace)}},
            {
                "timestamp": "2026-05-12T00:00:01Z",
                "type": "response_item",
                "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "raw-budget-unique-anchor"}]},
            },
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "search-raw-budget",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    monkeypatch.setattr(module, "SEARCH_RAW_LEXICAL_DEFAULT_MAX_BYTES", 1)
    bounded = module.search_index_sessions(aoa_root=aoa_root, target="all", rebuild=True)

    assert bounded["ok"] is True
    assert bounded["max_raw_bytes"] == 1
    assert bounded["raw_lexical_policy"]["source"] == "default"
    assert bounded["raw_text_status_counts"]["skipped_raw_too_large"] == 1
    assert bounded["raw_text_skipped_session_count"] == 1
    assert bounded["literal_postings"]["posting_document_count"] == 1
    assert bounded["literal_postings"]["session_status_counts"] == {"current": 1}
    bounded_results = module.search_sessions(aoa_root=aoa_root, query="raw-budget-unique-anchor")
    assert bounded_results["result_count"] == 1
    assert bounded_results["results"][0]["match_channel"] == "exact_literal_postings"
    assert bounded_results["results"][0]["raw_ref"] == "raw:line:2"

    unbounded = module.search_index_sessions(aoa_root=aoa_root, target="all", max_raw_bytes=-1, rebuild=True)

    assert unbounded["ok"] is True
    assert unbounded["max_raw_bytes"] is None
    assert unbounded["raw_lexical_policy"]["source"] == "explicit_unbounded"
    assert unbounded["raw_text_status_counts"]["available"] == 1
    unbounded_results = module.search_sessions(aoa_root=aoa_root, query="raw-budget-unique-anchor")
    assert unbounded_results["result_count"] >= 1


