    assert maintained["search_shards_repair_scoped_candidate_count"] == 1
    assert maintained["search_shards_repair_scoped_remaining_count"] == 0
    assert maintained["search_shards_repair_out_of_scope_count"] == 0
    assert maintained["search_shards_repair_remaining_count"] == 0
    assert maintained["search_shard_repair_limit"] == 1
    assert maintained["final_search_shards"]["status"] == "current"


