def test_search_read_routes_remain_available_during_wal_writer(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    repo = workspace / "aoa-session-memory"
    repo.mkdir(parents=True)
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-06-14T00-00-00-wal-writer-session.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-06-14T00:00:00Z", "type": "session_meta", "payload": {"id": "wal-writer-session", "cwd": str(repo)}},
            {"timestamp": "2026-06-14T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Keep search reads available"}]}},
            {"timestamp": "2026-06-14T00:00:02Z", "type": "response_item", "payload": {"type": "message", "role": "assistant", "content": [{"type": "output_text", "text": "wal answer committed for readers"}]}},
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "wal-writer-session",
            "transcript_path": str(transcript),
            "cwd": str(repo),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    indexed = module.search_index_sessions(aoa_root=aoa_root, target="all")
    assert indexed["ok"] is True

    baseline = module.search_sessions(aoa_root=aoa_root, query="wal answer", limit=1)
    assert baseline["ok"] is True
    assert baseline["result_count"] == 1

    writer: sqlite3.Connection | None = None
    try:
        writer = module.init_search_db(module.search_db_path(aoa_root), rebuild=False)
        journal_mode = str(writer.execute("PRAGMA journal_mode").fetchone()[0]).lower()
        assert journal_mode == "wal"
        writer.execute("BEGIN EXCLUSIVE")
        writer.execute("INSERT OR REPLACE INTO meta(key, value) VALUES ('concurrent_writer_probe', 'open')")

        status = module.search_provider_status(aoa_root=aoa_root, provider_name="portable_sqlite")
        search = module.search_sessions(aoa_root=aoa_root, query="wal answer", limit=1)
        agent_events = module.search_agent_event_documents(aoa_root=aoa_root, session="wal-writer-session", limit=1)
    finally:
        if writer is not None:
            writer.rollback()
            writer.close()

    assert status["providers"]["portable_sqlite"]["status"] == "ready"
    assert search["ok"] is True
    assert search["provider"]["status"]["providers"]["portable_sqlite"]["status"] == "ready"
    assert search["result_count"] == 1
    assert agent_events["ok"] is True
    assert agent_events["provider"]["status"]["providers"]["portable_sqlite"]["status"] == "ready"
    assert agent_events["result_count"] == 1


def test_search_read_routes_report_locked_search_db_without_traceback(tmp_path: Path, monkeypatch: Any) -> None:
    aoa_root = tmp_path / ".aoa"
    db_path = module.search_db_path(aoa_root)
    db_path.parent.mkdir(parents=True)
    db_path.touch()
    real_connect = sqlite3.connect
    search_connects: list[str] = []

    def locked_connect(database: Any, *args: Any, **kwargs: Any) -> sqlite3.Connection:
        database_text = str(database)
        if database_text.startswith("file:") and "mode=ro" in database_text:
            search_connects.append(database_text)
            raise sqlite3.OperationalError("database is locked")
        return real_connect(database, *args, **kwargs)

    monkeypatch.setattr(module.sqlite3, "connect", locked_connect)

    status = module.search_provider_status(aoa_root=aoa_root, provider_name="portable_sqlite")
    provider = status["providers"]["portable_sqlite"]
    search = module.search_sessions(aoa_root=aoa_root, query="anything", limit=1)
    agent_events = module.search_agent_event_documents(aoa_root=aoa_root, limit=1)

    assert provider["status"] == "sqlite_locked"
    assert provider["diagnostics"] == ["sqlite_locked:database is locked"]
    assert search["ok"] is False
    assert search["provider"]["status"] == "sqlite_locked"
    assert search["diagnostics"] == ["sqlite_locked:database is locked"]
    assert agent_events["ok"] is False
    assert agent_events["provider"]["status"] == "sqlite_locked"
    assert agent_events["diagnostics"] == ["sqlite_locked:database is locked"]
    assert search_connects


def test_raw_fts_search_timeout_returns_bounded_route_packet(tmp_path: Path, monkeypatch: Any) -> None:
    aoa_root = tmp_path / ".aoa"
    db_path = module.search_db_path(aoa_root)
    db_path.parent.mkdir(parents=True)
    db_path.touch()

    class TimeoutConnection:
        def __init__(self) -> None:
            self.progress_handlers: list[tuple[Any, int]] = []
            self.executed_sql: list[str] = []
            self.closed = False

        def set_progress_handler(self, handler: Any, n: int) -> None:
            self.progress_handlers.append((handler, n))

        def execute(self, sql: str, *_args: Any, **_kwargs: Any) -> Any:
            self.executed_sql.append(sql)
            time.sleep(0.01)
            raise sqlite3.OperationalError("interrupted")

        def close(self) -> None:
            self.closed = True

    fake_conn = TimeoutConnection()
    monkeypatch.setattr(module, "connect_existing_search_db", lambda *_args, **_kwargs: fake_conn)

    payload = module.search_sessions(
        aoa_root=aoa_root,
        query="very broad raw text",
        doc_type="event",
        query_timeout_ms=1,
        explain=True,
    )

    assert payload["ok"] is False
    assert payload["provider"]["status"] == module.SEARCH_FTS_QUERY_TIMEOUT_STATUS
    assert payload["bounded_timeout"]["status"] == module.SEARCH_FTS_QUERY_TIMEOUT_STATUS
    assert payload["bounded_timeout"]["query_timeout_ms"] == 1
    assert "--query-timeout-ms 30000" in payload["bounded_timeout"]["next_expansion_command"]
    assert "--doc-type event" in payload["bounded_timeout"]["next_expansion_command"]
    assert payload["cost_profile"]["uses_fts"] is True
    assert payload["cost_profile"]["bounded_query_timeout"] is True
    assert payload["cost_profile"]["rank_mode"] == "bounded_date_order_no_bm25"
    assert payload["diagnostics"][0] == "search_fts_query_timeout:1ms"
    assert payload["diagnostics"][1] == "sqlite_query_timeout:interrupted"
    assert module.SEARCH_FTS_QUERY_PROGRESS_OPCODES in {step for _handler, step in fake_conn.progress_handlers}
    assert fake_conn.progress_handlers[-1] == (None, 0)
    assert "bm25(" not in fake_conn.executed_sql[0]
    assert "sqlite_master" in fake_conn.executed_sql[0]
    assert fake_conn.closed is True


def test_structured_route_filter_stays_within_posting_first_work_budget(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """A rare typed posting must bound document reads before broad usage/date indexes."""
    aoa_root = tmp_path / ".aoa"
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)
    module.insert_search_document(
        conn,
        {
            "id": "typed-route-target",
            "doc_type": "event",
            "session_id": "gold-session",
            "session_label": "gold-session",
            "session_date": "2026-01-01",
            "event_id": "typed-route-target-event",
            "event_type": "FILE_READ",
            "usage_role": "usage",
            "route_layers": "skill",
            "route_signals": "skill:portable_route",
            "raw_ref": "raw:line:7",
            "title": "Portable route target",
            "body": "Portable route target",
        },
        store_raw_text=False,
    )
    conn.executemany(
        """
        INSERT INTO documents (
            id, doc_type, session_id, session_label, session_date,
            event_id, event_type, usage_role, title, body, payload_json
        )
        VALUES (
            ?, 'event', 'noise-session', 'noise-session', '2026-07-01',
            ?, 'COMMAND_OUTPUT', 'usage', 'Unrelated usage event', '', '{}'
        )
        """,
        (
            (f"typed-route-noise-{index:05d}", f"typed-route-noise-event-{index:05d}")
            for index in range(5_000)
        ),
    )
    conn.commit()
    conn.close()

    operation_budget = 2_000
    operation_callbacks = 0

    def install_operation_budget(
        search_conn: sqlite3.Connection,
        *,
        query_timeout_ms: int | None,
    ) -> tuple[int, None]:
        nonlocal operation_callbacks

        def interrupt_after_budget() -> int:
            nonlocal operation_callbacks
            operation_callbacks += 1
            return int(operation_callbacks > operation_budget)

        search_conn.set_progress_handler(interrupt_after_budget, 1)
        return module.normalized_search_fts_query_timeout_ms(query_timeout_ms), None

    monkeypatch.setattr(module, "install_search_fts_query_deadline", install_operation_budget)

    payload = module.search_sessions(
        aoa_root=aoa_root,
        query="",
        doc_type="event",
        usage_role="usage",
        route_signal="skill:portable_route",
        limit=1,
        query_timeout_ms=1,
        explain=True,
    )

    assert payload["ok"] is True
    assert payload["result_count"] == 1
    assert payload["results"][0]["raw_ref"] == "raw:line:7"
    assert operation_callbacks <= operation_budget


def test_structured_route_filter_adapts_before_dense_postings_exhaust_query_budget(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    """A dense typed posting must read the ordered document lane before sorting every posting."""
    aoa_root = tmp_path / ".aoa"
    conn = module.init_search_db(module.search_db_path(aoa_root), rebuild=True)
    route_cursor = conn.execute(
        "INSERT INTO route_terms(layer, key, route_signal) VALUES ('tool', 'exec_command', 'tool:exec_command')"
    )
    route_id = int(route_cursor.lastrowid)
    conn.executemany(
        """
        INSERT INTO documents (
            id, doc_type, session_id, session_label, session_date,
            event_id, event_type, usage_role, raw_ref, title, body, payload_json
        )
        VALUES (
            ?, 'event', 'dense-route-session', 'dense-route-session', ?,
            ?, 'COMMAND', 'usage', ?, 'Dense route usage', '', '{}'
        )
        """,
        (
            (
                f"dense-route-{index:05d}",
                f"2026-07-{1 + (index % 15):02d}",
                f"dense-route-event-{index:05d}",
                f"raw:line:{index + 1}",
            )
            for index in range(6_000)
        ),
    )
    conn.execute(
        "INSERT INTO document_routes(doc_rowid, route_id) SELECT rowid, ? FROM documents",
        (route_id,),
    )
    conn.commit()
    conn.close()

    operation_budget = 1_000
    operation_callbacks = 0

    def count_operations(
        search_conn: sqlite3.Connection,
        *,
        query_timeout_ms: int | None,
    ) -> tuple[int, None]:
        def count_callback() -> int:
            nonlocal operation_callbacks
            operation_callbacks += 1
            return int(operation_callbacks > operation_budget)

        search_conn.set_progress_handler(count_callback, 100)
        return module.normalized_search_fts_query_timeout_ms(query_timeout_ms), None

    monkeypatch.setattr(module, "install_search_fts_query_deadline", count_operations)

    payload = module.search_sessions(
        aoa_root=aoa_root,
        query="",
        doc_type="event",
        usage_role="usage",
        route_signal="tool:exec_command",
        limit=12,
        query_timeout_ms=1,
        explain=True,
    )

    assert payload["ok"] is True
    assert payload["result_count"] == 12
    assert all(str(result.get("raw_ref") or "").startswith("raw:line:") for result in payload["results"])
    assert payload["cost_profile"]["route_candidate_plan"] == "document_order_first_membership_probe"
    assert payload["cost_profile"]["route_membership_mode"] == "correlated_index_membership"
    assert payload["cost_profile"]["route_document_order_index"] == "idx_documents_doc_type_usage_role_date"
    assert payload["cost_profile"]["route_posting_probe_limit"] == 4_096
    assert payload["cost_profile"]["route_posting_probe_count"] == 4_097
    assert payload["cost_profile"]["route_posting_probe_truncated"] is True
    assert payload["cost_profile"]["route_filter_materialized_from_probe"] is False
    assert operation_callbacks <= operation_budget


