def test_session_scoped_route_search_uses_stale_readable_segment_postings(
    tmp_path: Path,
) -> None:
    """A stale global projection must not hide a resolvable session-local call."""
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-session-route-fallback.jsonl"
    write_jsonl(
        transcript,
        [
            {
                "timestamp": "2026-07-17T00:00:00Z",
                "type": "session_meta",
                "payload": {
                    "id": "session-route-fallback",
                    "cwd": str(workspace),
                },
            },
            {
                "timestamp": "2026-07-17T00:00:01Z",
                "type": "response_item",
                "payload": {
                    "type": "message",
                    "role": "user",
                    "content": [
                        {
                            "type": "input_text",
                            "text": "Inspect one bounded source span.",
                        }
                    ],
                },
            },
            {
                "timestamp": "2026-07-17T00:00:02Z",
                "type": "response_item",
                "payload": {
                    "type": "function_call",
                    "name": "exec_command",
                    "call_id": "call-session-route-fallback",
                    "arguments": "{\"cmd\":\"sed -n '1,20p' source.py\"}",
                },
            },
            {
                "timestamp": "2026-07-17T00:00:03Z",
                "type": "response_item",
                "payload": {
                    "type": "function_call_output",
                    "call_id": "call-session-route-fallback",
                    "output": "source span",
                },
            },
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "session-route-fallback",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    session_dir = next(
        path for path in (aoa_root / "sessions").iterdir() if path.is_dir()
    )

    current = module.search_sessions(
        aoa_root=aoa_root,
        query="",
        session=session_dir.name,
        doc_type="event",
        usage_role="usage",
        route_signal="tool:exec_command",
        limit=4,
        explain=True,
    )

    assert current["ok"] is True
    assert current["result_count"] == 1
    assert (
        current["search_projection"]["route_kind"]
        == "structured_event_session_segment_index"
    )
    assert current["cost_profile"]["uses_session_segment_indexes"] is True
    assert current["results"][0]["raw_ref"] == "raw:line:3"
    assert (
        current["results"][0]["correlation_id"]
        == "call-session-route-fallback"
    )

    manifest = module.read_json(session_dir / "session.manifest.json", {})
    segment_path = Path(str(manifest["segments"][0]["index"]))
    segment_index = module.read_json(segment_path, {})
    segment_index["route_signal_classifier_version"] = (
        module.ROUTE_SIGNAL_CLASSIFIER_VERSION - 1
    )
    module.write_json(segment_path, segment_index)

    stale = module.search_sessions(
        aoa_root=aoa_root,
        query="",
        session=session_dir.name,
        doc_type="event",
        usage_role="usage",
        route_signal="tool:exec_command",
        limit=4,
        explain=True,
    )

    assert stale["ok"] is True
    assert stale["result_count"] == 1
    assert stale["search_projection"]["stale_readable"] is True
    assert stale["search_projection"]["candidate_count_exhaustive"] is False
    assert stale["results"][0]["freshness"]["status"] == "stale"
    assert "route_signal_classifier_mismatch" in stale["results"][0][
        "freshness"
    ]["reasons"]

    # The real W0-A failure had a readable monolith whose route projection
    # lacked the session-local call.  Preserve that distinction from the
    # simpler missing-DB fallback above.
    assert module.search_index_sessions(
        aoa_root=aoa_root,
        target="all",
        rebuild=True,
    )["ok"] is True
    conn = sqlite3.connect(module.search_db_path(aoa_root))
    conn.execute("DELETE FROM document_routes")
    conn.commit()
    conn.close()

    stale_global = module.search_sessions(
        aoa_root=aoa_root,
        query="",
        session=session_dir.name,
        doc_type="event",
        usage_role="usage",
        route_signal="tool:exec_command",
        limit=4,
        explain=True,
    )

    assert stale_global["ok"] is True
    assert stale_global["result_count"] == 1
    assert stale_global["results"][0]["raw_ref"] == "raw:line:3"
    assert (
        stale_global["search_projection"]["fallback_from"]
        == "monolith_fallback_structured_route_empty"
    )


def test_structured_search_timeout_returns_bounded_route_packet(tmp_path: Path, monkeypatch: Any) -> None:
    aoa_root = tmp_path / ".aoa"
    db_path = module.search_db_path(aoa_root)
    db_path.parent.mkdir(parents=True)
    db_path.touch()

    class TimeoutConnection:
        def __init__(self) -> None:
            self.progress_handlers: list[tuple[Any, int]] = []
            self.closed = False

        def set_progress_handler(self, handler: Any, n: int) -> None:
            self.progress_handlers.append((handler, n))

        def execute(self, _sql: str, *_args: Any, **_kwargs: Any) -> Any:
            time.sleep(0.01)
            raise sqlite3.OperationalError("interrupted")

        def close(self) -> None:
            self.closed = True

    fake_conn = TimeoutConnection()
    monkeypatch.setattr(module, "connect_existing_search_db", lambda *_args, **_kwargs: fake_conn)

    payload = module.search_sessions(
        aoa_root=aoa_root,
        query="",
        session="gold-session",
        doc_type="event",
        route_signal="test:pytest",
        query_timeout_ms=1,
        explain=True,
    )

    assert payload["ok"] is False
    assert payload["provider"]["status"] == module.SEARCH_FTS_QUERY_TIMEOUT_STATUS
    assert payload["bounded_timeout"]["status"] == module.SEARCH_FTS_QUERY_TIMEOUT_STATUS
    assert payload["bounded_timeout"]["scope"] == "structured_filter"
    assert payload["bounded_timeout"]["query_timeout_ms"] == 1
    assert "--use-shards" in payload["bounded_timeout"]["next_expansion_command"]
    assert "--route-signal test:pytest" in payload["bounded_timeout"]["next_expansion_command"]
    assert "--query-timeout-ms 1" in payload["bounded_timeout"]["next_expansion_command"]
    assert payload["cost_profile"]["uses_fts"] is False
    assert payload["cost_profile"]["bounded_query_timeout"] is True
    assert payload["cost_profile"]["rank_mode"] == "none"
    assert payload["diagnostics"][0] == "search_structured_query_timeout:1ms"
    assert payload["diagnostics"][1] == "sqlite_query_timeout:interrupted"
    assert module.SEARCH_FTS_QUERY_PROGRESS_OPCODES in {step for _handler, step in fake_conn.progress_handlers}
    assert fake_conn.progress_handlers[-1] == (None, 0)
    assert fake_conn.closed is True


def test_agent_event_raw_fts_timeout_preserves_route_diagnostic(tmp_path: Path, monkeypatch: Any) -> None:
    aoa_root = tmp_path / ".aoa"
    db_path = module.search_db_path(aoa_root)
    db_path.parent.mkdir(parents=True)
    db_path.touch()

    class TimeoutConnection:
        def __init__(self) -> None:
            self.progress_handlers: list[tuple[Any, int]] = []
            self.executed_sql: list[str] = []

        def set_progress_handler(self, handler: Any, n: int) -> None:
            self.progress_handlers.append((handler, n))

        def execute(self, sql: str, *_args: Any, **_kwargs: Any) -> Any:
            self.executed_sql.append(sql)
            time.sleep(0.01)
            raise sqlite3.OperationalError("interrupted")

        def close(self) -> None:
            pass

    fake_conn = TimeoutConnection()
    monkeypatch.setattr(module, "connect_existing_search_db", lambda *_args, **_kwargs: fake_conn)

    route = module.agent_event_route_search(
        aoa_root=aoa_root,
        query="assistant answer broad query",
        agent_events=["assistant_answer"],
        query_timeout_ms=1,
    )

    assert route["ok"] is False
    assert route["provider"]["status"] == module.SEARCH_FTS_QUERY_TIMEOUT_STATUS
    assert route["bounded_timeout"]["status"] == module.SEARCH_FTS_QUERY_TIMEOUT_STATUS
    assert "agent-responses" in route["bounded_timeout"]["next_expansion_command"]
    assert "--agent-event assistant_answer" in route["bounded_timeout"]["next_expansion_command"]
    assert route["cost_profile"]["uses_fts"] is True
    assert route["cost_profile"]["bounded_query_timeout"] is True
    assert route["cost_profile"]["rank_mode"] == "bounded_date_order_no_bm25"
    assert route["diagnostics"][0] == "search_fts_query_timeout:1ms"
    assert module.SEARCH_FTS_QUERY_PROGRESS_OPCODES in {step for _handler, step in fake_conn.progress_handlers}
    assert fake_conn.progress_handlers[-1] == (None, 0)
    assert "bm25(" not in fake_conn.executed_sql[0]
    assert "sqlite_master" in fake_conn.executed_sql[0]


def test_search_provider_status_detects_structural_schema_drift(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    db_path = module.search_db_path(aoa_root)
    db_path.parent.mkdir(parents=True)
    conn = sqlite3.connect(str(db_path))
    conn.execute("CREATE TABLE meta (key TEXT PRIMARY KEY, value TEXT NOT NULL)")
    conn.execute("INSERT INTO meta (key, value) VALUES ('schema_version', ?)", (str(module.SEARCH_SCHEMA_VERSION),))
    conn.execute(
        """
        CREATE TABLE documents (
            rowid INTEGER PRIMARY KEY AUTOINCREMENT,
            id TEXT NOT NULL UNIQUE,
            doc_type TEXT NOT NULL,
            session_id TEXT,
            session_label TEXT,
            session_act TEXT,
            route_layers TEXT,
            route_signals TEXT,
            payload_json TEXT NOT NULL
        )
        """
    )
    conn.execute("CREATE VIRTUAL TABLE documents_fts USING fts5(title, body, session_label, session_title, content='documents', content_rowid='rowid')")
    conn.execute("CREATE TABLE document_bodies (doc_rowid INTEGER PRIMARY KEY, body_zlib BLOB NOT NULL, body_sha256 TEXT NOT NULL, body_chars INTEGER NOT NULL)")
    conn.execute("CREATE TABLE route_terms (id INTEGER PRIMARY KEY AUTOINCREMENT, layer TEXT NOT NULL, key TEXT NOT NULL, route_signal TEXT NOT NULL)")
    conn.execute("CREATE TABLE document_routes (doc_rowid INTEGER NOT NULL, route_id INTEGER NOT NULL)")
    conn.execute("CREATE TABLE session_index_state (session_id TEXT PRIMARY KEY, session_label TEXT, source_fingerprint TEXT NOT NULL, source_latest_mtime REAL, search_schema_version TEXT, route_signal_classifier_version INTEGER, indexed_at TEXT, document_count INTEGER)")
    conn.execute("INSERT INTO documents (id, doc_type, payload_json) VALUES ('doc-1', 'session', '{}')")
    conn.commit()
    conn.close()

    status = module.search_provider_status(aoa_root=aoa_root, provider_name="portable_sqlite")
    provider = status["providers"]["portable_sqlite"]
    state = module.sqlite_search_index_state(aoa_root, latest_source_mtime=0)

    assert provider["ok"] is False
    assert provider["status"] == "stale"
    assert "search_schema_missing_column:documents.agent_event" in provider["diagnostics"]
    assert "search_schema_missing_column:documents.usage_role" in provider["diagnostics"]
    assert "search_schema_missing_column:documents.task_episode_id" in provider["diagnostics"]
    assert "search_schema_missing_column:documents.agent_event" in state["reasons"]
    assert "search_schema_missing_column:documents.usage_role" in state["reasons"]
    assert state["needs_refresh"] is True


def test_search_schema_migrate_backfills_usage_role_without_reindex(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    db_path = module.search_db_path(aoa_root)
    conn = module.init_search_db(db_path, rebuild=True)
    conn.execute("INSERT OR REPLACE INTO meta(key, value) VALUES (?, ?)", ("schema_version", "12"))
    docs = [
        ("doc-command", "event", "COMMAND", "tool_call", "command_request"),
        ("doc-result", "event", "COMMAND_OUTPUT", "memory_observation", "tool_output_success"),
        ("doc-answer", "event", "ASSISTANT_MESSAGE", "assistant_message", "assistant_response"),
        ("doc-entrypoint", "event", "CUSTOM", "memory_request", "command_inspection_request"),
        ("doc-session", "session", "", "", ""),
    ]
    for doc_id, doc_type, event_type, session_act, conversation_act in docs:
        conn.execute(
            """
            INSERT INTO documents (
                id, doc_type, session_id, session_label, event_type,
                session_act, conversation_act, payload_json
            )
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (doc_id, doc_type, "migrate-session", "migrate-session", event_type, session_act, conversation_act, "{}"),
        )
    conn.execute(
        """
        INSERT INTO session_index_state (
            session_id, session_label, source_fingerprint, source_latest_mtime,
            search_schema_version, route_signal_classifier_version, indexed_at,
            document_count
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?)
        """,
        ("migrate-session", "migrate-session", "fp", 1.0, "12", module.ROUTE_SIGNAL_CLASSIFIER_VERSION, "2026-06-20T00:00:00Z", 5),
    )
    conn.execute(
        """
        INSERT INTO search_freshness_state (
            session_id, session_label, session_dir, source_fingerprint, source_latest_mtime,
            status, reason, last_checked, last_indexed_at, deferred_live_reason,
            live_transcript_path, live_transcript_mtime, search_schema_version,
            route_signal_classifier_version, document_count, updated_at
        )
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            "migrate-session",
            "migrate-session",
            "",
            "fp",
            1.0,
            "current",
            "indexed",
            "2026-06-20T00:00:00Z",
            "2026-06-20T00:00:00Z",
            "",
            "",
            0.0,
            "12",
            module.ROUTE_SIGNAL_CLASSIFIER_VERSION,
            5,
            "2026-06-20T00:00:00Z",
        ),
    )
    conn.commit()
    conn.close()

    payload = module.migrate_search_schema_usage_role(aoa_root=aoa_root)

    assert payload["ok"] is True
    assert payload["search_schema_version_before"] == "12"
    assert payload["search_schema_version_after"] == str(module.SEARCH_SCHEMA_VERSION)
    assert payload["backfilled_event_document_count"] == 4
    assert payload["role_counts"]["usage"] == 1
    assert payload["role_counts"]["result"] == 1
    assert payload["role_counts"]["outcome"] == 1
    assert payload["role_counts"]["entrypoint"] == 1

    conn = module.connect_existing_search_db(db_path)
    meta = module.search_index_metadata(conn)
    state_schema = conn.execute("SELECT search_schema_version FROM session_index_state").fetchone()[0]
    freshness_schema = conn.execute("SELECT search_schema_version FROM search_freshness_state").fetchone()[0]
    conn.close()

    assert meta["schema_version"] == str(module.SEARCH_SCHEMA_VERSION)
    assert meta["search_usage_role_projection_version"] == str(module.SEARCH_USAGE_ROLE_PROJECTION_VERSION)
    assert state_schema == str(module.SEARCH_SCHEMA_VERSION)
    assert freshness_schema == str(module.SEARCH_SCHEMA_VERSION)


def test_host_search_provider_overlay_never_replaces_aoa_refs(tmp_path: Path, monkeypatch) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    (aoa_root / "config").mkdir(parents=True, exist_ok=True)
    config = module.default_search_provider_config()
    config["providers"]["abyss_machine_nervous"]["enabled"] = True
    (aoa_root / module.SEARCH_PROVIDER_CONFIG_PATH).write_text(json.dumps(config, ensure_ascii=False), encoding="utf-8")
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-host-provider.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "host-provider-session", "cwd": str(workspace)}},
            {"timestamp": "2026-05-12T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Stop hook failed because hook timed out"}]}},
        ],
    )
    module.handle_hook_event(
        "Stop",
        {
            "session_id": "host-provider-session",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )
    module.search_index_sessions(aoa_root=aoa_root, target="all")

    def fake_run_json_command(command: list[str], **_kwargs: object) -> dict[str, object]:
        if command[:3] == ["abyss-machine", "stack-bridge", "validate"]:
            return {"ok": True, "status": "ok", "command": command, "payload": {"schema": "stack", "generated_at": "now", "summary": {"fails": 0, "warnings": 0, "checks": 1}}}
        if command[:3] == ["abyss-machine", "nervous", "quality-audit"]:
            return {"ok": True, "status": "ok", "command": command, "payload": {"schema": "quality", "generated_at": "now", "summary": {"fails": 0, "warnings": 1, "checks": 1}}}
        if command[:3] == ["abyss-machine", "nervous", "semantic-status"]:
            return {
                "ok": True,
                "status": "ok",
                "command": command,
                "payload": {
                    "schema": "semantic",
                    "generated_at": "now",
                    "ok": True,
                    "ready": True,
                    "warnings": [],
                    "embedding": {"model_dir": "/models/embed", "model_exists": True, "device": "GPU", "dimension": 1024},
                    "counts": {"vectors": 12},
                    "freshness": {"stale": False, "source_chunks": 12, "delta_chunks": 0, "partial": False},
                },
            }
        if command[:3] == ["abyss-machine", "nervous", "recall"]:
            return {
                "ok": True,
                "status": "ok",
                "command": command,
                "payload": {
                    "schema": "abyss_machine_nervous_retrieval_pack_v1",
                    "generated_at": "now",
                    "mode": "lexical",
                    "query": "hook timed out",
                    "summary": {"evidence_items": 1},
                    "evidence": [{"id": "host-context"}],
                },
            }
        raise AssertionError(command)

    def fake_run_json_url(url: str, **_kwargs: object) -> dict[str, object]:
        assert url == "http://127.0.0.1:5405/health"
        return {
            "ok": True,
            "status": "ok",
            "url": url,
            "payload": {
                "ok": True,
                "service": "rerank-api",
                "model": "qwen3-reranker-0.6b-int8-ov",
                "backend": "openvino_qwen3_reranker",
                "device": "GPU",
                "model_dir_exists": True,
                "fake_mode": False,
            },
        }

    monkeypatch.setattr(module, "run_json_command", fake_run_json_command)
    monkeypatch.setattr(module, "run_json_url", fake_run_json_url)

    guarded = module.search_sessions(
        aoa_root=aoa_root,
        query="hook timed out",
        provider="abyss_machine_nervous",
        doc_type="event",
        explain=True,
    )
    assert guarded["ok"] is True
    assert guarded["provider"]["authoritative_result_provider"] == "portable_sqlite"
    assert guarded["provider"]["status"]["providers"]["abyss_machine_nervous"]["status"] == "ready_with_warnings"
    assert guarded["provider"]["overlay"] is None
    assert guarded["results"][0]["refs"]["raw"] == "raw:line:2"
    assert "host provider has warnings" in guarded["diagnostics"][0]

    with_overlay = module.search_sessions(
        aoa_root=aoa_root,
        query="hook timed out",
        provider="abyss_machine_nervous",
        doc_type="event",
        include_host_context=True,
        allow_host_warnings=True,
    )
    assert with_overlay["provider"]["overlay"]["truth_level"] == "host_context_only_not_aoa_authority"
    assert with_overlay["provider"]["overlay"]["evidence_count"] == 1
    assert with_overlay["results"][0]["refs"]["raw"] == "raw:line:2"
    provider_models = with_overlay["provider"]["status"]["providers"]["abyss_machine_nervous"]["models"]
    assert provider_models["embedding"]["status"] == "ready"
    assert provider_models["reranker"]["status"] == "ready"


