def test_search_no_match_is_observed_without_hiding_real_empty_failures(tmp_path: Path) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    transcript = tmp_path / "rollout-2026-05-12T00-00-00-empty-nonzero.jsonl"
    write_jsonl(
        transcript,
        [
            {"timestamp": "2026-05-12T00:00:00Z", "type": "session_meta", "payload": {"id": "empty-nonzero", "cwd": str(workspace)}},
            {"timestamp": "2026-05-12T00:00:01Z", "type": "response_item", "payload": {"type": "message", "role": "user", "content": [{"type": "input_text", "text": "Search for a marker"}]}},
            {"timestamp": "2026-05-12T00:00:02Z", "type": "response_item", "payload": {"type": "function_call", "name": "exec_command", "call_id": "call-rg", "arguments": json.dumps({"cmd": "rg -n missing-marker README.md"})}},
            {"timestamp": "2026-05-12T00:00:03Z", "type": "response_item", "payload": {"type": "function_call_output", "call_id": "call-rg", "output": "Chunk ID: x\nProcess exited with code 1\nOriginal token count: 0\nOutput:\n"}},
            {"timestamp": "2026-05-12T00:00:04Z", "type": "response_item", "payload": {"type": "function_call", "name": "exec_command", "call_id": "call-python", "arguments": json.dumps({"cmd": "python3 -c 'raise SystemExit(1)'"})}},
            {"timestamp": "2026-05-12T00:00:05Z", "type": "response_item", "payload": {"type": "function_call_output", "call_id": "call-python", "output": "Chunk ID: y\nProcess exited with code 1\nOriginal token count: 0\nOutput:\n"}},
            {"timestamp": "2026-05-12T00:00:06Z", "type": "response_item", "payload": {"type": "function_call", "name": "exec_command", "call_id": "call-rg-error", "arguments": json.dumps({"cmd": "rg -n marker missing-file"})}},
            {"timestamp": "2026-05-12T00:00:07Z", "type": "response_item", "payload": {"type": "function_call_output", "call_id": "call-rg-error", "output": "Chunk ID: z\nProcess exited with code 2\nOriginal token count: 0\nOutput:\n"}},
        ],
    )

    module.handle_hook_event(
        "Stop",
        {
            "session_id": "empty-nonzero",
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "Stop",
        },
        workspace_root=workspace,
        aoa_root=aoa_root,
    )

    session_dir = aoa_root / "sessions" / "2026-05-12__001__search-for-a-marker"
    segment_index = json.loads((session_dir / "segments" / "000__initial-to-latest.index.json").read_text(encoding="utf-8"))
    records = {event["event_id"]: event for event in segment_index["events"]}
    no_match = records["000004"]
    assert no_match["type"] == "COMMAND_OUTPUT"
    assert no_match["outcome"] == "no_match"
    assert "search_no_match_signal" in no_match["tags"]
    assert "error_signal" not in no_match["tags"]
    assert no_match["facets"]["conversation_act"]["kind"] == "command_no_match"
    assert no_match["facets"]["session_act"]["outcome"] == "no_match"
    assert {
        f"{signal['layer']}:{signal['key']}"
        for signal in no_match["facets"]["route_signals"]
    } == {"verification_state:no_match_observed", "correlation:tool_call_output_link"}

    generic_failure = records["000006"]
    assert generic_failure["outcome"] == "failed"
    assert "empty_nonzero_output_signal" in generic_failure["tags"]
    assert "search_no_match_signal" not in generic_failure["tags"]

    search_error = records["000008"]
    assert search_error["outcome"] == "failed"
    assert "empty_nonzero_output_signal" in search_error["tags"]
    assert "search_no_match_signal" not in search_error["tags"]

    session_index_path = session_dir / module.SESSION_INDEX_JSON
    stale_session_index = module.read_json(session_index_path, {})
    stale_session_index["route_signal_classifier_version"] = (
        module.ROUTE_SIGNAL_CLASSIFIER_VERSION - 1
    )
    module.write_json(session_index_path, stale_session_index)

    refresh = module.reindex_sessions(
        aoa_root=aoa_root,
        target="all",
        stale_route_indexes=True,
    )
    assert refresh["ok"] is True
    assert refresh["counts"] == {"reindexed": 1}

    refreshed_segment_index = module.read_json(
        session_dir / "segments" / "000__initial-to-latest.index.json",
        {},
    )
    refreshed_records = {
        event["event_id"]: event for event in refreshed_segment_index["events"]
    }
    assert refreshed_records["000004"]["outcome"] == "no_match"
    assert "search_no_match_signal" in refreshed_records["000004"]["tags"]
    refreshed_session_index = module.read_json(session_index_path, {})
    assert all(
        failure.get("line") != 4
        for episode in refreshed_session_index["task_episodes"]
        for failure in episode.get("failures", [])
    )


