def test_hook_worker_reports_post_sync_staleness_when_transcript_grows_during_sync(
    tmp_path: Path,
    monkeypatch,
) -> None:
    """Regression derived from the raw-first 20260716 PreCompact worker wave."""

    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
    session_id = "session-worker-growing-source"
    transcript = tmp_path / f"rollout-2026-05-12T00-00-00-{session_id}.jsonl"
    initial_rows = [
        {
            "timestamp": "2026-05-12T00:00:00Z",
            "type": "session_meta",
            "payload": {"id": session_id},
        },
        {
            "timestamp": "2026-05-12T00:00:01Z",
            "type": "response_item",
            "payload": {
                "type": "message",
                "role": "user",
                "content": [{"type": "input_text", "text": "Observe worker post-sync freshness"}],
            },
        },
    ]
    write_jsonl(transcript, initial_rows)
    job_path = module.enqueue_hook_sync_job(
        aoa_root,
        event_name="PreCompact",
        event={
            "session_id": session_id,
            "transcript_path": str(transcript),
            "cwd": str(workspace),
            "hook_event_name": "PreCompact",
        },
        session_id=session_id,
        transcript_path=transcript,
        reason="test_source_growth_during_worker_sync",
    )
    assert job_path is not None

    original_sync = module.sync_session_from_transcript

    def sync_then_grow(**kwargs):
        synced = original_sync(**kwargs)
        write_jsonl(
            transcript,
            initial_rows
            + [
                {
                    "timestamp": "2026-05-12T00:00:02Z",
                    "type": "compacted",
                    "payload": {"message": "source advanced while the worker copied its snapshot"},
                }
            ],
        )
        return synced

    monkeypatch.setattr(module, "sync_session_from_transcript", sync_then_grow)

    payload = module.run_hook_worker(workspace_root=workspace, aoa_root=aoa_root, limit=1)

    result = payload["results"][0]
    assert payload["ok"] is True
    assert result["status"] == "synced_stale_readable"
    assert result["pre_sync_freshness"]["reason"] == "missing_manifest"
    assert result["freshness"]["fresh"] is False
    assert result["freshness"]["reason"] == "source_size_changed"
    assert result["retry_required"] is True


def test_hook_worker_skips_fresh_deferred_sync_job(tmp_path: Path, monkeypatch) -> None:
    workspace = tmp_path / "AbyssOS"
    aoa_root = workspace / ".aoa"
