def test_codex_hook_lookup_tracks_trust_and_expected_commands(tmp_path: Path) -> None:
    workspace = tmp_path / "portable-workspace"
    aoa_root = workspace / ".aoa"
    expected_commands = module.expected_hook_commands(workspace, aoa_root)
    hooks = [
        {
            "key": "/home/user/.codex/hooks.json:pre_compact:0:0",
            "eventName": "preCompact",
            "command": expected_commands["PreCompact"],
            "currentHash": "sha256:pre",
            "trustStatus": "trusted",
            "enabled": True,
        },
        {
            "key": "/home/user/.codex/hooks.json:post_compact:0:0",
            "eventName": "postCompact",
            "command": expected_commands["PostCompact"],
            "currentHash": "sha256:post",
            "trustStatus": "untrusted",
            "enabled": True,
        },
        {
            "key": "/home/user/.codex/hooks.json:stop:0:0",
            "eventName": "stop",
            "command": "python3 wrong.py",
            "currentHash": "sha256:wrong",
            "trustStatus": "trusted",
            "enabled": True,
        },
    ]

    lookup = module.hook_lookup_from_app_hooks(hooks, expected_commands)
    trust_state = module.hook_trust_state_from_lookup(lookup)

    assert lookup["PreCompact"]["present"] is True
    assert lookup["PreCompact"]["trusted"] is True
    assert lookup["PostCompact"]["present"] is True
    assert lookup["PostCompact"]["trusted"] is False
    assert lookup["Stop"]["present"] is False
    assert trust_state == {
        "/home/user/.codex/hooks.json:pre_compact:0:0": {"trusted_hash": "sha256:pre"},
        "/home/user/.codex/hooks.json:post_compact:0:0": {"trusted_hash": "sha256:post"},
    }


def test_codex_hooks_status_inspects_registry_without_mutating_trust(
    tmp_path: Path,
    monkeypatch: Any,
) -> None:
    workspace = tmp_path / "portable-workspace"
    aoa_root = workspace / ".aoa"
    expected_commands = module.expected_hook_commands(workspace, aoa_root)
    hooks = [
        {
            "key": f"fixture:{event_name}",
            "eventName": app_event_name,
            "command": expected_commands[event_name],
            "currentHash": f"sha256:{event_name.lower()}",
            "trustStatus": "trusted",
            "enabled": True,
        }
        for event_name, app_event_name in module.CODEX_APP_EVENT_NAMES.items()
    ]
    sent: list[dict[str, Any]] = []

    class FakeCodexAppServerClient:
        def __init__(self, **kwargs: Any) -> None:
            assert kwargs["codex_bin"] == "codex-fixture"
            assert kwargs["cwd"] == workspace
            assert kwargs["timeout"] == 7

        def __enter__(self) -> "FakeCodexAppServerClient":
            return self

        def __exit__(self, *_args: Any) -> None:
            return None

        def send(self, payload: dict[str, Any]) -> None:
            sent.append(payload)

        def recv_response(
            self,
            request_id: int,
            *,
            timeout: int | None = None,
        ) -> tuple[dict[str, Any], list[dict[str, Any]]]:
            assert timeout in {None, 7}
            if request_id == 1:
                return {"id": 1, "result": {}}, []
            assert request_id == 2
            return {
                "id": 2,
                "result": {"data": [{"hooks": hooks}]},
            }, []

    monkeypatch.setattr(
        module,
        "CodexAppServerClient",
        FakeCodexAppServerClient,
    )

    payload = module.codex_hooks_status(
        workspace_root=workspace,
        aoa_root=aoa_root,
        codex_bin="codex-fixture",
        trust_current=False,
        timeout=7,
    )

    assert payload["ok"] is True
    assert payload["trusted_written"] is False
    assert payload["trusted_state"] == {}
    assert payload["trust_response"] is None
    assert all(item["present"] for item in payload["hooks"].values())
    assert all(item["trusted"] for item in payload["hooks"].values())
    assert all(check["ok"] for check in payload["checks"])
    assert [item["method"] for item in sent] == [
        "initialize",
        "initialized",
        "hooks/list",
    ]
    assert not any(item["method"] == "config/batchWrite" for item in sent)


