    (workspace / ".codex").mkdir(parents=True)
    codex_home.mkdir()
    (workspace / ".codex" / "config.toml").write_text(
        "\n".join(
            [
                "[features]",
                "codex_hooks = true",
                "",
            ]
        ),
        encoding="utf-8",
    )
    (codex_home / "config.toml").write_text(
        "\n".join(
            [
                "model_context_window = 400000",
                "model_auto_compact_token_limit = 320000",
                "",
                "[features]",
                "hooks = true",
                "",
            ]
        ),
        encoding="utf-8",
    )
